        ["2026-07-02-feedback-midnight-season-2-dungeon-testing-july-2nd-july-6th-863b0c7589"] = {
            id = "2026-07-02-feedback-midnight-season-2-dungeon-testing-july-2nd-july-6th-863b0c7589",
            post_key = "863b0c7589",
            title = "Feedback: Midnight Season 2 Dungeon Testing July 2nd - July 6th",
            category = "Midnight: Curse of Ula'tek Public Test Realm (US)",
            timestamp = 1783019399,
            url = "https://us.forums.blizzard.com/en/wow/t/2323039/1",
            content = {
            { type = "p", text = "Greetings!" },
            { type = "p", text = "Midnight Season 2 dungeon testing continues on Thursday, July 2nd. We are making an adjustment to our Mythic+ testing schedule." },
            { type = "list_item", text = "July 2nd - July 6th: Midnight Dungeons", level = 0 },
            { type = "list_item", text = "The Blinding Vale", level = 1 },
            { type = "list_item", text = "Den of Nalorakk", level = 1 },
            { type = "list_item", text = "Murder Row", level = 1 },
            { type = "list_item", text = "Voidscar Arena", level = 1 },
            { type = "list_item", text = "July 7th - July 13th: Legacy Dungeons", level = 0 },
            { type = "list_item", text = "Temple of Sethraliss", level = 1 },
            { type = "list_item", text = "Kings’ Rest", level = 1 },
            { type = "list_item", text = "Ruby Life Pools", level = 1 },
            { type = "list_item", text = "July 14th - July 22nd: All Season 2 Mythic+ Dungeons", level = 0 },
            { type = "p", text = "During the test period you’ll be able to acquire and customize Mythic Keystones by talking to the Keystone Vendor in Stormwind, Orgrimmar and Silvermoon. The nearby Dungeon Teleports NPC will assist you with transportation. This NPC will now also appear at the beginning of each dungeon on Mythic difficulty who can teleport players back to a capital city.Provided that the items equipped on your character are at least item level 226, they will scale automatically to a higher level as needed to support Dungeon testing." },
            { type = "h3", text = "Dungeon Update" },
            { type = "list_item", text = "The Blinding Vale", level = 0 },
            { type = "list_item", text = "General", level = 1 },
            { type = "list_item", text = "Updated spawning across the dungeon to reduce the amount of casters found in a single creature pack", level = 2 },
            { type = "list_item", text = "Ikuzz the Light Hunter", level = 1 },
            { type = "list_item", text = "Slowed the encounter’s ability pacing to give players more time to destroy their Bloodthorn Roots", level = 2 },
            { type = "list_item", text = "Improved Ikuzz’s detection of nearby Bloodthorn Roots during Bloodthirsty Gaze", level = 2 },
            { type = "list_item", text = "Lightwarden Ruia", level = 1 },
            { type = "list_item", text = "Added a visual indicator to Lightfire that communicates the direction of outgoing Lightfire Beams", level = 2 },
            { type = "list_item", text = "Ziekket", level = 1 },
            { type = "list_item", text = "Lightspawn Lasher’s health has been reduced", level = 2 },
            { type = "list_item", text = "Den of Nalorakk", level = 0 },
            { type = "list_item", text = "General", level = 1 },
            { type = "list_item", text = "Increased the pacing of some RP sequences in the dungeon", level = 2 },
            { type = "list_item", text = "Winter Gauntlet", level = 1 },
            { type = "list_item", text = "Looming Tempest has been removed", level = 2 },
            { type = "list_item", text = "Defeating the creature The Winter Squall now stops the Harsh Winds effect in the area", level = 2 },
            { type = "list_item", text = "Snow drifts now prevents players from slipping on icy terrains", level = 2 },
            { type = "list_item", text = "Sentinel of Winter", level = 1 },
            { type = "list_item", text = "Eternal Winter has been redesigned", level = 2 },
            { type = "list_item", text = "Renamed to Frozen Tempest", level = 3 },
            { type = "list_item", text = "Absorb shield on the boss has been removed", level = 3 },
            { type = "list_item", text = "Channel time reduced to 8 seconds", level = 3 },
            { type = "list_item", text = "Now creates a 10 yards safe zone near the boss", level = 3 },
            { type = "list_item", text = "Fractured Shivercore now only creates one Rimeshatter instead of two", level = 2 },
            { type = "list_item", text = "Nalorakk", level = 1 },
            { type = "list_item", text = "Updated Overwhelming Onslaught to a group mechanic", level = 2 },
            { type = "list_item", text = "Murder Row", level = 0 },
            { type = "list_item", text = "General", level = 1 },
            { type = "list_item", text = "Significantly reduced the number of casters in the second half of the dungeon", level = 2 },
            { type = "list_item", text = "Cantina Event", level = 1 },
            { type = "list_item", text = "Event now instantly ends when players reach 5 stars", level = 2 },
            { type = "list_item", text = "Requirement to reach 5 stars reduced by 20%", level = 2 },
            { type = "list_item", text = "Players no longer switch roles during the event", level = 2 },
            { type = "list_item", text = "Five Star Review!'s buff duration increased from 3 minutes to 4 minutes", level = 2 },
            { type = "list_item", text = "Voidscar Arena", level = 0 },
            { type = "list_item", text = "General", level = 1 },
            { type = "list_item", text = "Overhauled creature spawning and ability packages across the dungeon", level = 2 },
            { type = "list_item", text = "Added two new minibosses at the start of the dungeon, each granting players a unique buff when defeated", level = 2 },
            { type = "list_item", text = "Protective Turtle", level = 1 },
            { type = "list_item", text = "Shell Guard now has a limited channel time. When the channel finishes, the caster becomes stunned, taking increased damage for 10 seconds.", level = 2 },
            { type = "list_item", text = "Taz’Rah", level = 1 },
            { type = "list_item", text = "Encounter has been redesigned with new abilities and updated visuals", level = 2 },
            { type = "list_item", text = "Atroxus", level = 1 },
            { type = "list_item", text = "Monstrous Stomp has been redesigned", level = 2 },
            { type = "list_item", text = "Renamed Monstrous Roar", level = 3 },
            { type = "list_item", text = "Removed Knockback", level = 3 },
            { type = "list_item", text = "Now summons a Toxic Creeper", level = 3 },
            { type = "list_item", text = "Chaornus", level = 1 },
            { type = "list_item", text = "Encounter has been updated with new mechanics and ability schedule", level = 2 },
            { type = "p", text = "Thanks for testing and sharing your thoughts with us! We’ll be reviewing your feedback closely and will continue to post updates throughout the beta as changes roll out." },
            },
        },
        ["2026-07-02-wow-weekly-turbulent-timeways-curse-of-ulax27tek-july-trading-post-and-6195109de2"] = {
            id = "2026-07-02-wow-weekly-turbulent-timeways-curse-of-ulax27tek-july-trading-post-and-6195109de2",
            post_key = "6195109de2",
            title = "WoW Weekly: Turbulent Timeways, Curse of Ula'tek, July Trading Post, and More!",
            category = "Blogs (US)",
            timestamp = 1783011727,
            url = "https://news.blizzard.com/en-us/article/24287398/wow-weekly-turbulent-timeways-curse-of-ula-tek-july-trading-post-and-more",
            content = {
            { type = "p", text = "Each week meets you with adventurous discovery and fresh rewards—be sure to check in to learn more about what awaits you in Azeroth." },
            { type = "hr" },
            { type = "h2", text = "SOAR THROUGH TURBULENT TIMEWAYS—NOW LIVE!" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-07-02-wow-weekly-turbulent-timeways-curse-of-ulax27tek-july-trading-post-and-6195109de2\\image-1.jpg" },
            { type = "p", text = "Once more, the Bronze Dragonflight has discovered growing disturbances in the timeways as several rapidly intersect our own." },
            { type = "p", text = "When: June 30–August 11" },
            { type = "p", text = "Timewalk through a previous expansion each week for six consecutive weeks, beginning and ending with Dragonflight. This grand tour through World of Warcraft’s past features six Timewalking Dungeons: Algeth’ar Academy, Halls of Infusion, Neltharus, Ruby Life Pools, The Azure Vaults, and Brackenhide Hollow." },
            { type = "p", text = "Players can also shop at a new Dragonflight vendor, Xydan, located in the Bronze Enclave in Valdrakken." },
            { type = "p", text = "Learn more by heading over to our previously published article." },
            { type = "hr" },
            { type = "h2", text = "QUALITY-OF-LIFE IMPROVEMENTS COMING IN CURSE OF ULA'TEK" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-07-02-wow-weekly-turbulent-timeways-curse-of-ulax27tek-july-trading-post-and-6195109de2\\image-2.jpg" },
            { type = "p", text = "Since the 12.0.5 content update, we’ve been building on your feedback by making targeted improvements to enhance the play experience. Recent hotfixes, along with changes in Midnight: Revelations, have already addressed some issues with rewards, looting, quest experience, and durability loss." },
            { type = "p", text = "More updates are planned in the Curse of Ula’tek content update, including account-wide user interface settings, Auction House improvements, a one-time Profession Knowledge reset, and fixes for common combat and travel issues." },
            { type = "p", text = "In Curse of Ula'tek and beyond, we’ll continue looking for ways to make World of Warcraft easier to navigate and more enjoyable to play. We deeply appreciate all of your feedback on ways we can improve the World of Warcraft player experience and will continue to make efforts to address these improvement opportunities as they arise." },
            { type = "p", text = "Dive into more details about the quality of life improvements ahead by reading our previously published article." },
            { type = "hr" },
            { type = "h2", text = "JULY’S TRADING POST IGNITES A TRUE-BLUE CELEBRATION" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-07-02-wow-weekly-turbulent-timeways-curse-of-ulax27tek-july-trading-post-and-6195109de2\\image-3.jpg" },
            { type = "p", text = "Bilgewater X-TREMEMount\"The engineers of Undermine were so preoccupied with whether or not they COULD make a faster rocket, they didn't stop to think if they should.\"" },
            { type = "p", text = "July’s Trading Post is taking on a brilliant blue streak, with fresh finds ready to add a bold splash of color to your collection." },
            { type = "p", text = "Complete activities to earn Trader’s Tender, fill your Traveler’s Log, and rocket away with the Bilgewater X-TREME mount." },
            { type = "p", text = "Visit T&W (Tawney and Wilder) just outside the Mage District in Stormwind or the Zen’shiri Trading Post next to Grommash Hold in Orgrimmar to check out all the latest items they have available." },
            { type = "p", text = "Players can also visit the Trading Post in the capital city of Dornogal (The Foregrounds) on the Isle of Dorn, the renewed Silvermoon City, where representatives of both Tawney and Wilder and the Zen’shiri Trading Post are open for business." },
            { type = "p", text = "Read through our article for a detailed list of all the items available from the July Trading Post and how to get them." },
            { type = "p", text = "Champions new or returning to World of Warcraft and Midnight who want to know more can take a tour of the Trading Post to learn everything you need to know, from where to find it to how you can earn additional Trader's Tender through the Traveler's Log." },
            { type = "hr" },
            { type = "h2", text = "WARCRAFT SHORT STORY: “THE BITTER TRUTH”" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-07-02-wow-weekly-turbulent-timeways-curse-of-ulax27tek-july-trading-post-and-6195109de2\\image-4.jpg" },
            { type = "p", text = "An unexpected meeting, meant to be diplomatic, places two longtime foes in a tense, drink-fueled standoff, where polite exchanges mask a long history of bloodshed and blame. As the conversation turns personal, both men are forced to confront the painful truth of their shared history." },
            { type = "p", text = "Head over to our previously published article to join Lor’themar and Torundo the Grizzled for a special fireside telling of our newest three-part short story, “The Bitter Truth,” narrated by Gideon Emery as Lor’themar and Keston John as Torundo the Grizzled, with a downloadable PDF written by Robert Brooks and illustrated by Surfside 3D." },
            { type = "hr" },
            { type = "h2", text = "SHAPE YOUR DESTINY, AND YOUR MOUNT, WITH THE STONEFORGED SENTINEL" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-07-02-wow-weekly-turbulent-timeways-curse-of-ulax27tek-july-trading-post-and-6195109de2\\image-5.jpg" },
            { type = "p", text = "Chiseled from enduring stone and awakened by ancient power, the Stoneforged Sentinel mount is yours to shape. With a wide array of customization options—over 300,000 unique mount variations—you can craft a truly personal flying guardian unlike any other. The mount automatically scales to the fastest riding skill known by each character, and if a character’s level isn’t high enough to use a flying mount, the Stoneforged Sentinel makes a sturdy ground mount." },
            { type = "p", text = "Visit any Rostrum of Transformation to customize your Stoneforged Sentinel. Customization options include: 4 x Stone Colors, 4 x Metal Colors, 5 x Gem Colors, 3 x Saddle Styles, 6 x Head Styles, 6 x Wing Styles, 6 x Claw Styles, and 6 x Tail Styles." },
            { type = "p", text = "Rostrum locations can be found in multiple cities and camps. Look for the gold dragon head on your minimap or ask a city guard for directions." },
            { type = "h3", text = "Visit the Shop" },
            { type = "hr" },
            { type = "p", text = "Let us journey alongside you, regale you with tales of adventure in faraway places, map out roads less traveled, and direct your gaze toward the legendary challenges that await. Return each week to the World of Warcraft news site, where together, we'll uncover your destiny." },
            },
        },
        ["2026-07-02-wow-weekly-turbulent-timeways-curse-of-ulax27tek-july-trading-post-and-94b0bc4e2c"] = {
