            content = {
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-07-01-warcraft-short-story-the-bitter-truth-e519a2a271\\image-1.jpg" },
