            title = "Hotfixes: June 30, 2026",
            category = "Blogs (EU)",
            timestamp = 1782863878,
            url = "https://news.blizzard.com/en-gb/article/24287397/hotfixes-june-23-2026",
            content = {
            { type = "p", text = "Here you'll find a list of hotfixes that address various issues related to World of Warcraft: Midnight, Mists of Pandaria Classic, Season of Discovery, Burning Crusade Classic, WoW Classic Era, and Hardcore. Some of the hotfixes below take effect the moment they were implemented, while others may require scheduled realm restarts to go into effect. Please keep in mind that some issues cannot be addressed without a client-side patch update. This list will be updated as additional hotfixes are applied." },
            { type = "h2", text = "HOTFIXES" },
            { type = "hr" },
            { type = "h3", text = "June 30, 2026" },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Balance", level = 1 },
            { type = "list_item", text = "All damage increased by 4%.", level = 2 },
            { type = "list_item", text = "Feral", level = 1 },
            { type = "dev_note", text = "Feral is performing well in M+, but their overall damage in raid is low. These changes shore up their single-target power and total raid damage.", level = 2 },
            { type = "list_item", text = "All damage increased by 3%. Does not apply to PvP combat.", level = 2 },
            { type = "list_item", text = "Melee auto-attack damage increased by 15%.", level = 2 },
            { type = "list_item", text = "Rip damage increased by 5%. Does not apply to PvP combat.", level = 2 },
            { type = "list_item", text = "Rampant Ferocity damage reduced by 15%. Does not apply to PvP combat.", level = 2 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "dev_note", text = "Restoration’s damage compared to other healers is lower than we’d like. We’re rebalancing some of Restoration Druid’s damage out of Thrash and into the rest of the kit.", level = 2 },
            { type = "list_item", text = "All damage increased by 15%.", level = 2 },
            { type = "list_item", text = "Bear Form Thrash damage reduced by 25%.", level = 2 },
            { type = "list_item", text = "Evoker", level = 0 },
            { type = "list_item", text = "Devastation", level = 1 },
            { type = "list_item", text = "All ability damage increased by 3%.", level = 2 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Arcane", level = 1 },
            { type = "list_item", text = "All ability damage increased by 3%.", level = 2 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "list_item", text = "Holy Word: Serenity healing increased by 20%.", level = 2 },
            { type = "list_item", text = "Holy Word: Sanctify healing increased by 20%.", level = 2 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "Elemental", level = 1 },
            { type = "list_item", text = "Corrected an issue where Purging Flames could cause Lava Burst to generate less Maelstrom than intended.", level = 2 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "list_item", text = "All healing increased by 4%. This does not apply to PvP combat.", level = 2 },
            { type = "h3", text = "Player versus Player" },
            { type = "list_item", text = "Demon Hunter", level = 0 },
            { type = "list_item", text = "Devourer", level = 1 },
            { type = "dev_note", text = "Devourer Demon Hunters have been performing above expectations, especially in defensive metrics, so self-healing is being reduced.", level = 2 },
            { type = "list_item", text = "Shattered Souls now heals for 0.5% of maximum Health per Soul Fragment consumed (was 1%) in PvP combat.", level = 2 },
            { type = "list_item", text = "Death Knight", level = 0 },
            { type = "list_item", text = "Unholy", level = 1 },
            { type = "dev_note", text = "Unholy’s burst damage is overwhelming too frequently, so contributing abilities are receiving a reduction with some of that overall damage moving into the steadier output from Dread Plague.", level = 2 },
            { type = "list_item", text = "Putrify damage reduced by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Soul Reaper damage reduced by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Dread Plague damage increased by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Guardian", level = 1 },
            { type = "dev_note", text = "Guardians’ burst potential with their apex talent has been higher than we would like for a tank specialization in PvP.", level = 2 },
            { type = "list_item", text = "Wild Guardian now echoes at 50% effectiveness (was 200%) in PvP combat.", level = 2 },
            { type = "list_item", text = "Evoker", level = 0 },
            { type = "list_item", text = "Fixed an issue where the Fire Breath Infuser during Evoker's introductory quests would not reset the cooldown of Fire Breath.", level = 1 },
            { type = "list_item", text = "Augmentation", level = 1 },
            { type = "list_item", text = "All damage increased by 8% in PvP combat.", level = 2 },
            { type = "list_item", text = "Preservation", level = 1 },
            { type = "dev_note", text = "Preservation Evoker is slightly overperforming in PvP, so we’re making one additional targeted nerf to them in this pass. Temporal Burst makes it hard for enemies to react to important casts like Sleep Walk, so we’re reducing its effectiveness.", level = 2 },
            { type = "list_item", text = "Temporal Burst increases haste, movement speed, and cooldown recovery rate by 15% in PvP combat (was 30%).", level = 2 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Marksmanship", level = 1 },
            { type = "list_item", text = "Double tap now causes Aimed Shot to fire at 16% effectiveness or your next Rapid Fire to fire 16% additional shots (was 40%).", level = 2 },
            { type = "dev_note", text = "We’re reducing Double Shot’s burst potential to allow enemy players to have more time to react to the Marksmanship Hunter’s incoming damage.", level = 2 },
            { type = "list_item", text = "Survival", level = 1 },
            { type = "list_item", text = "All damage increased by 3% in PvP Combat.", level = 2 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Frost", level = 1 },
            { type = "dev_note", text = "We are redistributing some of Frost Mage’s damage out of Ray of Frost and into the rest of its kit with the intention of decreasing its burst capabilities and improving its steady-state pressure.", level = 2 },
            { type = "list_item", text = "Ray of Frost damage decreased by 20% in PvP combat. All damage increased 3% in PvP combat.", level = 2 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "dev_note", text = "Templars’ burst capabilities have made Protection Paladin more of an offensive threat than we would like them to be in PvP.", level = 2 },
            { type = "list_item", text = "Divine Exaction now casts Divine Toll again at 25% effectiveness (was 75%) in PvP combat.", level = 2 },
            { type = "list_item", text = "Hammer of Light damage decreased by 30% in PvP combat.", level = 2 },
            { type = "list_item", text = "Retribution", level = 1 },
            { type = "dev_note", text = "Retribution has been performing better than expected, so we are applying a small damage reduction.", level = 2 },
            { type = "list_item", text = "All ability damage reduced by 3% in PvP combat.", level = 2 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Discipline", level = 1 },
            { type = "dev_note", text = "Voidweaver Priests are dealing too much damage in PvP. We’re reducing some of that damage and increasing their healing to compensate.", level = 2 },
            { type = "list_item", text = "Expiation deals damage equal to 200% of the of the amount consumed from Shadow Word: Pain in PvP combat (was 300%).", level = 2 },
            { type = "list_item", text = "Inescapable Torment damage reduced by 25% in PvP combat.", level = 2 },
            { type = "list_item", text = "Shadow Word: Pain damage reduced by 10% in PvP combat.", level = 2 },
            { type = "list_item", text = "Voidweaver: Atonement healing increased by 15%.", level = 2 },
            { type = "list_item", text = "Oracle: Preventive Measures increases damage of Penance, Smite, Holy Nova by 20% (was 15%).", level = 2 },
            { type = "list_item", text = "Ultimate Penitence healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Shadow", level = 1 },
            { type = "dev_note", text = "In addition to a needed boost of overall damage, Shadow Word: Death is also receiving a buff intended to make its damage worthwhile when striking enemies in its low-health threshold.", level = 2 },
            { type = "list_item", text = "All ability damage increased by 4% in PvP combat.", level = 2 },
            { type = "list_item", text = "Shadow Word: Death damage increased by 45% in PvP combat.", level = 2 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "dev_note", text = "Farseer Restoration Shaman has been behind in performance in PvP compared to Totemic, we’re increasing the throughput of heals and effects provided by Farseer talents and their Ancestors to help close the gap.", level = 2 },
            { type = "list_item", text = "Farseer: Maelstrom Supremacy increases healing of affected spells in PvP by 20% (was 15%).", level = 2 },
            { type = "list_item", text = "Farseer: Hydrobubble’s effectiveness is no longer reduced in PvP (was a 20% reduction).", level = 2 },
            { type = "list_item", text = "Farseer: Heals cast by Call of the Ancestors increased in PvP by 30% (was 20%).", level = 2 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "Arms, Protection", level = 1 },
            { type = "dev_note", text = "We’re slightly reducing Colossus’ ability to tank damage to make them more of a viable kill target.", level = 2 },
            { type = "list_item", text = "Mountain of Muscle and Scars reduces damage taken by 3% in PvP combat (was 5%).", level = 2 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Affliction", level = 1 },
            { type = "list_item", text = "All damage increased by 3% in PvP combat.", level = 2 },
            { type = "list_item", text = "Consuming Nightfall with Seed of Corruption on a target already afflicted with Seed of Corruption will cause the preexisting Seed of Corruption to detonate.", level = 2 },
            { type = "list_item", text = "Demonology", level = 1 },
            { type = "dev_note", text = "Demonology damage while freecasting has not been as effective as we would like, so we’re targeting a few adjustments to Shadow Bolt and Demonbolt with the intention of increasing their ability to punish enemies for allowing them to chain casts together.", level = 2 },
            { type = "list_item", text = "Shadow Bolt damage increased by 200% in PvP combat.", level = 2 },
            { type = "list_item", text = "Demonbolt damage increased by 30% in PvP combat.", level = 2 },
            { type = "list_item", text = "Destruction", level = 1 },
            { type = "list_item", text = "Incinerate damage increased by 50% in PvP combat.", level = 2 },
            { type = "h3", text = "Dungeons and Raids" },
            { type = "list_item", text = "Darkheart Thicket", level = 0 },
            { type = "list_item", text = "Players must now defeat Dresaron to complete the dungeon on Timewalking difficulty.", level = 1 },
            { type = "h3", text = "Naigtal" },
            { type = "list_item", text = "Players can no longer be attacked while on Transport Skiffs in Naigtal.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "June 25, 2026" },
            { type = "h3", text = "Delves" },
            { type = "list_item", text = "When tank Valeera is accompanied by a healer, she now takes significantly less damage, scaling from 45% less damage at Tier 1 to 29% less damage at Tier 11.", level = 0 },
            { type = "h3", text = "Dungeons and Raids" },
            { type = "list_item", text = "Sporefall", level = 0 },
            { type = "list_item", text = "Resolved an issue causing players to be able to interact with the door to Funggor Hollow.", level = 1 },
            { type = "h3", text = "Naigtal" },
            { type = "list_item", text = "Players will no longer lose their \"Lighthook Grapple\" ability when they log out of Naigtal.", level = 0 },
            { type = "h3", text = "Omnium Folio" },
            { type = "list_item", text = "Starting with Week 2, the weekly Seeking Knowledge quest prerequisites are now account-wide. Characters must still complete the Sunstrider Omnium unlock questline to access the weekly quests on alts.", level = 0 },
            { type = "h3", text = "Quests" },
            { type = "list_item", text = "All of the quests required for the Omnium Folio and to unlock and enter Val or Naigtal are now marked as Important quests.", level = 0 },
            { type = "list_item", text = "Fixed a bug preventing new Midsummer quests from rewarding XP.", level = 0 },
            { type = "h3", text = "Val" },
            { type = "list_item", text = "Gravity Shackles affix damage reduced by 50%.", level = 0 },
            { type = "list_item", text = "Adjusted the World Quest \"Dissent and Divide\".", level = 0 },
            { type = "list_item", text = "Increased the chances of a favorable gossip reaction even when selecting inappropriate gossip options for the target.", level = 1 },
            { type = "list_item", text = "Increased base spawn thresholds for conversation targets.", level = 1 },
            { type = "list_item", text = "Added additional Veilcasters around the quest area.", level = 1 },
            { type = "list_item", text = "Added partial credit for killing gossip targets.", level = 1 },
            { type = "list_item", text = "Added a movement bonus to the Domanaar disguise.", level = 1 },
            { type = "list_item", text = "Adjusted the World Quest “Aberration Liberation”.", level = 0 },
            { type = "list_item", text = "Reduced the quest objective count to 10 (was 12).", level = 1 },
            { type = "list_item", text = "Kills now give credit to the whole party (was the interacting player).", level = 1 },
            { type = "list_item", text = "Improved respawning when many players are present.", level = 1 },
            { type = "list_item", text = "Spirit Healers now correctly spawn in Val.", level = 0 },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Grendag Brightbeard can now be found in Thunder Bluff and in the entrance to the Undercity.", level = 0 },
            { type = "dev_note", text = "This is intended as a workaround to issue on some servers causing players in Orgrimmar to not be able to disable or re-enable XP gains. We hope to return Grendag to working order in Orgrimmar soon.", level = 1 },
            { type = "hr" },
            { type = "h3", text = "June 23, 2026" },
            { type = "h3", text = "Items" },
            { type = "list_item", text = "Rotmire's Sporeheart once again triggers from Leech healing.", level = 0 },
            { type = "h3", text = "Lorewalking" },
            { type = "list_item", text = "During Loa Lorewalking (and Darkspear Heritage), Lukou's portals will now allow transport while in combat.", level = 0 },
            { type = "h3", text = "Midsummer Fire Festival" },
            { type = "list_item", text = "“Reignite the Skies: Orgrimmar” and “Reignite the Skies: Stormwind” Midsummer dailies unlocks are now account-wide.", level = 0 },
            { type = "list_item", text = "Fixed an issue that allowed the contents Satchel of Chilled Goods to reroll each time it was opened.", level = 0 },
            { type = "list_item", text = "Sun Festival Painted Roc’s chance to drop in Satchel of Chilled Goods has been doubled for the first drop of the day on the account. The drop rate from the first satchel will continue to increase each day until it is obtained.", level = 0 },
            { type = "h3", text = "Player versus Player" },
            { type = "list_item", text = "Fixed an issue where some important effects and major defensives were not displaying on enemy player nameplates.", level = 0 },
            { type = "h3", text = "Professions" },
            { type = "list_item", text = "Fixed an issue where Empowered Mulch would result in no herbs being gathered.", level = 0 },
            { type = "h3", text = "Quests" },
            { type = "list_item", text = "The weekly offerings from Lady Liadrin should once again offer four choices to players.", level = 0 },
            { type = "h3", text = "Val" },
            { type = "list_item", text = "Adjustments made to the \"Until it is Done\" world quest, improving quest credit earned and increasing creature respawn rates.", level = 0 },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Challenge Mode", level = 0 },
            { type = "list_item", text = "Challenge Conqueror: Platinum (Season 3) is now correctly earnable.", level = 1 },
            { type = "dev_note", text = "Realm First! Challenge Conqueror: Platinum (Season 3) has been disabled in North America while we work on granting the achievement to the correct winners.", level = 2 },
            { type = "list_item", text = "Mists of Pandaria Classic can no longer be installed on Windows 7 and 8 operating systems.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "June 22, 2026" },
            { type = "h3", text = "Delves" },
            { type = "list_item", text = "The Excavation Site 9 and Sidestreet Sluice delves should be reliably displaying the correct names again.", level = 0 },
            { type = "h3", text = "Items" },
            { type = "list_item", text = "Fixed an issue causing the Draconic Nullcape cloak to use an unintended appearance. This item now contributes towards the Luminant Verdict's Vestments transmog sets.", level = 0 },
            { type = "h3", text = "Naigtal" },
            { type = "list_item", text = "More bouncy mushrooms have been added to help with some hard-to-reach locations.", level = 0 },
            { type = "list_item", text = "The Spore Buoy's slowfall effect now works on mounted players.", level = 0 },
            { type = "h3", text = "Omnium Folio" },
            { type = "list_item", text = "Fixed an issue with Rune of Void-Tainted Shell’s tooltip.", level = 0 },
            { type = "h3", text = "Quests" },
            { type = "list_item", text = "“Defying Gravity” should once again function with the Lair of Predaxas restored.", level = 0 },
            { type = "h3", text = "Ritual Sites" },
            { type = "list_item", text = "Players can now pick up Lady Darkglen's new quest for Tier 6 Ritual Sites in the Silvermoon hub in addition to outside the active Ritual Site.", level = 0 },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Fixed an issue that was causing Midsummer Festival Bonfires to deal more damage to players than expected.", level = 0 },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Siege of Orgrimmar cooldown reduction trinkets will now correctly re-evaluate their effects when starting a Challenge Mode dungeon.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "June 18, 2026" },
            { type = "h3", text = "Items" },
            { type = "list_item", text = "Fixed an issue that could prevent Rotmire's Sporeheart’s effect from triggering from certain sources of healing.", level = 0 },
            { type = "h3", text = "Lorewalking" },
            { type = "list_item", text = "Rewards from the Loa Lorewalking campaign should now scale all the way to level 90.", level = 0 },
            { type = "h3", text = "Naigtal" },
            { type = "list_item", text = "Rares are now enveloped in shadow for the first 3 minutes after spawning and cannot be attacked, giving players additional time to reach the encounter.", level = 0 },
            { type = "h3", text = "Player versus Player" },
            { type = "list_item", text = "Resolved an issue that could cause Horde to lose reinforcements instead of Alliance when they capture the Sparring Grounds in Slayer's Rise.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "June 17, 2026" },
            { type = "h3", text = "Abundance" },
            { type = "list_item", text = "Fixed an issue where players could not begin Abundance in Voidstorm. All players who lost Shards of Dundun due to this issue will be refunded with Unalloyed Abundance in an upcoming hotfix.", level = 0 },
            { type = "h3", text = "Island Expeditions" },
            { type = "list_item", text = "Island Expeditions should be queueing correctly once again.", level = 0 },
            { type = "h3", text = "Items" },
            { type = "list_item", text = "Fixed an issue where the Void-Touched Torch had lower Intellect than intended.", level = 0 },
            { type = "h3", text = "Lorewalking" },
            { type = "list_item", text = "Fixed an issue where the initial objective conversation for “The Prince Who Would Be King” would not complete.", level = 0 },
            { type = "h3", text = "Naigtal" },
            { type = "list_item", text = "The \"Bouncy Mushrooms,\" \"Aerospores\", and \"The Grappler\" unlocks in Naigtal are now account wide.", level = 0 },
            { type = "list_item", text = "Fixed an issue that prevented Nexus-Captain Leth'ir from dropping the quest item for “Knocking Off the Top (Heroic).” Characters that encountered the issue can earn their emblem from another Heroic kill of Nexus-Captain Leth'ir or from a wrapper quest they have not completed.", level = 0 },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Siege of Orgrimmar", level = 0 },
            { type = "list_item", text = "Garrosh Hellscream", level = 1 },
            { type = "list_item", text = "Beginning with realm maintenance this week, defeating Garrosh will now give you a chance to bonus roll for an extra piece of loot.", level = 2 },
            { type = "list_item", text = "Celestial Dungeons", level = 0 },
            { type = "list_item", text = "Kor'kron Arcweavers no longer ignore line of sight and Magistrike has had its damage reduced.", level = 1 },
            { type = "list_item", text = "Kor'kron Banners have had their health significantly reduced.", level = 1 },
            { type = "list_item", text = "The respawn rate of the Kor'kron forces has been adjusted to be every 2 hours (was 5 minutes).", level = 1 },
            { type = "list_item", text = "August Stone Clusters now cap at 200 (was 70).", level = 1 },
            { type = "list_item", text = "The Coffer of Celestial Chance now awards 50-60 Lesser Charms of Good Fortune (was 20-30).", level = 1 },
            },
        },
        ["2026-06-30-midnight-curse-of-ulatek-121-ptr-development-notes-32b9da7c85"] = {
            id = "2026-06-30-midnight-curse-of-ulatek-121-ptr-development-notes-32b9da7c85",
            post_key = "32b9da7c85",
            title = "Midnight: Curse of Ula’tek 12.1 PTR Development Notes",
            category = "Midnight: Curse of Ula'tek Public Test Realm (US)",
            timestamp = 1782858658,
            url = "https://us.forums.blizzard.com/en/wow/t/2317811/1",
            content = {
            { type = "h1", text = "MIDNIGHT: CURSE OF ULA’TEK 12.1 PTR DEVELOPMENT NOTES" },
            { type = "hr" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-30-midnight-curse-of-ulatek-121-ptr-development-notes-32b9da7c85\\image-1.jpg" },
            { type = "h2", text = "NEW CAMPAIGN CHAPTERS" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-30-midnight-curse-of-ulatek-121-ptr-development-notes-32b9da7c85\\image-2.jpg" },
            { type = "p", text = "Continue the story of Zul’jan as the fog lifts from the island off the east coast of Zul’Aman. We’ll join Zul’jarra as she pursues him to bring her brother and others home to Zul’Aman. We’ll delve into a long-buried history of the Coiled Isle, learn more about what is locked away, and who was left behind." },
            { type = "h2", text = "THE COILED ISLE" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-30-midnight-curse-of-ulatek-121-ptr-development-notes-32b9da7c85\\image-3.jpg" },
            { type = "p", text = "Within the mountain on the Coiled Isle, you’ll undertake a variety of new activities as you explore this corrupted eco-system filled with poisonous waters and venomous foes." },
            { type = "list_item", text = "Plunge into the Vaults of Atal’Utek primed for challenging group content and rotating public events. Taking part in these public events will ultimately build up to a boss fight.", level = 0 },
            { type = "list_item", text = "While in the zone players will have access to a custom talent tree that will provide different perks of player power along with quality-of-life perks. Ex: Reduce the potency of the venom in the zone.", level = 0 },
            { type = "list_item", text = "As you adventure through the zone, you’ll come across Curse Surges which will regularly spawn rare elites at five rotating locations throughout the isle. Killing a rare elite unlocks Cursed Fishing in that location.", level = 0 },
            { type = "list_item", text = "You’ll also discover a Local story with a tortollan sea captain named Tokka, gain reputation with his crew, and learn to fish in more cursed waters around the isle.", level = 0 },
            { type = "h2", text = "INTRODUCING LAIRS" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-30-midnight-curse-of-ulatek-121-ptr-development-notes-32b9da7c85\\image-4.jpg" },
            { type = "p", text = "Lairs are an evolution on world bosses located in instanced encounters with scaling difficulty up to flexible Mythic with 15-25 players. These will be found in specific locations similar to Delves and will come complete with a summoning stone outside the lair." },
            { type = "p", text = "The goal is to make it easier for players to gather and take on these bosses by encountering them at specific locations where you can choose your difficulty and use the summoning stone to bring others to you." },
            { type = "p", text = "The Lair will be available for testing in a later PTR build." },
            { type = "h2", text = "NEW RAID: THE VENOMOUS ABYSS" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-30-midnight-curse-of-ulatek-121-ptr-development-notes-32b9da7c85\\image-5.jpg" },
            { type = "p", text = "Arriving with the start of Midnight Season 2, players will face Ula’tek herself in the Venomous Abyss. An ancient powerful creature of hatred, corruption, and venom, Ula’tek has been unleashed by Zul’jan’s actions. This new raid dungeon will feature eight new boss encounters and you’ll ultimately face off against Ula’tek as the final boss." },
            { type = "p", text = "Raid testing schedule can be found here: The Venomous Abyss Raid Testing Schedule" },
            { type = "h2", text = "NEW DUNGEON: ALTAR OF FANGS" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-30-midnight-curse-of-ulatek-121-ptr-development-notes-32b9da7c85\\image-6.jpg" },
            { type = "p", text = "This new three boss dungeon will be available up to Heroic difficulty at the launch of the content update and will join the Mythic+ rotation once Midnight Season 2 begins a week after the launch." },
            { type = "p", text = "The Altar of Fangs dungeon will be available for testing in a later PTR build." },
            { type = "h2", text = "DELVES" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-30-midnight-curse-of-ulatek-121-ptr-development-notes-32b9da7c85\\image-7.jpg" },
            { type = "p", text = "Take on three new Delves with one of these Delves as a new Nemesis Delve. You’ll step into The Ring of Glory, Gnarldor Isle, and the Venomfall Deeps Nemesis Delve for new rewards (and a little glory). With the start of Midnight Season 2, Bountiful Delves will become available and players will be able to push into the upper tiers to challenge themselves beyond Tier 7 and face the new Nemesis boss." },
            { type = "p", text = "You’ll also begin encountering new snake and venom variants in existing Midnight Delves." },
            { type = "h2", text = "SEASON 2" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-30-midnight-curse-of-ulatek-121-ptr-development-notes-32b9da7c85\\image-8.jpg" },
            { type = "p", text = "One week after the content update goes live the new season will begin, bringing with it a new dungeon rotation for Mythic+, a new raid, new PvP Season, more Prey, and Bountiful Delves and keys become available." },
            { type = "h3", text = "Mythic+ Dungeon Rotation" },
            { type = "list_item", text = "New Dungeon: Altar of Fangs", level = 0 },
            { type = "list_item", text = "Murder Row", level = 0 },
            { type = "list_item", text = "Den of Nalorakk", level = 0 },
            { type = "list_item", text = "The Blinding Vale", level = 0 },
            { type = "list_item", text = "Voidscar Arena", level = 0 },
            { type = "h3", text = "Returning Dungeons" },
            { type = "list_item", text = "King’s Rest", level = 0 },
            { type = "list_item", text = "Ruby Life Pools", level = 0 },
            { type = "list_item", text = "Temple of Sethraliss", level = 0 },
            { type = "p", text = "The Season 2 dungeons will be available for testing in a later PTR build." },
            { type = "h2", text = "PREY" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-30-midnight-curse-of-ulatek-121-ptr-development-notes-32b9da7c85\\image-9.jpg" },
            { type = "p", text = "Season 2 brings about new Affixes, new targets, and some new hunts on the Coiled Isle in Prey." },
            { type = "p", text = "Astalor also has a few new voice lines to deliver to you and new Arcantina Quests are ahead." },
            { type = "p", text = "The new Prey season will be available for testing in a later PTR build." },
            { type = "h2", text = "HOUSING" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-30-midnight-curse-of-ulatek-121-ptr-development-notes-32b9da7c85\\image-10.jpg" },
            { type = "p", text = "Neighborhoods and player houses will become available in next week’s build." },
            { type = "list_item", text = "BLUEPRINTS", level = 0 },
            { type = "list_item", text = "Blueprints let players save their housing creations to swap between or share them with other players!", level = 1 },
            { type = "list_item", text = "Blueprint codes can be shared cross-region (excluding China) with other players for them to import as well.", level = 1 },
            { type = "list_item", text = "Blueprints operate on the entire house (both inside and out), the interior only, the exterior only, or a single room.", level = 1 },
            { type = "list_item", text = "When importing, a list of all required rooms and decor will be shown, including the budget needed, what’s missing, and so on so players know what’s about to happen or what they need.", level = 1 },
            { type = "list_item", text = "Importing will also try to do the “right” thing for dyed items (using correctly dyed items, potentially dyeing items, but NOT replacing already dyed items, etc).", level = 1 },
            { type = "list_item", text = "Players can have up to 50 “save slots” for their different layouts, as well as 10 additional ones for “auto-saves”.", level = 1 },
            { type = "list_item", text = "Auto-saves are automatically created when importing a Blueprint so players can easily revert.", level = 2 },
            { type = "list_item", text = "Players now have an additional house permission called “Export” that defaults to no one. Other players visiting a house where they pass this permission can choose to import into their own save slots.", level = 1 },
            { type = "list_item", text = "Blueprint codes can be linked in chat and inspected there as well.", level = 1 },
            { type = "list_item", text = "Blueprints can be reported.", level = 1 },
            { type = "list_item", text = "A Reset button has also been added that will reset the whole house or just the interior or exterior if someone wants to start over from scratch.", level = 1 },
            { type = "list_item", text = "PETS", level = 0 },
            { type = "list_item", text = "Pet Beds allow players to show off their pets both in and outside their house.", level = 1 },
            { type = "list_item", text = "Players can place up to 10 beds inside and up to 5 beds outside. Once a bed is placed, players can select a pet to make its home there.", level = 1 },
            { type = "list_item", text = "Indoor pets can be set to either Stationary or Roaming while pets placed outdoors are only Stationary for the time being.", level = 1 },
            { type = "list_item", text = "A small number of pets are unavailable to be placed for a variety of reasons.", level = 1 },
            { type = "list_item", text = "ENDEAVORS", level = 0 },
            { type = "list_item", text = "There are 4 new Endeavors:", level = 1 },
            { type = "list_item", text = "Knock-off Amani (this is the featured Endeavor with the release of Curse of Ula’tek)", level = 2 },
            { type = "list_item", text = "Griftah and his travelling troupe of traders would like to visit the neighborhood to trade their “traditional Amani goods”. It’s fairly obvious that these are not original Amani items, however the neighborhood residents are interested nonetheless.", level = 3 },
            { type = "list_item", text = "Every Bakar Has Its Day", level = 2 },
            { type = "list_item", text = "Residents of the neighborhood love their pets, but they could use some help training them. The centaurs of the Ohn’ahran Plains have very strong bonds with their bakar and they may be willing to pass on some training tips.", level = 3 },
            { type = "list_item", text = "Candle Culture", level = 2 },
            { type = "list_item", text = "Strange wax deposits have started to appear in the neighborhood. Who better to find a use than the Kobolds of the Ringing Deeps? Seek their counsel on illumination.", level = 3 },
            { type = "list_item", text = "Vacation Season", level = 2 },
            { type = "list_item", text = "The Tortollans are a worldly folk. So worldly, in fact, that they need no introduction to your neighborhood–they’ve been vacationing here long before you put down your roots! Share in their recreational wisdom.", level = 3 },
            { type = "list_item", text = "Players may notice new things in their Neighborhood based on the Endeavors that have been completed, both old and new.", level = 1 },
            { type = "list_item", text = "DYE UPDATES", level = 0 },
            { type = "list_item", text = "Dye crafting has been streamlined, considerably freeing up bag space taken up by dyes.", level = 1 },
            { type = "list_item", text = "New dye colors have been added, including those that replicate the darker appearances from before 12.0.5.", level = 1 },
            { type = "list_item", text = "More information can be found in the I Bet You’re Dyeing to Hear About This thread.", level = 1 },
            { type = "list_item", text = "HOUSES", level = 0 },
            { type = "list_item", text = "Houses can now reach level 12, unlocking increased limits, large exteriors, and more.", level = 1 },
            { type = "list_item", text = "Players can now move the entry room anywhere in the house, including other floors! Finally, basement dreams can be realized!", level = 1 },
            { type = "list_item", text = "UI", level = 0 },
            { type = "list_item", text = "Two new categories have been added for decor:", level = 1 },
            { type = "list_item", text = "Vines and Hanging Plants", level = 2 },
            { type = "list_item", text = "Pet Beds", level = 2 },
            { type = "list_item", text = "Removed an extra pop-up when deleting a room with no Decor in it.", level = 0 },
            { type = "h2", text = "DISCORD" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-30-midnight-curse-of-ulatek-121-ptr-development-notes-32b9da7c85\\image-11.jpg" },
            { type = "p", text = "It won’t be long before you’ll be able to speak with your guildmates both in and out of the game by connecting your Battle.net and Discord accounts to chat with your guild no matter where they are. Whether you’re coordinating your next raid run, looking for more to join you in game for PvP, or just hanging out in your neighborhoods together, you’ll be able to send messages between the two quickly and easily." },
            { type = "p", text = "This new feature will be available to test on the PTR next week. We’ll let you know when the feature is live and ready for testing!" },
            { type = "p", text = "More details can be found in our article." },
            { type = "h2", text = "CONTINUE THE HUNT FOR XAL’ATATH WITH ARATOR" },
            { type = "p", text = "We’ll also get an update on Arator as he deals with the fallout from the Voidspire and we’ll also investigate the resurgence of the Twilight’s Blade with him as we continue the hunt for Xal’atath." },
            { type = "h2", text = "DUMMY DOME ON THE PTR" },
            { type = "p", text = "Season 2’s PTR includes the DUMMY DOME!, a new test zone full of combat dummies and 50,000 pounds of MUD MUD MUD that you can reach by speaking to Nexus-Lord Donjon Rade IX in major cities. In this high-octane training arena, you can initiate fights against 1, 2, 3, or 5 dummies that have the same armor as Season 2 raid bosses and whose health decreases steadily over 5-minute encounters for maximum Execution Accuracy. Adrenaline junkies can also spawn a Hazardous Dummy that deals ramping steady damage that will literally kill you and your friends if you don’t heal through it. So rev your engines and cause some CARNAGE!" },
            { type = "h2", text = "CLASSES" },
            { type = "list_item", text = "Player health and creature damage has been increased by 25% at max level. Health consumable values have been adjusted to match new health values.", level = 0 },
            { type = "dev_note", text = "In Curse of Ula’tek, we’ve decided to increase player health and enemy damage by 25% for max level players. We’ve made similar adjustments at the start of Midnight and also in early Dragonflight. Our intent is for damage to be less spiky and for healing gameplay to be more satisfying. When healing is too bursty, enemies have to be tuned to deal spiky damage which requires quick reactions to survive, and we feel that leads to unsatisfying and more stressful gameplay. While we are increasing overall creature damage with this change, we are hand tuning encounter abilities to deal appropriate damage alongside these changes to meet our goals. We’re also making adjustments to several healing and absorb spells for DPS and Tank specializations so that they retain their relative impact.", level = 1 },
            { type = "list_item", text = "In Curse of Ula’tek, we’re going to be lowering throughput for major DPS cooldown’s for several specializations and increasing their steady state damage. When damage done during cooldowns is significantly higher than damage outside of cooldowns, the pacing of combat outside of cooldowns can feel sluggish. Our priority is ensuring that cooldowns continue to be high-impact and fun moments, that damage dealt without cooldowns is effective, and that we maintain texture between specs. We’re going to be observing how this plays out on PTR and it’s possible we will need to make further adjustments or pull back on some of our changes.", level = 0 },
            { type = "list_item", text = "All class interrupts (such as Kick, Pummel, Counterspell, etc) will now display a “missed” visual over the target’s head if used while the target was not casting a spell. It will also play a separate sound to represent a missed interrupt. This is intended to help players recognize when enemies or allies have used their interrupt ability even if a spell was not interrupted.", level = 0 },
            { type = "list_item", text = "DEATH KNIGHT", level = 0 },
            { type = "list_item", text = "Blood", level = 1 },
            { type = "list_item", text = "Permafrost grants a shield equal to 50% of damage dealt (was 40%).", level = 2 },
            { type = "list_item", text = "Voracious grants 15% Leech (was 12%).", level = 2 },
            { type = "list_item", text = "Relish in Blood healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Rapid Decomposition increases Blood Plague healing by 85% (was 50%).", level = 2 },
            { type = "list_item", text = "Sanguinary Burst heals you for 18% of damage dealt (was 15%).", level = 2 },
            { type = "list_item", text = "Umbilicus Eternus absorbs damage equal to 6 times damage dealt by Blood Plague (was 5).", level = 2 },
            { type = "list_item", text = "Frost", level = 1 },
            { type = "list_item", text = "Permafrost grants a shield equal to 35% of damage dealt (was 30%).", level = 2 },
            { type = "list_item", text = "Unholy", level = 1 },
            { type = "dev_note", text = "With Curse of Ula’tek, we’re aiming to smooth the gap between cooldown and non-cooldown throughput. Additionally, we’re taking a look at the current summon density of Unholy Death Knight. For its rework in Midnight, Unholy Death Knight was reimagined as a summoner of the Scourge and we’re very happy with how it landed. However, combined with the previous summoning powers from the Rider of the Apocalypse Hero Talent tree, the amount of summons are exceeding the numbers we’re comfortable with. It is paramount for us to provide a clear game space for our players, and we felt there was no design space left for us to give more summoning powers without ignoring this core principle.", level = 2 },
            { type = "list_item", text = "Reanimation renamed to Lord of the Dead and its secondary effect has been redesigned – When you control 3 Magus of the Dead, sacrifice them to summon their Lord of the Dead for 15 seconds, casting Frostbolts that chain between 2 enemies. Magus with higher remaining duration grant increased power.", level = 2 },
            { type = "list_item", text = "Apex Talent: Forbidden Knowledge (Rank 3) has been updated – Magus of the Dead no longer grants stacking damage to Necrotic Coil and Graveyard. The effectiveness of Putrefy activated by Dread Plague has been increased to 100% (was 60%).", level = 2 },
            { type = "list_item", text = "Soul Reaper has been updated – No longer consumes charges of Putrefy to cast. Now consumes up to 3 Lesser Ghoul stacks to summon them instantly.", level = 2 },
            { type = "list_item", text = "Unholy Aura has been updated – Magus of the Dead now grant the Haste buff on spawn for 15 seconds.", level = 2 },
            { type = "list_item", text = "Army of the Dead has been updated – Summon or empower Lesser Ghouls to form an unholy army of 8 for 30 seconds. While active, you command your army through Scourge Strike, executing Orders based on nearby enemies instead of summoning Lesser Ghouls.", level = 2 },
            { type = "list_item", text = "Death Order – Lesser Ghouls strike with you, dealing Shadow damage to your target.", level = 3 },
            { type = "list_item", text = "Epidemic Order – Lesser Ghouls erupt in viscera, dealing Shadow damage to nearby enemies. Deals reduced damage beyond 5 targets.", level = 3 },
            { type = "list_item", text = "Menacing Magus now has an additional effect – Your Lord of the Dead Frostbolts now chain to 3 additional enemies.", level = 2 },
            { type = "list_item", text = "Lesser Ghoul damage increased by 10%.", level = 2 },
            { type = "list_item", text = "Army of the Dead Lesser Ghoul damage reduced by 20%.", level = 2 },
            { type = "list_item", text = "Necrotic Coil damage increased by 20%.", level = 2 },
            { type = "list_item", text = "Graveyard damage increased by 20%.", level = 2 },
            { type = "list_item", text = "Commander of the Dead now causes Dark Transformation to increase the damage of your summoned creatures by 10%/20% for 30 seconds (was 15%/30%).", level = 2 },
            { type = "list_item", text = "Ruptured Viscera now deals reduced damage beyond 5 targets.", level = 2 },
            { type = "list_item", text = "Players other than the Death Knight can now only see up to 3 Lesser Ghouls at a time.", level = 2 },
            { type = "list_item", text = "Permafrost grants a shield equal to 35% of damage dealt (was 30%).", level = 2 },
            { type = "list_item", text = "DEMON HUNTER", level = 0 },
            { type = "list_item", text = "Demon Hunters can now equip daggers.", level = 1 },
            { type = "dev_note", text = "This will allow Devourer Demon Hunters to acquire and use daggers with Intelligence on them.", level = 2 },
            { type = "list_item", text = "Devourer", level = 1 },
            { type = "dev_note", text = "We’re reducing the scaling of Devourer’s Mastery: Monster Within to help other stats to compete and compensating with an overall ability damage buff. Between that and a few more targeted changes, we expect damage during Void Metamorphosis to be slightly reduced while damage outside of Metamorphosis is significantly increased.", level = 2 },
            { type = "list_item", text = "Mastery: Monster Within has been updated – Bonus damage during Void Metamorphosis reduced by 66%.", level = 2 },
            { type = "list_item", text = "All ability damage increased by 20%.", level = 2 },
            { type = "list_item", text = "Void Metamorphosis now increases Void Ray damage by 40% (was 67%).", level = 2 },
            { type = "list_item", text = "Impending Apocalypse now causes each Collapsing Star to grant 20% increased damage to the next one (was 30%).", level = 2 },
            { type = "list_item", text = "Consume damage increased by 60% (does not affect Devour).", level = 2 },
            { type = "list_item", text = "Havoc", level = 1 },
            { type = "list_item", text = "Demon Blades, Blade Dance, and Chaos Strike now require equipped Warglaives, Axes, Swords, and Fist Weapons.", level = 2 },
            { type = "list_item", text = "New Talent: Never Say Die – Damage increased by 3% while above 50% Health. Leech increased by 5% while below 50% Health.", level = 2 },
            { type = "list_item", text = "Dash of Chaos has been removed.", level = 2 },
            { type = "list_item", text = "Vengeance", level = 1 },
            { type = "list_item", text = "Fracture and Soul Cleave now require equipped Warglaives, Axes, Swords, and Fist Weapons.", level = 2 },
            { type = "list_item", text = "Charred Warblades heals you for 5% of Fire damage you deal (was 4%).", level = 2 },
            { type = "list_item", text = "Soul Cleave healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Fel Devastation healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Frailty causes you to heal for 10% of damage dealt to afflicted targets (was 8%).", level = 2 },
            { type = "list_item", text = "Feast of Souls healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Revel in Pain causes 6% of your Fire damage to shield you (was 5%).", level = 2 },
            { type = "list_item", text = "DRUID", level = 0 },
            { type = "list_item", text = "Matted Fur absorb increased by 25%.", level = 1 },
            { type = "list_item", text = "Heart of the Wild empowered Wild Growth healing increased by 25%.", level = 1 },
            { type = "list_item", text = "Balance", level = 1 },
            { type = "dev_note", text = "Our goal for Balance in Curse of Ula’tek is to emphasize its core gameplay of building, spending, and pooling Astral Power. In Midnight, Balance had high Astral Power generation and a lot of free spender procs, which meant there weren’t many GCDs left after casting spenders. In Curse of Ula’tek we’ve reduced Astral Power generation and the number of free spenders but increased the damage each spender does. The intent is to provide more time to react to Astral Power gain and make pooling Astral Power outside Eclipse to spend inside Eclipse more impactful. We’ve also adjusted some talent power to increase build diversity.", level = 2 },
            { type = "list_item", text = "New passive ability learned at level 42: Stellar Protection – If Moonfire and Sunfire are dispelled, Stellar Flare is applied to the target. Generates 12 Astral Power.", level = 2 },
            { type = "list_item", text = "Umbral Intensity has been updated – Now increases Wrath and Starfire damage by 10% at all times.", level = 2 },
            { type = "list_item", text = "Apex Talent: Ascendant Eclipses (Rank 2) – Astral Smolder damage reduced to 10%/20% of critical strike damage (was 12%/24%) and its duration is increased to 8 seconds (was 6 seconds).", level = 2 },
            { type = "list_item", text = "All damage dealt increased by 4%.", level = 2 },
            { type = "list_item", text = "Starsurge damage increased by 10%.", level = 2 },
            { type = "list_item", text = "Starfall damage increased by 10%.", level = 2 },
            { type = "list_item", text = "Rejuvenation healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Wild Growth healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Regrowth healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Celestial Fire increases the damage of Moonfire, Sunfire, and Shooting Stars by 10% (was 8%).", level = 2 },
            { type = "list_item", text = "Orbit Breaker effectiveness reduced to 50% (was 60%).", level = 2 },
            { type = "list_item", text = "Touch the Cosmos chance to trigger from Wrath reduced to 12% (was 15%), and chance to trigger from Starfire reduced to 15% (was 20%).", level = 2 },
            { type = "list_item", text = "Total Eclipse chance to trigger increased to 15%/30% (was 10%/20%).", level = 2 },
            { type = "list_item", text = "Sculpt the Stars and Astral Communion have swapped positions in the talent tree.", level = 2 },
            { type = "list_item", text = "Sculpt the Stars reduces Eclipse cooldown by 3 seconds (was 2 seconds).", level = 2 },
            { type = "list_item", text = "A counter aura for Orbit Breaker has been added to show your progress toward casting a Full Moon. This aura can be tracked in the Cooldown Manager and manually cancelled to reset your Orbit Breaker progress.", level = 2 },
            { type = "list_item", text = "Hero Talents", level = 2 },
            { type = "list_item", text = "Elune’s Chosen", level = 3 },
            { type = "list_item", text = "Lunar Calling increases the primary target damage of Starfire by 100% (was 120%).", level = 4 },
            { type = "list_item", text = "Keeper of the Grove", level = 3 },
            { type = "list_item", text = "Bounteous Bloom now extends the duration of Force of Nature Treants by 4 seconds instead of adding a fourth Treant.", level = 4 },
            { type = "list_item", text = "Cenarius’ Might haste increase reduced to 6% (was 8%).", level = 4 },
            { type = "list_item", text = "Potent Enchantments haste increase reduced to 6% (was 10%).", level = 4 },
            { type = "list_item", text = "Feral", level = 1 },
            { type = "dev_note", text = "Feral updates in Curse of Ula’tek are aimed at talent diversity. We’d like Chomp to be stronger for players who enjoy it, and we’re adjusting some other talents to get their power closer and open up more build options.", level = 2 },
            { type = "list_item", text = "Saber Jaws damage bonus increased to 60% per point (was 50%).", level = 2 },
            { type = "list_item", text = "Focused Frenzy damage bonus reduced to 15% (was 20%).", level = 2 },
            { type = "list_item", text = "Rip and Tear damage bonus increased to 20% (was 15%).", level = 2 },
            { type = "list_item", text = "Chomp damage increased by 30%.", level = 2 },
            { type = "list_item", text = "Apex Predator’s Craving base chance to trigger reduced to 4% (was 5%).", level = 2 },
            { type = "list_item", text = "Rejuvenation healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Wild Growth healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Regrowth healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "dev_note", text = "We’re making several quality-of-life adjustments to Restoration Druid in this update with a goal of addressing usability issues with Tranquility, Nature’s Swiftness, and Incarnation: Tree of Life. We’re also making a few adjustments to Swiftmend to bring back some of its power as a punchy single-target heal. Finally, we’d like to address issues with Abundance by redesigning it with a clear threshold of when you should be using Regrowth.", level = 2 },
            { type = "list_item", text = "New Talent: Overgrowth – Nature’s Swiftness causes your next Regrowth to apply Lifebloom, Rejuvenation, and Wild Growth’s heal over time effect to an ally.", level = 2 },
            { type = "list_item", text = "New Talent: Flash of Clarity – Omen of Clarity increases Regrowth’s healing by 40%. Now available where Cultivation previously was in the talent tree.", level = 2 },
            { type = "list_item", text = "Cultivation is now available below Flash of Clarity in the talent tree.", level = 2 },
            { type = "list_item", text = "Innervate has been redesigned – Now regenerates 25% of the target’s maximum mana over 8 seconds, rather than causing spells to be free for 8 seconds.", level = 2 },
            { type = "list_item", text = "Abundance has been redesigned – While you have at least 5 Rejuvenations active, Regrowth’s critical strike chance is increased by 50% and its mana cost is reduced by 50%.", level = 2 },
            { type = "list_item", text = "Tranquility has been updated – Now grows protective roots at your feet, absorbing damage equal to 60% of your health and preventing knockbacks.", level = 2 },
            { type = "list_item", text = "Incarnation: Tree of Life has been updated – Now casts Regrowth on up to 3 nearby injured allies when you initially shapeshift.", level = 2 },
            { type = "list_item", text = "Swiftmend has been updated – Healing increased by 40% of the consumed heal over time effect.", level = 2 },
            { type = "list_item", text = "Everbloom (Rank 3) has been updated – Its heal effect now triggers when you press Swiftmend (was Soul of the Forest).", level = 2 },
            { type = "list_item", text = "Verdant Infusion has been updated – No longer extends heal over time effects.", level = 2 },
            { type = "list_item", text = "Germination has been updated – No longer increases Rejuvenation’s duration by 2 seconds.", level = 2 },
            { type = "list_item", text = "Ysera’s Gift has been updated – If its healing would overheal the Druid, the overhealing amount is instead transferred to a nearby ally.", level = 2 },
            { type = "list_item", text = "All spell and ability healing increased by 6%.", level = 2 },
            { type = "list_item", text = "Wild Growth healing increased by 20%.", level = 2 },
            { type = "list_item", text = "Wild Growth mana cost increased by 15%.", level = 2 },
            { type = "list_item", text = "Verdancy healing increased by 40%.", level = 2 },
            { type = "list_item", text = "Rejuvenation mana cost reduced by 10%.", level = 2 },
            { type = "list_item", text = "Regrowth mana cost reduced by 10%.", level = 2 },
            { type = "list_item", text = "Lifebloom mana cost reduced by 20%.", level = 2 },
            { type = "list_item", text = "Passing Seasons reduces Nature’s Swiftness cooldown by 15 seconds (was 12 seconds).", level = 2 },
            { type = "list_item", text = "Symbiotic Relationship now highlights itself on the action bar while it is not active.", level = 2 },
            { type = "list_item", text = "Germination and Verdancy have swapped positions in the talent tree.", level = 2 },
            { type = "list_item", text = "Nature’s Splendor has been removed.", level = 2 },
            { type = "list_item", text = "Guardian", level = 1 },
            { type = "dev_note", text = "Our goals with these Guardian Druid updates are largely to address issues with the specialization’s damage composition and ability breakdown. In particular, we’re reworking Lunation in order to resolve its adverse rotational pressure, and our adjustments to Gory Fur and Wild Guardian are intended to incentivize more balance between Rage spenders as well as distribute the impact of the Apex talent across a longer duration and a broader portion of the kit.", level = 2 },
            { type = "list_item", text = "Gory Fur has been redesigned – Ironfur has a chance to make your next Maul, Raze, or Ravage free. Maul, Raze, or Ravage have a chance to make your next Ironfur free.", level = 2 },
            { type = "list_item", text = "Apex Talent: Wild Guardian has been redesigned (not yet implemented) –", level = 2 },
            { type = "list_item", text = "Rank 1: Spending Rage has a chance to awaken a Guardian Spirit for 8 seconds, which attacks a nearby enemy and generates 3 Rage when you cast Thrash or Mangle.", level = 3 },
            { type = "list_item", text = "Rank 2: Mangle and Maul deal 20%/40% additional Nature damage over 12 seconds. Your Mastery is increased by 3%/6%.", level = 3 },
            { type = "list_item", text = "Rank 3: When a spirit is awakened, the cooldowns of Thrash and Mangle are reset. After casting Berserk or Incarnation: Guardian of Ursoc, gain 2 charges of Wild Guardian.", level = 3 },
            { type = "list_item", text = "Wild Guardian: Your next cast of Maul is guaranteed to awaken a spirit.", level = 4 },
            { type = "list_item", text = "Brambles absorb increased by 25%.", level = 2 },
            { type = "list_item", text = "After the Wildfire healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Ursoc’s Fury grants an absorb for 35% of Thrash and Maul damage (was 30%).", level = 2 },
            { type = "list_item", text = "Elune’s Favored heals you for 18% of Arcane damage dealt (was 15%).", level = 2 },
            { type = "list_item", text = "Lunar Beam healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Lunation reduces Lunar Beam’s cooldown by 20 seconds (was 3 seconds per Arcane ability).", level = 2 },
            { type = "list_item", text = "Hero Talents", level = 2 },
            { type = "list_item", text = "Elune’s Chosen", level = 3 },
            { type = "list_item", text = "Boundless Moonlight – Lunar Beam now causes you to Leech 12% of damage dealt to affected enemies (was 10%).", level = 4 },
            { type = "list_item", text = "EVOKER", level = 0 },
            { type = "list_item", text = "Augmentation", level = 1 },
            { type = "dev_note", text = "The additional stopping power created by Duplicate-cast Upheavals was more warping to dungeon gameplay than desired, and could be frustrating in some situations due to its uncontrolled timing.", level = 2 },
            { type = "list_item", text = "Apex Talent: Duplicate – Upheaval casts by your Duplicate no longer knock enemies into the air.", level = 2 },
            { type = "list_item", text = "Living Flame healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Verdant Embrace healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Emerald Blossom healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Hero Talents", level = 2 },
            { type = "list_item", text = "Chronowarden", level = 3 },
            { type = "list_item", text = "Double-time has been updated – The additional stats granted when Ebon Might critically strikes now last 15 seconds (modified by Mastery: Timewalker). Double-time’s functionality with Prescience is unchanged.", level = 4 },
            { type = "dev_note", text = "The behavior of an Ebon Might critical strike’s stat bonus lasting for the full duration of the Ebon Might put more emphasis on tracking Ebon Might’s critical state than desired, and created an unintuitive decision space regarding whether re-casting Ebon Might was correct.", level = 5 },
            { type = "list_item", text = "Devastation", level = 1 },
            { type = "dev_note", text = "Devastation’s Apex talent, while powerful, hasn’t been as gameplay-affecting as we had hoped. We’ve redesigned the Rank 3 effect to override Dragonrage with a limited number of uses of a new, powerful spell, Unbound Flame, once Dragonrage is over. Additionally, Rising Fury and Risen Fury have been streamlined into one buff effect. Please give Unbound Flame a try on the PTR, and let us know how this new spell feels!", level = 2 },
            { type = "list_item", text = "Rising Fury (Rank 3) has been redesigned – When Dragonrage ends, Rising Fury persists for 4 seconds per stack, and Dragonrage becomes Unbound Flame. Unbound Flame may be cast 4 times before Dragonrage finishes its cooldown.", level = 2 },
            { type = "list_item", text = "Unbound Flame – Exhale destructive flame, critically striking for Fire damage to your target and nearby enemies. Damage reduced beyond 5 targets. Causes 1 Essence Burst. Instant cast and 25-yard range.", level = 3 },
            { type = "list_item", text = "Tyranny has been updated – Now interacts with Unbound Flame, causing Unbound Flame to always gain the maximum benefit of Mastery: Giantkiller regardless of the targets’ health.", level = 2 },
            { type = "list_item", text = "Living Flame healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Verdant Embrace healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Emerald Blossom healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Risen Fury has been removed.", level = 2 },
            { type = "list_item", text = "Preservation", level = 1 },
            { type = "dev_note", text = "The goal of this change is to make Dream Breath a flexible heal that can once again serve as a powerful heal over time effect or a burst heal when charged. This also further differentiates it from spells like Verdant Embrace and Merithra’s Blessing, which have filled a similar role as an on-demand burst heal.", level = 2 },
            { type = "list_item", text = "Merithra’s Blessing has been updated – Now increases all healing of Dream Breath by 60% (was 250%, and previously applied only to its instant healing).", level = 2 },
            { type = "list_item", text = "Font of Magic has been updated – Now also reduces the empower time of Dream Breath and Fire Breath by 20%.", level = 2 },
            { type = "list_item", text = "Dream Breath instant healing reduced by 50%.", level = 2 },
            { type = "list_item", text = "Dream Breath periodic healing increased by 118%.", level = 2 },
            { type = "list_item", text = "Temporal Barrier absorption increased by 30%.", level = 2 },
            { type = "list_item", text = "HUNTER", level = 0 },
            { type = "list_item", text = "Ranged auto-shot damage increased by 600%.", level = 1 },
            { type = "list_item", text = "Hunter’s Mark can now be applied to up to 5 targets (was 1).", level = 1 },
            { type = "dev_note", text = "This change should allow Hunters to more reliably apply the Hunter’s Mark debuff in raid or dungeon boss encounters when there are multiple bosses without the need to bring multiple Hunters.", level = 2 },
            { type = "list_item", text = "Hero Talents", level = 1 },
            { type = "list_item", text = "Dark Ranger", level = 2 },
            { type = "list_item", text = "Bleak Arrows damage increased by 300%.", level = 3 },
            { type = "list_item", text = "Withering Fire’s Black Arrow damage reduced by 40%.", level = 3 },
            { type = "list_item", text = "Beast Mastery", level = 1 },
            { type = "dev_note", text = "Beast Mastery Hunters felt a bit weak outside of Bestial Wrath damage windows, so we’re increasing their steady-state damage by boosting Kill Command, Cobra Shot, and Barbed Shot. We’re increasing the duration of Beast Cleave to 10 seconds, so you should be able to maintain 100% uptime in area damage situations as long as you are using Wild Thrash when it is available.", level = 2 },
            { type = "list_item", text = "Heart of the Pack renamed to Razor Sharp and has been redesigned – Increases the damage of your pet’s Bite, Claw, and Smack by 100%.", level = 2 },
            { type = "list_item", text = "Piercing Fangs has been redesigned – Kill Command critical damage increased by 15%.", level = 2 },
            { type = "list_item", text = "Bloody Frenzy has been updated – Now reduces Barbed Shot’s periodic rate increase by 33% (was 50%).", level = 2 },
            { type = "list_item", text = "Kill Cleave has been updated – Kill Command now only cleaves 20% of its damage during Beast Cleave (was 40%).", level = 2 },
            { type = "list_item", text = "Barbed Shot damage increased by 25%.", level = 2 },
            { type = "list_item", text = "Kill Command damage increased by 20%.", level = 2 },
            { type = "list_item", text = "Cobra Shot damage increased by 20%.", level = 2 },
            { type = "list_item", text = "Beast Cleave duration increased to 10 seconds (was 8 seconds).", level = 2 },
            { type = "list_item", text = "Dire Beast summons can now be tracked on the Cooldown Manager.", level = 2 },
            { type = "list_item", text = "Wild Instincts has been removed.", level = 2 },
            { type = "list_item", text = "Hero Talents", level = 2 },
            { type = "list_item", text = "Dark Ranger", level = 3 },
            { type = "list_item", text = "Dark Hound summons can now be tracked on the Cooldown Manager.", level = 4 },
            { type = "list_item", text = "Marksmanship", level = 1 },
            { type = "dev_note", text = "Marksmanship Hunter’s last round of changes reintroduced Explosive Shot as a button players can opt into, but it didn’t flow well with how the spec was playing. In Midnight Season 2, we’re making changes to Explosive Shot’s design and some of its supporting talents. The Headshot talent has also been a source of frustration, so we’re removing it and adjusting how Deathblow works to make it more predictable when you should follow up an Aimed Shot cast with a Kill Shot or Black Arrow. Finally, we’re adjusting Markmanship’s Apex Talent nodes to no longer make Aimed Shot a guaranteed critical strike to reduce the emphasis on Aimed Shot modifiers.", level = 2 },
            { type = "list_item", text = "New Talent: Unstable Trigger – Explosive Shot can be used a second time if used within 3 seconds. Explosive Shot incorporates any remaining damage from previous Explosive Shots on your target.", level = 2 },
            { type = "list_item", text = "Explosive Shot has been redesigned – Fire an explosive shot at your target. Every 1 second for 3 seconds, the target explodes, dealing Fire damage to all enemies within 8 yards. Damage reduced beyond 5 targets. Recasting Explosive Shot incorporates any remaining damage from previous Explosive Shots on your target.", level = 2 },
            { type = "dev_note", text = "We are pivoting the design of Explosive Shot quite a bit to attempt to find a stronger identity. The changes to the core Explosive Shot as well as the Explosive Shot related talents should give it a distinct feel to play with compared to your other main abilities.", level = 3 },
            { type = "list_item", text = "Explosive Shot’s visual has been updated.", level = 2 },
            { type = "list_item", text = "Explosive Shot’s tooltip has been updated and now includes contextual notes when Unstable Trigger is talented.", level = 2 },
            { type = "list_item", text = "Precision Detonation has been redesigned – Explosive Shot lasts for 1 additional second.", level = 2 },
            { type = "list_item", text = "Shrapnel Shot renamed to Incendiary Ammunition and has been redesigned – Explosive Shot’s cooldown is reduced by 10 seconds.", level = 2 },
            { type = "list_item", text = "Incendiary Ammunition and Unstable Trigger are now a choice node.", level = 2 },
            { type = "list_item", text = "Apex Talent: Take Aim (Rank 2) has been redesigned – Your critical strike damage is increased by 5%/10%. Your ranged abilities deal 3%/6% increased damage.", level = 2 },
            { type = "list_item", text = "Apex Talent: Take Aim (Rank 3) has been updated – Spotter’s Mark now increases the damage of your next Aimed Shot and Rapid Fire against the target (was Aimed Shot only).", level = 2 },
            { type = "list_item", text = "Developer’s notes: The previous version of Marksmanship’s Apex Talents put too much emphasis on Aimed Shot and its critical damage modifiers. This new version should better interact with more of your specialization’s abilities.", level = 3 },
            { type = "list_item", text = "Bulletstorm has been redesigned – Rapid Fire now increases the damage of your next Aimed Shot by 20%.", level = 2 },
            { type = "list_item", text = "Incendiary Ammunition renamed to Accuracy by Volume and has been redesigned – Bulletstorm now affects your next 2 Aimed Shots.", level = 2 },
            { type = "list_item", text = "Deathblow has been updated – Aimed Shot now has a chance to cause your next Aimed Shot to grant the Deathblow effect.", level = 2 },
            { type = "dev_note", text = "Our goal with our Deathblow updates for Marksmanship Hunters is to make it clear to you when you should follow up an Aimed Shot with a Kill Shot or Black Arrow cast rather than having the uncertainty of which button to press. Rapid Fire’s 100% chance to get the Deathblow effect is unchanged, you should always be able to follow-up a Rapid Fire with a Kill Shot or Black Arrow.", level = 3 },
            { type = "list_item", text = "Aspect of the Hydra has been updated – Arcane Shot no longer cleaves.", level = 2 },
            { type = "list_item", text = "Aimed Shot damage increased by 20%.", level = 2 },
            { type = "list_item", text = "Rapid Fire damage increased by 20%.", level = 2 },
            { type = "list_item", text = "Arcane Shot damage increased by 20%.", level = 2 },
            { type = "list_item", text = "Multi-Shot damage increased by 20%.", level = 2 },
            { type = "list_item", text = "Kill Shot damage increased by 20%.", level = 2 },
            { type = "list_item", text = "Eagle’s Accuracy is now a 1-point talent that increases the damage of Aimed Shot by 5% (was 10%) and Rapid Fire by 10% (was 20%).", level = 2 },
            { type = "list_item", text = "Focused Aim now reduces the cooldown of Aimed Shot by 1 second (was 2 seconds).", level = 2 },
            { type = "list_item", text = "Fixed an issue that caused Deathblow to not trigger at the expected rates when casting Aimed Shot.", level = 2 },
            { type = "list_item", text = "Aimed Shot has a new icon.", level = 2 },
            { type = "list_item", text = "Some talents have changed locations in the second gate of the talent tree to make Explosive Shot more easily obtained.", level = 2 },
            { type = "list_item", text = "The Tenacious/Cunning talent node has been moved and is no longer required pathing to reach Trueshot.", level = 2 },
            { type = "list_item", text = "Small Game Hunter is now a 2-point talent. Values unchanged.", level = 2 },
            { type = "list_item", text = "The following talents have been removed:", level = 2 },
            { type = "list_item", text = "Double Tap", level = 3 },
            { type = "list_item", text = "Headshot", level = 3 },
            { type = "list_item", text = "Hero Talents", level = 2 },
            { type = "list_item", text = "Dark Ranger", level = 3 },
            { type = "list_item", text = "Through the Eyes has been redesigned – Increases the damage of Kill Shot and Black Arrow by 10%.", level = 4 },
            { type = "list_item", text = "Black Arrow no longer highlights itself whenever it is able to be used against the target.", level = 4 },
            { type = "list_item", text = "Black Arrow direct damage reduced by 40%.", level = 4 },
            { type = "list_item", text = "Ebon Bowstring now causes Black Arrow to have a chance to cause your next Aimed Shot to grant the Deathblow effect.", level = 4 },
            { type = "list_item", text = "Dark Minion summons can now be tracked on the Cooldown Manager.", level = 4 },
            { type = "list_item", text = "Sentinel", level = 3 },
            { type = "list_item", text = "Moon’s Blessing now only causes 1 second of cooldown reduction to Aimed Shot (was 2 seconds).", level = 4 },
            { type = "list_item", text = "Survival", level = 1 },
            { type = "list_item", text = "New Talent: Razor Edge – Raptor Strike, Raptor Swipe, and Kill Command gain 10% increased critical strike chance and 10% increased critical damage dealt.", level = 2 },
            { type = "list_item", text = "Primal Surge has been moved up to an easier to access location in the talent tree.", level = 2 },
            { type = "dev_note", text = "We’re hoping that making this talent easier to obtain should open up more talent build variety.", level = 3 },
            { type = "list_item", text = "Shower of Blood has been removed.", level = 2 },
            { type = "list_item", text = "Hero Talents", level = 2 },
            { type = "list_item", text = "Sentinel", level = 3 },
            { type = "list_item", text = "Lethal Barbs has been updated – Auto-attacks now have a very high chance to generate 3 Focus, rather than granting 1 Focus per auto-attack.", level = 4 },
            { type = "dev_note", text = "The previous version of the Lethal Barbs talent favored dual wielding the fastest attack speed weapons. We’re changing it to be a very high chance to generate 3 Focus, which should normalize the Focus gain and allow you to wield your preferred weapon types.", level = 5 },
            { type = "list_item", text = "Scout’s Vigil no longer increases stealth detection radius while using Camouflage.", level = 4 },
            { type = "list_item", text = "MAGE", level = 0 },
            { type = "dev_note", text = "We’re making some adjustments to Mage defensives with the goal of improving Mage survivability as a whole and slightly reducing the power of Glacial Bulwark.", level = 1 },
            { type = "list_item", text = "New Talent: Improved Warding – Damage taken from area of effect attacks reduced by 4%.", level = 1 },
            { type = "list_item", text = "Improved Prismatic Barrier has been updated – Now grants an additional charge of Prismatic Barrier, in addition to its previous bonuses.", level = 1 },
            { type = "list_item", text = "Temporal Realignment has been updated – Now immediately heals 20% of your health and heals an additional 30% over 6 seconds.", level = 1 },
            { type = "list_item", text = "Hero Talents", level = 1 },
            { type = "list_item", text = "Spellslinger", level = 2 },
            { type = "list_item", text = "Spellfrost Teachings’s tooltip has been adjusted for clarity. Functionality unchanged.", level = 3 },
            { type = "list_item", text = "Sunfury", level = 2 },
            { type = "dev_note", text = "We’re redesigning Rondurmancy to lean into making your 3 orbs better, rather than giving you 5 orbs, to align more closely with the inspirations for Sunfury and reduce visual clutter on your character. We’re also uncapping Mana Cascade to match other “applications may overlap” effects.", level = 3 },
            { type = "list_item", text = "Rondurmancy has been redesigned – Your chance to generate a Spellfire Sphere is increased by 6%/12%. Spellfire Spheres grant an additional 1% spell damage.", level = 3 },
            { type = "list_item", text = "Ashes of Inspiration has been redesigned – Each time your Phoenix casts a spell, gain 1 stack of Mana Cascade. Exceptional Spells grant 1 additional stack.", level = 3 },
            { type = "list_item", text = "Memory of Al’ar has been updated – Combustion and Arcane Surge no longer cause the Mage to gain twice as many stacks of Mana Cascade.", level = 3 },
            { type = "list_item", text = "Spellfire Spheres orb generation chance reduced to 6% for Arcane Mages and 12% for Fire Mages (was 12% and 25%).", level = 3 },
            { type = "list_item", text = "Mana Cascade no longer has a stack cap.", level = 3 },
            { type = "list_item", text = "Mana Cascade is now also gained when the Mage casts Arcane Pulse or Prismatic Bolt.", level = 3 },
            { type = "list_item", text = "Fixed an issue for Arcane that caused Mana Cascade to be gained from some unintended spells.", level = 3 },
            { type = "list_item", text = "Arcane", level = 1 },
            { type = "dev_note", text = "We’re redesigning Arcane Mage’s Apex Talent to provide a more exciting visual moment and a greater impact on your talent build and rotation. Arcane Pulse has also been redesigned to focus its identity as a significant area damage event and a way to quickly regain charges in AOE.", level = 2 },
            { type = "list_item", text = "New Apex Talent: Prismatic Bolt", level = 2 },
            { type = "list_item", text = "Rank 1: Arcane Barrage has a 1% chance per Arcane Salvo stack consumed to trigger Prismatic Bolt. Prismatic Bolt devastates the target with overwhelming energy, dealing Arcane damage to your target and reduced Arcane damage to nearby enemies. Damage reduced beyond 5 targets. Generates 4 Arcane Charges. Not affected by Arcane Blast talents or effects and does not scale its damage or mana cost with Arcane Charges.", level = 3 },
            { type = "list_item", text = "Rank 2: Prismatic Bolt has a 50%/100% chance to grant Clearcasting. Arcane Missiles damage increased by 15%/30%.", level = 3 },
            { type = "list_item", text = "Rank 3: Arcane Salvo grants an additional 1% chance to trigger Prismatic Bolt. Arcane Barrage damage increased by 15%.", level = 3 },
            { type = "list_item", text = "Arcane Pulse has been redesigned – Cast time reduced to 2 seconds (was 2.25 seconds). Radius increased to 8 yards (was 2 yards). Now has a 15-second cooldown, generates 1 Arcane Charge for each enemy struck, and costs 10% of base mana. No longer has its cast time, radius, mana cost, or cast speed affected by Arcane Charges.", level = 2 },
            { type = "list_item", text = "Expanded Mind has been updated – Casting Prismatic Bolt now grants 4 stacks of Arcane Salvo.", level = 2 },
            { type = "list_item", text = "Impetus no longer affects Arcane Pulse.", level = 2 },
            { type = "list_item", text = "Prodigious Savant no longer affects Arcane Pulse.", level = 2 },
            { type = "list_item", text = "Touch of the Archmage has been removed.", level = 2 },
            { type = "list_item", text = "Fire", level = 1 },
            { type = "dev_note", text = "Our goal with these changes is to shift the relative value of Fire’s steady-state damage versus Combustion window burst. It is important that time spent outside of Combustion remains meaningful and impactful to your overall performance.", level = 2 },
            { type = "list_item", text = "Pyroblast damage increased by 15%.", level = 2 },
            { type = "list_item", text = "Flamestrike damage increased by 15%.", level = 2 },
            { type = "list_item", text = "Apex Talent: Fired Up (Rank 1) now grants 2% increased Fire damage for 8 seconds (was 4% for 12 seconds).", level = 2 },
            { type = "list_item", text = "Apex Talent: Fired Up (Rank 2) now increases Fire damage by 5%/10% (was 3%/6%).", level = 2 },
            { type = "list_item", text = "Apex Talent: Fired Up (Rank 3) chance to occur during Combustion has been slightly reduced.", level = 2 },
            { type = "list_item", text = "Frost", level = 1 },
            { type = "list_item", text = "Glacial Bulwark has been updated – No longer grants an additional charge of Ice Barrier.", level = 2 },
            { type = "list_item", text = "All damage dealt increased by 4%.", level = 2 },
            { type = "list_item", text = "Apex Talent: Hand of Frost (Rank 2) now grants 0.5%/1% increased spell damage (was 1%/2%).", level = 2 },
            { type = "dev_note", text = "Hand of Frost in combination with Frost’s Hero Talents was providing more burst than we’d like.", level = 3 },
            { type = "list_item", text = "MONK", level = 0 },
            { type = "list_item", text = "Chi Transfer now causes Touch of Death to heal you for 60% of damage it deals (was 50%).", level = 1 },
            { type = "list_item", text = "Vigorous Expulsion increases Expel Harm’s healing by 6% (was 5%).", level = 1 },
            { type = "list_item", text = "Brewmaster", level = 1 },
            { type = "list_item", text = "Stagger reduction from Staggering Strikes increased by 25%.", level = 2 },
            { type = "list_item", text = "Spirit of the Ox chance to generate a healing sphere increased by 20%.", level = 2 },
            { type = "list_item", text = "Celestial Brew and Celestial Infusion absorb increased by 25%.", level = 2 },
            { type = "list_item", text = "Awakening Spirit’s maximum absorb value increased by 25%.", level = 2 },
            { type = "list_item", text = "Vital Flame heals for 50% of Fire or Nature damage dealt (was 40%).", level = 2 },
            { type = "list_item", text = "The following buffs are now tracked in the Cooldown Manager: Fuel on the Fire, Hot Potato, Scorched, Crackling Jade Lightning, and August Blessing.", level = 2 },
            { type = "list_item", text = "Mistweaver", level = 1 },
            { type = "dev_note", text = "We’re making a few adjustments to Mistweaver Monk with the intent of incentivizing Mastery as a more viable secondary stat and shifting some throughput out of Spinning Crane Kick and into Ancient Teachings.", level = 2 },
            { type = "list_item", text = "New Talent: Vital Expenditure – Soothing Mist’s healing is increased by 300%, but its mana cost is increased by 200%. Choice node with Dancing Mists.", level = 2 },
            { type = "list_item", text = "All healing reduced by 3%.", level = 2 },
            { type = "list_item", text = "Mastery: Gust of Mist healing increased by 50%.", level = 2 },
            { type = "list_item", text = "Spinning Crane Kick damage decreased by 15%.", level = 2 },
            { type = "list_item", text = "Way of the Crane now transfers 280% of damage done (was 340%).", level = 2 },
            { type = "list_item", text = "Jadefire Teachings now increases Ancient Teaching’s transfer amount by 320% (was 270%).", level = 2 },
            { type = "list_item", text = "Windwalker", level = 1 },
            { type = "dev_note", text = "We are making a few adjustments to Windwalker’s damage profile to reduce the gap between their steady-state damage and high-end burst capabilities.", level = 2 },
            { type = "list_item", text = "Melee auto-attack damage increased by 30%.", level = 2 },
            { type = "list_item", text = "Zenith Stomp damage reduced by 30%.", level = 2 },
            { type = "list_item", text = "Blackout Kick damage increased by 50%.", level = 2 },
            { type = "list_item", text = "Tiger Palm damage increased by 200%.", level = 2 },
            { type = "list_item", text = "Dual Threat damage increased by 30%.", level = 2 },
            { type = "list_item", text = "Weapon of Wind now increases damage during Zenith by 5% (was 10%).", level = 2 },
            { type = "list_item", text = "Tigereye Brew now increases Critical Strike damage by 5%/10% (was 10%/20%).", level = 2 },
            { type = "list_item", text = "Vivify healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Hero Talents", level = 2 },
            { type = "list_item", text = "Conduit of the Celestials", level = 3 },
            { type = "list_item", text = "Celestial Conduit damage reduced by 25%.", level = 4 },
            { type = "list_item", text = "Temple Training increases the damage of Fists of Fury and Spinning Crane Kick by 30% (was 10%).", level = 4 },
            { type = "list_item", text = "PALADIN", level = 0 },
            { type = "list_item", text = "Golden Path healing increased by 25%.", level = 1 },
            { type = "list_item", text = "Lightforged Blessing healing increased by 25%.", level = 1 },
            { type = "list_item", text = "Brought to Light healing increased by 25%.", level = 1 },
            { type = "list_item", text = "Hero Talents", level = 1 },
            { type = "list_item", text = "Lightsmith", level = 2 },
            { type = "list_item", text = "Rite of Adjuration healing increased by 25%.", level = 3 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "dev_note", text = "With these changes we’re intending to reduce the opportunity cost associated with taking Sentinel and broadening the suite of defensive talent options. We’re also transferring some power out of strong cooldown windows and into baseline throughput, with the goal of reducing associated threat pain points and improving the feel of combat outside of cooldowns.", level = 2 },
            { type = "list_item", text = "New Talent: Blessed Word – Word of Glory can no longer critically strike, but its healing is increased by your critical strike chance and 80% of its overhealing done to you instead shrouds you in Light, granting an absorb shield.", level = 2 },
            { type = "list_item", text = "Improved Ardent Defender has been redesigned – Now increases maximum HP by 20% while active and no longer cancels remaining duration if fatal damage is sustained.", level = 2 },
            { type = "list_item", text = "Seal of Reprisal has been redesigned – Blessed Hammer reduces enemy damage dealt to you by 10% for 8 seconds.", level = 2 },
            { type = "list_item", text = "Masterwork has been updated – After casting a Holy Armament, your next 3 casts of Hammer of the Righteous/Blessed Hammer/Crusader Strike bestow a Lesser Armament of the same kind on a nearby ally.", level = 2 },
            { type = "list_item", text = "Judgment damage increased by 100%.", level = 2 },
            { type = "list_item", text = "Consecration damage increased by 100%.", level = 2 },
            { type = "list_item", text = "Shield of the Righteous damage increased by 150%.", level = 2 },
            { type = "list_item", text = "Hammer of the Righteous primary damage increased by 50%.", level = 2 },
            { type = "list_item", text = "Avenging Wrath increases damage and healing done by 10%, and critical strike by 10%.", level = 2 },
            { type = "list_item", text = "Avenger’s Shield damage increased by 30%.", level = 2 },
            { type = "list_item", text = "Lesser Weapon damage increased by 50%.", level = 2 },
            { type = "list_item", text = "Hammer of Light damage reduced by 33%.", level = 2 },
            { type = "list_item", text = "Empyrean Hammer damage reduced by 33%.", level = 2 },
            { type = "list_item", text = "Divine Exaction’s Divine Toll effectiveness reduced to 80% (was 150%).", level = 2 },
            { type = "list_item", text = "Sentinel duration increased to 20 seconds.", level = 2 },
            { type = "list_item", text = "Undying Embers heals you for 125% of damage dealt by Refining Fire (was 100%).", level = 2 },
            { type = "list_item", text = "Bulwark of Order absorb increased to 75% of Avenger’s Shield damage (was 60%).", level = 2 },
            { type = "list_item", text = "Solace causes Consecration to heal you for 375% of damage it deals (was 300%).", level = 2 },
            { type = "list_item", text = "Sacred Weapon and Holy Bulwark extend their duration when reapplied by the same caster.", level = 2 },
            { type = "list_item", text = "Glory of the Vanguard now deals damage as a percentage of Avenger’s Shield’s initial damage.", level = 2 },
            { type = "list_item", text = "Sentinel has been moved, and now inherits Avenging Wrath’s critical strike bonus.", level = 2 },
            { type = "list_item", text = "Sanctified Wrath has been removed.", level = 2 },
            { type = "list_item", text = "Retribution", level = 1 },
            { type = "dev_note", text = "In addition to addressing the throughput spikes during cooldown windows, with Curse of Ula’tek we are aiming to smooth out the rotation by reducing the pressure on consuming Art of War/Righteous Cause effects. Alongside these changes, we are also removing some interactions with the Skyfury buff that deeply impacts the rotation and Holy Power economy. We believe this is a healthier direction for Retribution Paladin that will allow for more choice and player agency.", level = 2 },
            { type = "list_item", text = "Apex Talent: Light Within (Rank 1) now has an additional effect – Art of War and Righteous Cause can now each accumulate an additional time.", level = 2 },
            { type = "list_item", text = "Art of War has been updated – Now increases Blade of Justice damage by 80% (was 150%).", level = 2 },
            { type = "list_item", text = "Blade of Justice damage increased by 40%.", level = 2 },
            { type = "list_item", text = "Final Verdict damage increased by 15%.", level = 2 },
            { type = "list_item", text = "Divine Storm damage increased by 15%.", level = 2 },
            { type = "list_item", text = "Avenging Wrath now increases damage done and critical strike chance by 15% (was 20%).", level = 2 },
            { type = "list_item", text = "Templar Strike damage increased by 50%.", level = 2 },
            { type = "list_item", text = "Templar Slash damage increased by 50%.", level = 2 },
            { type = "list_item", text = "Judgment damage increased by 50%.", level = 2 },
            { type = "list_item", text = "Hammer of Wrath damage increased by 50%.", level = 2 },
            { type = "list_item", text = "Divine Toll’s Judgment now deals 50% increased damage (was 100%).", level = 2 },
            { type = "list_item", text = "Apex Talent: Light Within (Rank 3) damage reduced by 25%.", level = 2 },
            { type = "list_item", text = "Flash of Light healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Word of Glory healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Eternal Flame healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Art of War no longer activates from additional Skyfury attacks.", level = 2 },
            { type = "list_item", text = "Additional Skyfury attacks no longer generate Holy Power when talented into Crusading Strikes.", level = 2 },
            { type = "list_item", text = "Crusading Strikes now increases auto-attack speed by 15% (was decreasing by 20%).", level = 2 },
            { type = "list_item", text = "Execution Sentence area of effect radius increased to 10 yards and now includes the bounding radius of the target (was 8 yards).", level = 2 },
            { type = "list_item", text = "Hero Talents", level = 2 },
            { type = "list_item", text = "Templar", level = 3 },
            { type = "list_item", text = "Hammer of Light damage reduced by 30%. Does not affect PvP combat.", level = 4 },
            { type = "list_item", text = "Hammer of Light now costs 3 Holy Power (was 5).", level = 4 },
            { type = "list_item", text = "PRIEST", level = 0 },
            { type = "list_item", text = "Discipline", level = 1 },
            { type = "dev_note", text = "For Discipline in Curse of Ula’tek, our changes are aimed at reducing the spec’s reliance on procs for effective healing, improving sources of consistent damage, and improving Hero talent balance. We felt the spec was too reliant on Shadow Mend and Void Shield procs for effective healing, so we’re updating Shadow Mend to be a passive upgrade to Flash Heal and adding a deterministic way to gain access to Void Shield. Additionally, Smite contributes a low amount of damage despite being frequently cast, so we’re increasing its damage and updating the talent tree for easier access to Greater Smite.", level = 2 },
            { type = "list_item", text = "New Talent: Grim Deliverance – Shadow Mend heals for 30% more and applies Atonement for an additional 4 seconds, but its cast time is increased by 0.5 seconds.", level = 2 },
            { type = "list_item", text = "Shadow Mend’s chance to trigger is no longer based on Shadow Word: Pain damage and has been redesigned to a passive upgrade – Flash Heal is upgraded to Shadow Mend, a stronger heal with a higher mana cost.", level = 2 },
            { type = "list_item", text = "Apex Talent: Master the Darkness (Rank 3) has been updated – Mind Blast now upgrades your next Power Word: Shield to Void Shield. Void Shield’s chance to trigger from Penance reduced to 25% (was 33%).", level = 2 },
            { type = "list_item", text = "Apex Talent: Master the Darkness (Rank 3) has been updated – Void Shield now reflects 15% of damage taken (was 25%).", level = 2 },
            { type = "list_item", text = "Apex Talent: Master the Darkness can now accumulate up to 2 charges.", level = 2 },
            { type = "list_item", text = "Flash Heal healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Smite damage increased by 40%.", level = 2 },
            { type = "list_item", text = "Inescapable Torment damage reduced by 30%.", level = 2 },
            { type = "list_item", text = "Penance no longer applies Atonement when cast on an ally.", level = 2 },
            { type = "dev_note", text = "We updated Penance to apply Atonement going into Midnight but have felt this has not been playing well as it causes too much friction between casting Penance on allies that need healing, allies that need Atonement applied, and enemies you want to deal damage to.", level = 3 },
            { type = "list_item", text = "Greater Smite is now a 1-point talent.", level = 2 },
            { type = "list_item", text = "Hero Talents", level = 2 },
            { type = "list_item", text = "Oracle", level = 3 },
            { type = "list_item", text = "Unfolding Vision has been redesigned – When Power Word: Shield or Void Shield expires with absorption remaining, it jumps to a nearby injured ally instead. Can only happen once per shield.", level = 4 },
            { type = "list_item", text = "Voidweaver", level = 3 },
            { type = "list_item", text = "Void Blast damage increased by 25%.", level = 4 },
            { type = "list_item", text = "Voidwraith damage increased by 30%.", level = 4 },
            { type = "list_item", text = "Void Infusion now increases Atonement healing from Void Blast and Penance by 75% while Entropic Rift is active (was 50%).", level = 4 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "list_item", text = "Hero Talents", level = 2 },
            { type = "list_item", text = "Archon", level = 3 },
            { type = "list_item", text = "Resonant Energy has been slightly redesigned – Creating a Halo increases healing done by 2% for 10 seconds, stacking up to 4 times.", level = 4 },
            { type = "list_item", text = "Divine Hymn has been updated – Now additionally grants Guardian Spirit while channeled.", level = 2 },
            { type = "dev_note", text = "We are adding a benefit to channeling Divine Hymn to make it easier to use. If you already have Guardian Spirit active on yourself, Divine Hymn will add 5 seconds to its duration. If Divine Hymn’s channeling is ended early, it will remove whatever time is remaining from the amount that it added.", level = 3 },
            { type = "list_item", text = "Shadow", level = 1 },
            { type = "dev_note", text = "For Shadow in Curses of Ula’tek, we’re intending to improve Voidform gameplay and are adding an additional source of multi-target damage to reduce the spec’s reliance on Psychic Link in AoE situations. For Voidform, we’re updating Void Volley to be a limited use ability that can be used a set number of times during Voidform which leaves more room in the rotation while giving you the chance to use it at its most opportune moment. We’ve also updated Voidform support talents to have more noticeable effects to align with our goals.", level = 2 },
            { type = "list_item", text = "New Talent: Shadeburst – Shadowy Apparitions that float towards your primary target explode, dealing Shadow damage to all enemies within 8 yards. Damage reduced beyond 5 targets.", level = 2 },
            { type = "list_item", text = "Improved Voidform has been redesigned – Voidform increases your spell damage by an additional 5% and grants 2 additional uses of Void Volley.", level = 2 },
            { type = "list_item", text = "Ancient Madness has been redesigned – Shadow Word: Madness increases your Haste during Voidform by 2% and increases its duration by 1.5 seconds, stacking up to 5 times. When Voidform ends, the Haste lingers and decays over 10 seconds.", level = 2 },
            { type = "list_item", text = "Voidform now grants 3 uses of Void Volley instead of Void Volley having a cooldown during Voidform.", level = 2 },
            { type = "list_item", text = "Power Word: Shield absorb increased by 25%.", level = 2 },
            { type = "list_item", text = "Phantom Menace has been removed.", level = 2 },
            { type = "list_item", text = "Hero Talents", level = 2 },
            { type = "list_item", text = "Archon", level = 3 },
            { type = "list_item", text = "Focused Outburst has been redesigned – Void Volley deals 15% increased damage and Shadow Word: Madness casts during Voidform unleash a Void Volley at your target.", level = 4 },
            { type = "list_item", text = "Resonant Energy has been slightly redesigned – Creating a Halo increases your spell damage by 2% for 10 seconds, stacking up to 4 times.", level = 4 },
            { type = "list_item", text = "ROGUE", level = 0 },
            { type = "list_item", text = "Class", level = 1 },
            { type = "list_item", text = "Thistle Tea is now a choice talent – Players may now choose between the existing version, which casts automatically at low Energy in addition to being usable actively, and a new version that must be cast actively.", level = 2 },
            { type = "list_item", text = "Atrophic Poison now reduces damage dealt by 4% (was 3%).", level = 2 },
            { type = "list_item", text = "Atrophic Poison duration increased to 60 seconds (was 10 seconds). Duration remains unchanged in PvP combat.", level = 2 },
            { type = "list_item", text = "Hero Talents", level = 1 },
            { type = "list_item", text = "Fatebound", level = 2 },
            { type = "list_item", text = "Deal Fate now has a 60% chance to grant an extra combo point when you Seal Fate (was 100%).", level = 3 },
            { type = "list_item", text = "Assassination", level = 1 },
            { type = "list_item", text = "Developers’ notes We’re making some updates to Assassination’s Energy economy in Curse of Ula’tek. We aren’t happy with how the Rank 1 Implacable apex talent is playing – it’s unintuitive for optimal play to intentionally let Envenom drop. We’re updating its design so refreshing Envenom late is consistently the best way to play and giving it consistent Energy recovery value. We’re also making some changes aimed at increasing talent build options.", level = 2 },
            { type = "list_item", text = "New Talent: Unstable Toxin – Envenom damage increased by 18%, but its duration is reduced by 2 seconds.", level = 2 },
            { type = "list_item", text = "Apex Talent: Implacable (Rank 1) has been updated – Envenom damage increased by 10%. Envenom now restores 2 Energy per combo point spent.", level = 2 },
            { type = "list_item", text = "Internal Bleeding has been updated – Now triggers from casting Kidney Shot and Rupture, rather than also being applied when copying Ruptures with Crimson Tempest. Damage increased by 10%.", level = 2 },
            { type = "list_item", text = "Iron Wire has been updated – Garrotes applied from stealth or during the Improved Garrote window now silence the target for 5 seconds. Damage reduction behavior unchanged.", level = 2 },
            { type = "list_item", text = "Dashing Scoundrel has been updated – Envenom’s effect now also increases the critical strike chance of your weapon poisons by 10% (was 5%). Your Energy generation is increased by 4% for each lethal poison on your weapons.", level = 2 },
            { type = "list_item", text = "All damage dealt increased by 3%.", level = 2 },
            { type = "list_item", text = "Deathmark increases the damage of your Rupture, Garrote, and Lethal Poisons by 75% (was 100%).", level = 2 },
            { type = "list_item", text = "Kingsbane damage reduced by 15%.", level = 2 },
            { type = "list_item", text = "Shrouded Suffocation increases Garrote damage by 30% (was 20%).", level = 2 },
            { type = "list_item", text = "Avulsion increases Rupture damage by 25% (was 20%).", level = 2 },
            { type = "list_item", text = "Motivated Murderer Energy increased to 30% (was 20%).", level = 2 },
            { type = "list_item", text = "Rapid Injection damage bonus increased to 20%/40% (was 15%/30%).", level = 2 },
            { type = "list_item", text = "Venomous Wounds generates more Energy when multiple targets are affected by your bleeds.", level = 2 },
            { type = "list_item", text = "Blindside’s chance to trigger reduced to 10% (was 15%), and 20% when the target is at low health (was 30%).", level = 2 },
            { type = "list_item", text = "Poison Bomb’s visual has been adjusted to make other important visuals on top of it easier to see.", level = 2 },
            { type = "list_item", text = "Several talents have changed positions in the talent tree.", level = 2 },
            { type = "list_item", text = "Deadly Momentum has been removed.", level = 2 },
            { type = "list_item", text = "Outlaw", level = 1 },
            { type = "dev_note", text = "The changes to Outlaw in Curse of Ula’tek are intended to improve talent build diversity and flexibility. We’ve increased the power of some underperforming talents and pulled back some that could feel “locked in”. Killing Spree’s damage has been increased significantly because the damage it did wasn’t sufficiently stronger than using other abilities during its channel would have been. The talent should now increase your overall damage about as much as other comparable talents.", level = 2 },
            { type = "list_item", text = "Improved Between the Eyes has been updated – Causes Between the Eyes critical strikes to deal 2.5 times normal damage (was 3 times).", level = 2 },
            { type = "list_item", text = "Fast Action has been updated – Now reduces the cooldown of Between the Eyes by 8 seconds (was 5 seconds) and increases the damage bonus from each Between the Eyes stack by 1%.", level = 2 },
            { type = "list_item", text = "Killing Spree damage increased by 60%.", level = 2 },
            { type = "list_item", text = "Heavy Hitter increases the damage of attacks that generate combo points by 15%/30% (was 10%/20%).", level = 2 },
            { type = "list_item", text = "Zero In value per stack reduced to 2% (was 3%).", level = 2 },
            { type = "dev_note", text = "We don’t want players to feel obligated to use off-hand daggers to maximize the value of this talent. Zero In now has a 30% chance to not proc if triggered by a weapon with 1.8 Speed, giving it the same proc rate when attacking with daggers vs. other one-handed weapons.", level = 3 },
            { type = "list_item", text = "Hidden Opportunity’s chance for Ambush to grant Opportunity increased to 100% (was 80%) of the chance for Sinister Strike to grant Opportunity.", level = 2 },
            { type = "list_item", text = "New connectors have been added between Ruthlessness and Find an Opening, and between the Flickering Steel choice node and Grand Melee.", level = 2 },
            { type = "list_item", text = "Subtlety", level = 1 },
            { type = "list_item", text = "Relentless Strikes now generates 4 Energy per combo point spent on finishing moves (was 5 Energy).", level = 2 },
            { type = "list_item", text = "Shadowcraft no longer stores 1 additional combo point. Frequency bonus from auto-attacks increased to 75% (was 40%).", level = 2 },
            { type = "dev_note", text = "Energy and Combo Point generation during cooldown windows has often been overflowing. These reductions aim to reduce circumstances of over-capping resources while maintaining potent relative generation in those windows.", level = 3 },
            { type = "list_item", text = "Lingering Shadow now also applies to Shuriken Storm.", level = 2 },
            { type = "list_item", text = "Shadow Dance’s tooltip has been updated to include its threat reduction effect.", level = 2 },
            { type = "list_item", text = "Apex Talent: Ancient Arts now considers the total damage of Secret Technique when creating a shadow clone, instead of only its initial hit.", level = 2 },
            { type = "list_item", text = "Fixed an issue that caused Secret Technique damage from secondary hits to be attributed to summoned pets instead of the attacking Rogue.", level = 2 },
            { type = "list_item", text = "SHAMAN", level = 0 },
            { type = "list_item", text = "Ascendance has a new icon for all three specializations.", level = 1 },
            { type = "list_item", text = "Hero Talents", level = 1 },
            { type = "list_item", text = "Farseer", level = 2 },
            { type = "dev_note", text = "In a previous tuning hotfix for Elemental Shaman, Farseer Spirits received a small change so they scale with the Elemental Fury talent. We are changing several other places where they weren’t scaling the same as the Shaman’s abilities.", level = 3 },
            { type = "list_item", text = "Chain Lightning now hits up to 5 targets (was 3).", level = 3 },
            { type = "list_item", text = "Lava Burst now also increases damage by a percent equal to your critical strike chance.", level = 3 },
            { type = "list_item", text = "Elemental", level = 1 },
            { type = "dev_note", text = "Elemental Shaman have higher burst during their Ascendance window with the changes in Midnight than we would like. We don’t want Ascendance to stop being a noticeable damage amplifier, but the combination of effects that boosted your Elemental Overload damage from both Ascendance and Apex talents all compounded with each other. We’re spreading a lot more damage into your spells to deal consistently higher damage while still getting a nice spike during Ascendance.", level = 2 },
            { type = "list_item", text = "Power of the Maelstrom has been redesigned – Lightning Bolt and Chain Lightning have a 15% chance to cause your next Lava Burst to deal 20% increased damage, stacking up to 2 times. Lava Burst consumes one stack at a time.", level = 2 },
            { type = "list_item", text = "Developes’ notes: Supercharge and Power of the Maelstrom both were extra, random Elemental Overloads. We feel that the other changes will make your damage more consistent, while still allowing other parts of your talent tree to still increase the quantity or power of Elemental Overload spells.", level = 3 },
            { type = "list_item", text = "Stormkeeper has been redesigned – Your next 2 Lightning Bolts become instant cast and deal 150% increased damage, or your next 2 Chain Lightnings become instant and cause an Elemental Overload on all targets hit.", level = 2 },
            { type = "list_item", text = "Lava Burst damage increased by 30%. This does not apply to PvP combat.", level = 2 },
            { type = "list_item", text = "Lightning Bolt damage increased by 30%. This does not apply to PvP combat.", level = 2 },
            { type = "list_item", text = "Chain Lightning damage increased by 60%.", level = 2 },
            { type = "list_item", text = "Flame Shock damage increased by 60%.", level = 2 },
            { type = "list_item", text = "Tempest direct damage reduced by 20%.", level = 2 },
            { type = "list_item", text = "Healing Surge healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Earth Shield healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Healing Stream Totem healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Ascendance now increases the damage of Elemental Overload by 30% (was 75%).", level = 2 },
            { type = "list_item", text = "Bonus Lava Bursts when activating Ascendance are now 50% of their normal value (was 100%).", level = 2 },
            { type = "list_item", text = "Molten Wrath now increases the damage of Lava Burst by 10% (was 15%).", level = 2 },
            { type = "list_item", text = "Apex Talent: Feedback Loop (Rank 1) now increases Elemental Overload damage by 10% (was 35%) and also increases Elemental damage done by 10%.", level = 2 },
            { type = "list_item", text = "Apex Talent: Feedback Loop (Rank 2) now grants 15%/30% critical damage bonus (was 25%/50%).", level = 2 },
            { type = "list_item", text = "Elemental Blast casts from Fusion of the Elements now only grant 40% of the normal duration of the Elemental Blast stat buffs (was 100%).", level = 2 },
            { type = "list_item", text = "Fixed an issue that caused Voltaic Blaze to not be properly affected by Elemental Fury’s critical damage bonus.", level = 2 },
            { type = "list_item", text = "Fixed an issue that caused Elemental Resonance to not affect periodic Elemental damage.", level = 2 },
            { type = "list_item", text = "Fixed an issue where Apex Talent: Feedback Loop (Rank 2) did not properly increase the critical damage of several Elemental Shaman spells.", level = 2 },
            { type = "list_item", text = "Hero Talents", level = 2 },
            { type = "list_item", text = "Stormbringer", level = 3 },
            { type = "list_item", text = "Supercharge has been redesigned – Lightning Bolt, Chain Lightning, and Tempest overloads deal 10% additional damage.", level = 4 },
            { type = "list_item", text = "Enhancement", level = 1 },
            { type = "list_item", text = "Healing Surge healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Earth Shield healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Healing Stream Totem healing increased by 25%.", level = 2 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "list_item", text = "Healing Rain now has a 12 second cooldown and an 18 second duration. Recasting Healing Rain while one is already active will despawn the previous one. This cooldown change does not affect the Surging Totem’s Healing Rain from the Totemic Hero Talents.", level = 2 },
            { type = "dev_note", text = "This change should allow more flexibility for the player to move Healing Rain around when that is desirable.", level = 3 },
            { type = "list_item", text = "WARLOCK", level = 0 },
            { type = "list_item", text = "Summon Demonic Gateway is now a Utility spell by default in the Cooldown Manager.", level = 1 },
            { type = "list_item", text = "Hero Talents", level = 1 },
            { type = "list_item", text = "Hellcaller", level = 2 },
            { type = "dev_note", text = "We’re updating Blackened Soul to give Hellcaller a better tool for focusing damage into a priority target, increasing the overall flexibility of the hero talent tree rather than have it only excel in situations where multiple targets are present. However, we are keeping the functionality of Malevolence the same, so it remains a cool and impactful tool in Hellcaller’s toolkit.", level = 3 },
            { type = "list_item", text = "Blackened Soul has been redesigned – If the target is afflicted with your Wither, your Chaos Bolt and Shadowburn increase its stack count by 1. Each time Wither gains a stack it has a chance to collapse, consuming a stack every 1 second to deal Shadowflame damage to its host until 1 stack remains.", level = 3 },
            { type = "list_item", text = "Mark of Peroth’arn has been redesigned – Damaging critical strikes dealt by Wither deal 215% damage instead of the usual 200%. Damaging critical strikes dealt by Blackened Soul deal 225% damage instead of the usual 200%.", level = 3 },
            { type = "list_item", text = "Destruction", level = 1 },
            { type = "list_item", text = "Conflagration of Chaos has been redesigned – Conflagrate and Shadowburn have a 100% chance to critically strike, and their damage is increased by your critical strike chance.", level = 2 },
            { type = "list_item", text = "Conflagration of Chaos has been removed from the Cooldown Manager.", level = 2 },
            { type = "list_item", text = "Apex Talent: Embers of Nihilam (Rank 1) tooltip has been updated to show players the percent chance of Incinerate evoking an Echo of Sargeras.", level = 2 },
            { type = "list_item", text = "WARRIOR", level = 0 },
            { type = "dev_note", text = "Rend is an iconic and core Warrior ability with a different relationship to each spec. Our approach to Rend in Midnight hasn’t worked out as we hoped, so we’re making changes to how each spec applies and interacts with Rend in Curse of Ula’tek.", level = 1 },
            { type = "list_item", text = "The Rend ability is now exclusive to Arms, has returned to being a single-target ability, and its Rage cost is reduced to 10. Cleave will apply Rend to all targets if the Warrior knows Rend.", level = 1 },
            { type = "list_item", text = "New Talent (Fury): Storm of Blood – Whirlwind applies Rend to all targets. Crashing Thunder causes Storm of Blood to also apply to Thunder Clap for Mountain Thane.", level = 1 },
            { type = "list_item", text = "New Talent (Protection): Blood and Thunder – Thunder Clap applies Rend to all targets.", level = 1 },
            { type = "list_item", text = "Thunder Clap no longer innately applies Rend if known.", level = 1 },
            { type = "list_item", text = "Javelineer has a new icon.", level = 1 },
            { type = "list_item", text = "Arms", level = 1 },
            { type = "list_item", text = "Ravager has been updated:", level = 2 },
            { type = "dev_note", text = "Ravager is a unique ability and we want Ravager itself and its positioning to be important, but the current design puts more emphasis on its value as an AOE damage amp rather than Ravager itself. We’re redesigning Ravager slightly to address this, as well as to increase Ravager’s value in all combat situations.", level = 3 },
            { type = "list_item", text = "Ravager damage increased by 50%.", level = 3 },
            { type = "list_item", text = "Ravager no longer increases Cleave and Whirlwind damage while active. Ravager now causes all enemies it damages to take 25% increased damage from your Bleeds for 12 seconds.", level = 3 },
            { type = "list_item", text = "Ravager’s duration is no longer reduced by Haste.", level = 3 },
            { type = "list_item", text = "Bloodletting has been updated – Your abilities have a 5% increased chance to critically strike targets affected by Rend. If you know Rend, Mortal Strike inflicts Rend on targets below 35% health. Deep Wounds lasts 33% longer.", level = 2 },
            { type = "list_item", text = "Broad Strokes has been updated – Colossus Smash now grants 6 stacks of Sweeping Strikes on use.", level = 2 },
            { type = "list_item", text = "Stacks of Sweeping Strikes from the Sweeping Strikes ability and Broad Strokes will stack normally, regardless of the order in which they were used.", level = 3 },
            { type = "list_item", text = "Sweeping Strikes now displays the number of active Sweeping Strikes charges.", level = 2 },
            { type = "list_item", text = "Improved Sweeping Strikes has been removed.", level = 2 },
            { type = "list_item", text = "Mass Execution and Overpowering Finish are now on a choice node with each other.", level = 2 },
            { type = "list_item", text = "Battlelord and Master Tactician have swapped positions in the tree.", level = 2 },
            { type = "list_item", text = "Hero Talents", level = 2 },
            { type = "list_item", text = "Colossus", level = 3 },
            { type = "dev_note", text = "Demolish’s variable cooldown has proven to be more frustrating than interesting, so we’re changing it to align closely with Colossus Smash, enabling Arms Colossus Warriors to coordinate their use for maximum devastation.", level = 4 },
            { type = "list_item", text = "Tide of Battle increases the damage of Overpower and Execute (was Overpower only).", level = 4 },
            { type = "list_item", text = "Demolish’s cooldown reduced to 30 seconds (was 45 seconds).", level = 4 },
            { type = "list_item", text = "Dominance of the Colossus no longer reduces the cooldown of Demolish.", level = 4 },
            { type = "list_item", text = "Fury", level = 1 },
            { type = "list_item", text = "Whirlwind has been updated:", level = 2 },
            { type = "dev_note", text = "Whirlwind has historically been a core part of Fury gameplay, even in single-target situations. We’d like to open the door for Whirlwind to be a useful ability in single target again.", level = 3 },
            { type = "list_item", text = "Whirlwind now generates 3 Rage innately.", level = 3 },
            { type = "list_item", text = "Improved Whirlwind has been updated – No longer causes Whirlwind to generate 3 Rage innately, but still increases Rage generated by Whirlwind by 1 per target hit, up to 8 total Rage.", level = 3 },
            { type = "list_item", text = "New Talent: Carving Blades – Whirlwind deals 50% additional damage when it strikes only a single target. Talent is on a choice node with Meat Cleaver.", level = 3 },
            { type = "list_item", text = "Rampaging Ruin has been redesigned – While Improved Whirlwind is active, Rampage’s final strike slams the ground, dealing Physical damage to all enemies within 8 yards of your target. Damage reduced beyond 5 targets.", level = 2 },
            { type = "dev_note", text = "Rampaging Ruin is intended to help alleviate the AOE target cap on Fury’s rotational AOE abilities. The current design ended up being very difficult to figure out when it was best to use Rampaging Ruin, the new design should make the choice much more intuitive.", level = 3 },
            { type = "list_item", text = "Hack and Slash has been updated – Rampage now has a 75% chance to refund a charge of Raging Blow and increase the damage of your next Raging Blow by 20%.", level = 2 },
            { type = "list_item", text = "Developer’s notes: We feel that Fury plays best when there is a degree of uncertainty about which ability you’ll use after the one you’re currently pressing. Previous iterations of Hack and Slash provided extremely regular and consistent Raging Blow resets, causing Raging Blow to almost always be available. We believe this change will help keep Fury rotations variable and allow for more difference in rotational feel between builds that emphasize Raging Blow and those that do not.", level = 3 },
            { type = "list_item", text = "Hero Talents", level = 2 },
            { type = "list_item", text = "Mountain Thane", level = 3 },
            { type = "dev_note", text = "Thunder Clap’s base damage increased significantly in Midnight, causing overall Thunder Clap damage to rise significantly for Mountain Thane, which in turn devalued Thunder Blast. We’re moving the Crashing Thunder damage bonus into Thunder Blast itself to keep Thunder Blast feeling special and powerful.", level = 4 },
            { type = "list_item", text = "Thunder Blast damage increased by 40%.", level = 4 },
            { type = "list_item", text = "Crashing Thunder increases Thunder Clap damage by 10% (was 30%).", level = 4 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "list_item", text = "Devastating Focus has been updated – Now increases Revenge and Execute damage dealt to the target (was Revenge only).", level = 2 },
            { type = "list_item", text = "Bloodborne has been updated – Now increases all Bleed damage (was only Rend and Deep Wounds).", level = 2 },
            { type = "list_item", text = "Fueled by Violence heals you for 125% of Bleed damage dealt (was 110%).", level = 2 },
            { type = "list_item", text = "Ignore Pain absorb amount increased by 25%.", level = 2 },
            { type = "list_item", text = "Brutal Vitality adds 10% of damage dealt to Ignore Pain (was 8%).", level = 2 },
            { type = "list_item", text = "Ravager has been updated:", level = 2 },
            { type = "dev_note", text = "Ravager is a unique ability and we want the Ravager itself and its positioning to be important, but the current design puts more emphasis on its value as an AOE damage amp rather than the Ravager itself. We’re redesigning Ravager slightly to address this, as well as to increase Ravager’s value in all combat situations.", level = 3 },
            { type = "list_item", text = "Ravager damage increased by 50%.", level = 3 },
            { type = "list_item", text = "Ravager no longer increases Revenge and Thunder Clap damage while active. Ravager now causes all enemies it damages to take 25% increased damage from your Bleeds for 12 seconds. Duration reduced to 4 seconds with Whirling Blade.", level = 3 },
            { type = "list_item", text = "Ravager’s duration is no longer reduced by Haste.", level = 3 },
            { type = "list_item", text = "Hero Talents", level = 2 },
            { type = "list_item", text = "Colossus", level = 3 },
            { type = "dev_note", text = "Demolish’s variable cooldown is difficult to integrate smoothly into Protection’s rotation, so we’re changing the cooldown to be consistent so Demolish can be available more reliably for burst damage or additional damage mitigation.", level = 4 },
            { type = "list_item", text = "Demolish cooldown reduced to 30 seconds (was 45 seconds).", level = 4 },
            { type = "list_item", text = "Dominance of the Colossus no longer reduces the cooldown of Demolish.", level = 4 },
            { type = "list_item", text = "Tide of Battle increases the damage of Revenge and Execute (was Revenge only).", level = 4 },
            { type = "list_item", text = "Mountain Thane", level = 3 },
            { type = "dev_note", text = "Thunder Clap’s base damage increased significantly in Midnight, causing overall Thunder Clap damage to rise significantly for Mountain Thane, which in turn devalued Thunder Blast. We’re moving the Crashing Thunder damage bonus into Thunder Blast itself to keep Thunder Blast feeling special and powerful.", level = 4 },
            { type = "list_item", text = "Thunder Blast damage increased by 40%.", level = 4 },
            { type = "list_item", text = "Crashing Thunder increases Thunder Clap damage by 10% (was 30%).", level = 4 },
            { type = "h2", text = "CLASS SETS" },
            { type = "p", text = "Post any feedback on class sets in the thread: Feedback: Midnight Season 2 Class Sets." },
            { type = "list_item", text = "DEATH KNIGHT", level = 0 },
            { type = "list_item", text = "Blood", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Your attack speed is increased by 15%, and Crimson Scourge’s chance to occur is increased by an additional 5%.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Crimson Scourge increases the damage of your next Death and Decay by 100%, and grants 5% critical strike chance for 8 seconds when consumed.", level = 2 },
            { type = "list_item", text = "Frost", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Each time Remorseless Winter damages at least 1 enemy, gain Freezing Tempest which grants 2% attack speed and 4% increased Icy Death Torrent damage for 5 sec, stacking.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Remorseless Winter deals damage 25% more frequently, and Freezing Tempest lasts 5 seconds longer.", level = 2 },
            { type = "list_item", text = "Unholy", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Your Magus of the Dead and Lord of the Dead cast a more powerful Necrotic Bolt instead of Frostbolt, and Withering Grasp instead of Shadow Bolt.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Necrotic Bolt’s damage is increased by 130%, and Withering Grasp’s damage is increased by 130%, against enemies below 35% health.", level = 2 },
            { type = "list_item", text = "DEMON HUNTER", level = 0 },
            { type = "list_item", text = "Devourer", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Harvesting 4 or more Soul Fragments with Reap has a 20% chance to cause your next Consume to be instant cast and explode in a Soulburst, dealing Cosmic damage to nearby enemies.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Soulburst generates 8 Soul Fragments and grants Moment of Craving. Reap deals 20% increased damage.", level = 2 },
            { type = "list_item", text = "Havoc", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Blade Dance, Chaos Strike, and Essence Break deal 12% increased damage.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Essence Break now applies and benefits from the effects of Cycle of Hatred, has 25% increased initial strike damage, and has 2 seconds of increased duration.", level = 2 },
            { type = "list_item", text = "Vengeance", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Sigil of Flame’s damage over time is increased by 50%. Soul Cleave increases the duration of Sigil of Flame on your primary target by 2 seconds.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Immolation Aura and Sigil of Spite deal 100% increased damage against targets affected by your Sigil of Flame.", level = 2 },
            { type = "list_item", text = "DRUID", level = 0 },
            { type = "list_item", text = "Balance", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Starsurge damage increased by 20%. Starfall also deals Astral damage instantly to all valid enemies in range when cast.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Your damage is increased by 10% while in any Eclipse. This bonus wanes to 2% at the midpoint of the Eclipse, then waxes back to 10% at the end.", level = 2 },
            { type = "list_item", text = "Feral", level = 1 },
            { type = "list_item", text = "2-Set Bonus: When Berserk or Incarnation ends, you deal 10% increased damage for 1 second for each combo point spent during Berserk or Incarnation.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Berserk and Incarnation last 10 seconds longer.", level = 2 },
            { type = "list_item", text = "Guardian", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Thrash has a 20% chance to make your next Mangle deal 100% increased damage.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Thrash calls up 3 thorns, each impaling a target for Nature damage and dealing additional Nature damage to up to 5 nearby enemies, and extends the duration of Berserk by 0.5 seconds, up to 5 seconds.", level = 2 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Rejuvenation has a 15% chance and Nature’s Swiftness has a 100% chance to grant Genesis, causing all your heal over time effects to heal for 25% more for 8 seconds. Multiple applications may overlap.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Genesis duration is increased by 4 seconds, and gaining Genesis grants Clearcasting.", level = 2 },
            { type = "list_item", text = "EVOKER", level = 0 },
            { type = "list_item", text = "Augmentation", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Upheaval’s cooldown is reduced by 10 seconds.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Upheaval magnifies your Fate Mirror effects for 8 seconds, increasing the amount of damage echoed to 45%.", level = 2 },
            { type = "list_item", text = "Devastation", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Shattering Star’s damage is increased by 150%, and it always casts as if you had reached maximum empower level.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Causality reduces the remaining cooldown of your empower spells by an additional 0.1 seconds each time the effect occurs. Eternity Surge deals 10% increased damage.", level = 2 },
            { type = "list_item", text = "Preservation", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Consuming Essence Burst sends forth a Living Flame at your target at 150% effectiveness, or at a nearby injured target if your primary target is at full health.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Green spells restore 5% more health, and Verdant Embrace has a 100% chance to grant Essence Burst.", level = 2 },
            { type = "list_item", text = "HUNTER", level = 0 },
            { type = "list_item", text = "Beast Mastery", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Barbed Shot causes your pets to stomp 1 additional time at 50% effectiveness.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Stomp causes your next Cobra Shot to either benefit from Beast Cleave at 20% effectiveness, or strike your primary target for 30% additional damage, stacking up to 4 times.", level = 2 },
            { type = "list_item", text = "Marksmanship", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Explosive Shot lasts 1 second longer and deals 20% increased damage.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Aimed Shot and Rapid Fire damage increased by 5%. Each time Explosive Shot causes a burst of damage, the cooldown of Aimed Shot and Rapid Fire is reduced by 0.5 seconds.", level = 2 },
            { type = "list_item", text = "Survival", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Raptor Strike damage increased by 15%.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Mongoose Fury also increases the damage of Wildfire Bomb by 10%.", level = 2 },
            { type = "list_item", text = "MAGE", level = 0 },
            { type = "list_item", text = "Arcane", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Arcane Missiles fires 1 additional missile and deals 20% increased damage.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Each wave of Arcane Missiles increases the damage of your next Arcane Blast, Arcane Pulse, or Prismatic Bolt by 5%, up to 40%.", level = 2 },
            { type = "list_item", text = "Fire", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Pyroclasm causes Flamestrike and Pyroblast to always critically strike.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Pyroclasm reduces the cast time of Flamestrike and Pyroblast by 20% and its damage bonus is increased by 20%.", level = 2 },
            { type = "list_item", text = "Frost", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Each stack of Freezing Shattered has a 5% chance to generate an Icicle. Glacial Spike damage increased by 25%.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Consuming Glacial Spike has a small chance to grant Glacial Spike. Shatter damage increased by 15%.", level = 2 },
            { type = "list_item", text = "MONK", level = 0 },
            { type = "list_item", text = "Brewmaster", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Breath of Fire ignites your next Keg Smash, causing it to explode on contact, dealing additional Flamestrike damage to its primary target and reduced damage to additional targets.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Ignited Keg Smashes cause enemies struck to take 8% increased damage from your Physical abilities, and leave a patch of flames on the ground, dealing Fire damage each second for 5 seconds.", level = 2 },
            { type = "list_item", text = "Mistweaver", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Rising Sun Kick deals 30% increased damage and Rushing Wind Kick’s healing is increased by 100%.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Rising Sun Kick and Rushing Wind Kick have a chance to cause their next cast to ignore their cooldown and have their mana cost reduced by 100%.", level = 2 },
            { type = "list_item", text = "Windwalker", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Fists of Fury strikes an additional time at the start of its channel at 50% effectiveness.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Fists of Fury increases the damage of your next Rising Sun Kick by 10% or Spinning Crane Kick by 20% each time it strikes, stacking up to 6 times.", level = 2 },
            { type = "list_item", text = "PALADIN", level = 0 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Infusion of Light increases the healing of Flash of Light by an additional 75% and the absorb from Greater Judgment by an additional 75%.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Judgment now has a 20% chance to grant Infusion of Light. Holy Light now has a 50% chance to grant Infusion of Light.", level = 2 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Consecration is 30% larger and enemies within your Consecration are illuminated, increasing the chance for your abilities to critically strike them by 5%.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Enemies struck by Judgment or Crusader Strike take 20% additional Holy damage. If they are struck by a critical strike, the additional damage is increased by 200%.", level = 2 },
            { type = "list_item", text = "Retribution", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Divine Purpose has an additional 10% chance to activate and consuming it grants Divine Power, increasing Holy damage done by 10% for 12 seconds.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Consuming Divine Purpose with Divine Storm causes your next Final Verdict to be free and unleash Divine Arbiter at its target, dealing Holy damage and Holy damage to enemies within 8 yards.", level = 2 },
            { type = "list_item", text = "PRIEST", level = 0 },
            { type = "list_item", text = "Discipline", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Penance damage and healing increased by 20%. Casting Penance reduces the cooldown of Mind Blast by 2 seconds.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: After casting Mind Blast, your next Power Word: Shield or Void Shield absorbs 25% more damage.", level = 2 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Each target affected by your Renew increases your Haste by 2%, up to 6%.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Renew healing increased by 10%. Light’s Resurgence now has a 100% chance to leave a Renew on the first target Prayer of Mending heals.", level = 2 },
            { type = "list_item", text = "Shadow", level = 1 },
            { type = "dev_note", text = "The Shadow Priest set will be available PTR week 2.", level = 2 },
            { type = "list_item", text = "2-Set Bonus: Tentacle Slam’s cooldown is reduced by 3 seconds and its damage is increased by 100%.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: After casting Tentacle Slam, your next Vampiric Touch is instant, generates 4 additional Insanity, and conjures Shadowy Apparitions that deal 200% of normal damage.", level = 2 },
            { type = "list_item", text = "ROGUE", level = 0 },
            { type = "list_item", text = "Assassination", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Envenom damage increased by 10% and it increases your damage dealt by 3%.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Deadly Poison increases your bleed damage on the target by 10%. Auto-attacks against targets with your Amplifying Poison deal 2% increased damage per stack. Wound Poison hits a second time.", level = 2 },
            { type = "list_item", text = "Outlaw", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Dispatch damage increased by 15%.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Sinister Strike and Ambush have a 12% chance to cause your next Dispatch to be free and deal damage as if you spent the maximum combo points.", level = 2 },
            { type = "list_item", text = "Subtlety", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Backstab costs 10 less Energy and deals 100% increased damage. Shuriken Storm costs 5 less Energy and deals 60% increased damage.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Lingering Shadow now also benefits Eviscerate and Black Powder at 100% effectiveness.", level = 2 },
            { type = "list_item", text = "SHAMAN", level = 0 },
            { type = "list_item", text = "Elemental", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Earth Shock, Elemental Blast, and Earthquake damage increased by 25%.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: When Stormkeeper or Ascendance fade, your next 2 Lightning Bolts, Chain Lightnings, or Lava Bursts deal 25% increased damage and cause your next Earthquake, Earth Shock, or Elemental Blast to cost 100% less Maelstrom.", level = 2 },
            { type = "list_item", text = "Enhancement", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Voltaic Blaze causes your primary target to erupt in a Fire Nova every 2 seconds for 6 seconds. Fire Nova damage is increased by 200% if it only strikes a single target.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Fire Nova reduces the cooldown of Crash Lightning by 2 seconds and increases the damage of your next Crash Lightning by 8%, stacking up to 5 times.", level = 2 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Healing Wave and Chain Heal have a chance to create a Healing Rain at the target’s location for 10 seconds.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Every 1 second, 1 ally inside of Healing Rain gains a watery shield that absorbs X damage for 10 seconds.", level = 2 },
            { type = "list_item", text = "WARLOCK", level = 0 },
            { type = "list_item", text = "Affliction", level = 1 },
            { type = "list_item", text = "2-Set Bonus: You have a 20% chance to refund a Soul Shard after spending a Soul Shard.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Each active Unstable Affliction increases your damage dealt by your spells and abilities by 2%, up to 6%. Seed of Corruption applies Unstable Affliction at 50% effectiveness to your target.", level = 2 },
            { type = "list_item", text = "Demonology", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Wild Imp damage increased by 10%. Implosion damage increased by 20%.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: When their energy depletes, Wild Imps have a 20% chance to fling themselves at their target and Implode at 150% effectiveness to their main target and 125% effectiveness to other targets.", level = 2 },
            { type = "list_item", text = "Destruction", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Incinerate damage increased by 25% and Incinerate has a 10% increased chance to evoke an Echo of Sargeras.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Targets damaged by Echo of Sargeras take 6% increased damage from Echo of Sargeras for 6 seconds.", level = 2 },
            { type = "list_item", text = "WARRIOR", level = 0 },
            { type = "list_item", text = "Arms", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Mortal Strike damage increased by 10% and when you Slam a target, Slam also deals damage to enemies within 8 yards of it. Deals reduced damage beyond 5 targets.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Overpower damage increased by 15%. Mortal Strike and Overpower increase the damage of your next Slam by 10%, stacking up to 3 times.", level = 2 },
            { type = "list_item", text = "Fury", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Raging Blow damage increased by 15% and during Recklessness, Raging Blow extends the Duration of Recklessness by 2 seconds, up to 6 seconds.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Bloodthirst damage increased by 10% and during Recklessness, Bloodthirst increases the critical strike bonus of Recklessness by 5%, up to 10%.", level = 2 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "list_item", text = "2-Set Bonus: Free revenges deal 15% additional damage and cause your next Shield Slam to deal 20% additional damage.", level = 2 },
            { type = "list_item", text = "4-Set Bonus: Ravager and your free Revenges cause all targets to bleed for X damage over 12 sec. Ravager’s cooldown is reduced by 30 seconds.", level = 2 },
            { type = "h2", text = "ITEMS" },
            { type = "dev_note", text = "With the Curse of Ula’tek content update on the horizon, we wanted to share a few thoughts on endgame rewards and additional context on some upcoming changes. Learn more in our forum thread: Curse of Ula’tek Endgame Reward Changes", level = 0 },
            { type = "list_item", text = "RAID REWARDS", level = 0 },
            { type = "list_item", text = "LFR, Normal, and Heroic raid Great Vault rewards are now awarded at the first step of the next harder difficulty’s upgrade track; for example, all Heroic raid vault rewards will be Myth 1/6.", level = 1 },
            { type = "list_item", text = "Mythic raid Great Vault rewards are now awarded at Myth 6/6 apart from Very Rare items and loot from the penultimate and final bosses.", level = 1 },
            { type = "list_item", text = "Mythic raid Very Rare items and loot from the penultimate and final bosses will be acquired at the equivalent of Myth 9 regardless of whether acquired directly from a boss drop or the Great Vault.", level = 1 },
            { type = "list_item", text = "NEBULOUS VOIDCORES", level = 0 },
            { type = "list_item", text = "Nebulous Voidcores acquired in Season 1 will be converted to gold upon the end of Season 1, and they may no longer be used in Season 1 content.", level = 1 },
            { type = "list_item", text = "Nebulous Voidcores will be available as a Great Vault reward from the start of Season 2.", level = 1 },
            { type = "list_item", text = "Orin Straylight has begun learning the basics of weaving Nebulous Voidcores from void energy and has relocated to near the Catalyst in Silvermoon. He will be able to provide one additional Nebulous Voidcore per week starting in the eighth week of Season 2.", level = 1 },
            { type = "list_item", text = "The cost to roll for a raid item is reduced from two Nebulous Voidcores to one.", level = 1 },
            { type = "list_item", text = "As in Season 1, items acquired using Nebulous Voidcores will continue to be equivalent to a Great Vault reward in terms of item level.", level = 1 },
            { type = "list_item", text = "THE CATALYST", level = 0 },
            { type = "list_item", text = "Class set armor now inherits the secondary and tertiary stats as well as certain special cantrip effects of items converted with the Catalyst.", level = 1 },
            { type = "list_item", text = "Midnight Season 1 Mythic+ 1% Umbral Champion achievement mount: Umbral Ashes", level = 0 },
            { type = "h2", text = "PLAYER VERSUS PLAYER" },
            { type = "list_item", text = "ARENA TRAINING GROUNDS", level = 0 },
            { type = "list_item", text = "Training Grounds has now been expanded to include combat against computer controlled players in Arenas. Use the Training Grounds section of the Player vs. Player tab in the Group Finder to queue for ‘Random Arenas’ with up to 2 other players for the activity.", level = 1 },
            { type = "dev_note", text = "In Curse of Ula’tek, we’ve decided to reduce the effectiveness of a large number of movement speed reductions in PvP. We have found in the past that when players have access to strong snares with a high uptime, there are less opportunities for enemies to use positioning and escape tactics. Our primary target has been strong snares that are auto applied during normal combat rotations, with some of the activated reductions retaining their strength. In general we’ve reduced movement speed reductions ‘a tier’ down, with 70% reduced to 50%, 50% to 30%, and so on.", level = 0 },
            { type = "list_item", text = "DEATH KNIGHT", level = 0 },
            { type = "list_item", text = "Chains of Ice movement slow reduced to 50% (was 70%) in PvP combat.", level = 1 },
            { type = "list_item", text = "Enfeeble movement slow reduced to 20% (was 30%) in PvP combat.", level = 1 },
            { type = "list_item", text = "Grip of the Dead movement slow reduced to 60% (was 90%) in PvP combat.", level = 1 },
            { type = "list_item", text = "Hero Talents", level = 1 },
            { type = "list_item", text = "Rider of the Apocalypse", level = 2 },
            { type = "list_item", text = "Chains of Ice movement slow reduced to 20% (was 40%) in PvP combat.", level = 3 },
            { type = "list_item", text = "Trollbane’s Icy Fury movement slow reduced to 20% (was 40%) in PvP combat.", level = 3 },
            { type = "list_item", text = "Frost", level = 1 },
            { type = "list_item", text = "Blinding Sleet movement slow reduced to 50% (was 60%) in PvP combat.", level = 2 },
            { type = "list_item", text = "Blinding Sleet secondary slow reduced to 30% (was 50%) in PvP combat.", level = 2 },
            { type = "list_item", text = "Unholy", level = 1 },
