            { type = "list_item", text = "Thorns movement slow reduced to 30% (was 50%) in PvP combat.", level = 1 },
            { type = "list_item", text = "Balance", level = 1 },
            { type = "dev_note", text = "We are adding a new dispel protection passive for Balance Druids so they don’t need to commit a PvP talent to protecting their Moonfire and Sunfire. This is similar to what has been done for other specializations like Elemental Shaman, and should increase their viability in arenas and battlegrounds.", level = 2 },
            { type = "list_item", text = "New baseline passive, learned at level 42: Stellar Protection - If Moonfire and Sunfire are dispelled, Stellar Flare is applied to the target. Burns the target for 36% Spell Power Astral damage, and then an additional 210% Spell Power damage over 24 seconds. If dispelled, causes 212% Spell Power damage to the dispeller and blasts them upwards. Generates 12 Astral Power.", level = 2 },
            { type = "list_item", text = "Fungal Growth movement slow reduced to 30% (was 50%) in PvP combat.", level = 2 },
            { type = "list_item", text = "Faerie Swarm movement slow reduced to 20% (was 30%) in PvP combat.", level = 2 },
            { type = "list_item", text = "The following PvP talents have been removed:", level = 2 },
            { type = "list_item", text = "Crescent Burn", level = 3 },
            { type = "list_item", text = "Dying Stars", level = 3 },
            { type = "list_item", text = "Guardian", level = 1 },
            { type = "list_item", text = "Infected Wounds movement slow reduced to 30% (was 50%) in PvP combat.", level = 2 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "list_item", text = "Ancient of (Lore PvP Talent) has returned – Shapeshift into an Ancient of Lore, preventing all crowd control effects, reducing damage taken by 20%, and granting you access to Blossom Burst and Mass Blooming. Reduces movement speed.", level = 2 },
            { type = "list_item", text = "Blossoming Burst: Heals an ally for (910% of Spell power) and applies 1 missing heal over time effect. If all of them are present, Blossom Burst critically heals.", level = 3 },
            { type = "list_item", text = "Mass Blooming: Heals 5 allies for (585% of Spell power) and applies 1 missing heal over time effect.", level = 3 },
            { type = "list_item", text = "EVOKER", level = 0 },
            { type = "dev_note", text = "Unburdened Flight was frustrating for other players to deal with, particularly on capture the flag battlegrounds. With this new design, slowing an Evoker with Hover active will still have the effect of canceling out the Evoker’s speed bonuses. The goal is to balance Evoker’s kiting capabilities while still keeping them mobile and slippery.", level = 1 },
            { type = "list_item", text = "Unburdened Flight now causes Hover to prevent movement speed from being reduced below 100%, rather than granting immunity to movement-impairing effects.", level = 1 },
            { type = "list_item", text = "Permeating Chill movement slow reduced to 30% (was 50%) in PvP combat.", level = 1 },
