            { type = "h2", text = "QUESTS" },
            { type = "list_item", text = "New Arcantina quests.", level = 0 },
            { type = "dev_note", text = "The new quests will be available for testing in a later PTR build.", level = 1 },
            { type = "h2", text = "USER INTERFACE AND ACCESSIBILITY" },
            { type = "list_item", text = "COOLDOWN MANAGER", level = 0 },
            { type = "list_item", text = "Now tracks trinkets and potions.", level = 1 },
            { type = "list_item", text = "Buff and debuff icons displayed on raid and party frames can now have independent sizes and border scales.", level = 1 },
            { type = "list_item", text = "Healers can now assign visual alerts to specific group buff spells through the Group Buff Filter UI.", level = 1 },
            { type = "list_item", text = "Added a new category of “Short” sounds to use for Cooldown Manager.", level = 1 },
            { type = "list_item", text = "Sounds from the Cooldown Manager are now available to be used for the Combat Audio Assist accessibility feature.", level = 1 },
            { type = "list_item", text = "PING SYSTEM", level = 0 },
            { type = "list_item", text = "You can now ping the action bar and spells on the Cooldown Manager.", level = 1 },
            { type = "list_item", text = "You can now ping certain items.", level = 1 },
            { type = "list_item", text = "You can now ping your player resources (such as health bars) to communicate that info as a chat bubble.", level = 1 },
            { type = "list_item", text = "Ping icons will now show on certain unit frames (target, focus, and raid) when that unit is pinged.", level = 1 },
            { type = "list_item", text = "Ping System now has a new option to target the environment only, units only, or both.", level = 1 },
            { type = "list_item", text = "Updated ping macros to support pinging spells or items. Added the following slash commands: /pingspell:1234 (or spell name) and /pingitem:1234 (or item name)", level = 1 },
            { type = "list_item", text = "Adding the ability to use the [@cursor] target for ping macros. Using this will have the ping ignore all UI and units, and explicitly attempt to ping the environment wherever the cursor currently is.", level = 1 },
            { type = "list_item", text = "NAMEPLATES", level = 0 },
            { type = "list_item", text = "New options added in Friendly Nameplates settings to show only the name, use class color for names, and hide realm name.", level = 1 },
            { type = "list_item", text = "For the “Enemy Player Buffs/Debuffs” nameplates option, “Big Debuff” is now enabled by default.", level = 1 },
            { type = "list_item", text = "EDIT MODE", level = 0 },
            { type = "list_item", text = "Raid Warnings can now be moved.", level = 1 },
            { type = "list_item", text = "Raid and party frames now support the Frame Size setting that has been available for other unit frames. These frames can now be scaled up by 100%.", level = 1 },
            { type = "list_item", text = "Auction House filters now persist across sessions.", level = 0 },
            { type = "list_item", text = "In Group Finder, the refresh button no longer overlaps with the filter reset button.", level = 0 },
            { type = "list_item", text = "ADDONS", level = 0 },
            { type = "list_item", text = "Added new APIs that allow addons to display filtered sets of auras in customized ways, without exposing the underlying aura information that could be used for automation. Read more information in the Addons and Auras in Curse of Ula’tek thread.", level = 1 },
            { type = "list_item", text = "New UI texture filenames will no longer be published to the ManifestInterfaceData DB. Existing filenames will remain available, and this change will not affect players. Addons will still be able to use these textures, and we’re informing addon developers so we can work with them to adopt these changes.", level = 1 },
            { type = "h2", text = "WORLD" },
            { type = "list_item", text = "The Amani Pass between Eversong Woods and Zul’Aman should no longer dismount players that pass through it.", level = 0 },
            { type = "list_item", text = "Fixed several creature spawns across the entire game that could cause players to get stuck in combat.", level = 0 },
            { type = "h2", text = "KNOWN ISSUES" },
            { type = "list_item", text = "Curse of Ula’tek rares do not have their loot yet.", level = 0 },
            },
        },
        ["2026-06-30-soar-through-turbulent-timewaysnow-live-32c42bd775"] = {
            id = "2026-06-30-soar-through-turbulent-timewaysnow-live-32c42bd775",
            post_key = "32c42bd775",
            title = "Soar Through Turbulent Timeways—Now Live!",
            category = "Blogs (US)",
            timestamp = 1782837599,
            url = "https://news.blizzard.com/en-us/article/24264422/soar-through-turbulent-timewaysnow-live",
            content = {
            { type = "p", text = "Once more, the Bronze Dragonflight has discovered growing disturbances in the timeways as several rapidly intersect our own." },
            { type = "p", text = "When: June 30–August 11" },
            { type = "p", text = "Timewalk through a previous expansion each week for six consecutive weeks, beginning and ending with Dragonflight. This grand tour through World of Warcraft’s past features six Timewalking Dungeons: Algeth’ar Academy, Halls of Infusion, Neltharus, Ruby Life Pools, The Azure Vaults, and Brackenhide Hollow." },
            { type = "p", text = "Players can also shop at a new Dragonflight vendor, Xydan, located in the Bronze Enclave in Valdrakken." },
            { type = "hr" },
            { type = "h2", text = "TIME TO BUFF UP" },
            { type = "p", text = "Those who run any Timewalking dungeon during the event get the “Knowledge of the Timeways” buff, granting a 5% increase to experience when killing monsters and completing quests." },
            { type = "p", text = "Completing Timewalking dungeons increases the effect and extends its duration. This is a stacking buff, and after four applications, it transforms into “Mastery of the Timeways,” increasing the experience gained from killing monsters and completing quests to 30%, and persists through death." },
            { type = "hr" },
            { type = "h2", text = "MASTER THE TIMEWAYS FOR A NEW MOUNT" },
            { type = "p", text = "This season, players can earn the Spawn of Vyranoth flying mount by completing the “Master of the Turbulent Timeways V” achievement, awarded to champions who maintain “Mastery of the Timeways” for any four weeks during the event." },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-30-soar-through-turbulent-timewaysnow-live-32c42bd775\\image-1.jpg" },
            { type = "p", text = "“Vyranoth's brood was decimated by the aspects, yet her actions have brought many of her surviving progeny to follow in her frigid path and aid in Azeroth's defense.”" },
            { type = "hr" },
            { type = "h2", text = "DON’T LET TIME PASS YOU BY" },
            { type = "p", text = "Timewalking dungeons have a chance to drop items that usually drop when you run them on Heroic, and you'll earn Reputation with a faction associated with the dungeon. Enemies and loot will automatically scale to your level." },
            { type = "p", text = "While Timewalking is active, you will gain a 50% bonus to reputations earned from quests and creature kills for all reputations related to the corresponding expansion." },
            { type = "p", text = "To get to any one of the dungeons, open the Group Finder (default hotkey: “I”) and then select Dungeon Finder and Timewalking in the “Type” dropdown menu. Selecting “Find Group” will match you with other players and send you to one of the available Heroic Dungeons." },
            { type = "p", text = "Here’s the expansion timeline for Turbulent Timeways:" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-30-soar-through-turbulent-timewaysnow-live-32c42bd775\\image-2.jpg" },
