            { type = "list_item", text = "Brackenhide Hollow", level = 0 },
            { type = "hr" },
            { type = "h2", text = "TRADE IN YOUR TIMEWARPED BADGES" },
            { type = "p", text = "New rewards and returning favorites from past Turbulent Timeways events, including the Bronze Wilderling, Bronze Corpsefly, Bronze Gravewing, and Bronze Aquilon Shadowlands mounts, can be found on the Timewalking vendor throughout the event." },
            { type = "p", text = "The Covenant restrictions for these Shadowlands mounts have been lifted. For example, if you choose a Venthyr Mount (Bronze Gravewing) but are not part of the Venthyr Covenant faction, you can still ride this mount." },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-30-soar-through-turbulent-timewaysnow-live-32c42bd775\\image-8.jpg" },
