        ["2026-06-29-class-tuning-incoming-june-30-d225dd98da"] = {
            id = "2026-06-29-class-tuning-incoming-june-30-d225dd98da",
            post_key = "d225dd98da",
            title = "Class Tuning Incoming – June 30",
            category = "General Discussion (US)",
            timestamp = 1782765911,
            url = "https://us.forums.blizzard.com/en/wow/t/2320744/1",
            content = {
            { type = "p", text = "With scheduled weekly maintenance in each region, we’ll make tuning adjustments that are primarily targeted at specs that are unperforming in group content." },
            { type = "p", text = "In PvP, we’re continuing to improve underperforming specs, address over-performing specs, and adjust burst damage where specs have too much or too little." },
            { type = "h2", text = "CLASSES" },
            { type = "h3", text = "Druid" },
            { type = "list_item", text = "Balance", level = 0 },
            { type = "list_item", text = "All damage increased by 4%.", level = 1 },
            { type = "list_item", text = "Feral", level = 0 },
            { type = "dev_note", text = "Feral is performing well in M+, but their overall damage in raid is low. These changes shore up their single-target power and total raid damage.", level = 1 },
            { type = "list_item", text = "All damage increased by 3%. Does not apply to PvP combat.", level = 1 },
            { type = "list_item", text = "Melee auto-attack damage increased by 15%.", level = 1 },
            { type = "list_item", text = "Rip damage increased by 5%. Does not apply to PvP combat.", level = 1 },
            { type = "list_item", text = "Rampant Ferocity damage reduced by 15%. Does not apply to PvP combat.", level = 1 },
            { type = "list_item", text = "Restoration", level = 0 },
            { type = "dev_note", text = "Restoration’s damage compared to other healers is lower than we’d like. We’re rebalancing some of Restoration Druid’s damage out of Thrash and into the rest of the kit.", level = 1 },
            { type = "list_item", text = "All damage increased by 15%.", level = 1 },
            { type = "list_item", text = "Bear Form Thrash damage reduced by 25%.", level = 1 },
            { type = "h3", text = "Evoker" },
            { type = "list_item", text = "Devastation", level = 0 },
            { type = "list_item", text = "All ability damage increased by 3%.", level = 1 },
            { type = "h3", text = "Mage" },
            { type = "list_item", text = "Arcane", level = 0 },
            { type = "list_item", text = "All ability damage increased by 3%.", level = 1 },
            { type = "h3", text = "Priest" },
            { type = "list_item", text = "Holy", level = 0 },
            { type = "list_item", text = "Holy Word: Serenity healing increased by 20%.", level = 1 },
            { type = "list_item", text = "Holy Word: Sanctify healing increased by 20%.", level = 1 },
            { type = "h3", text = "Shaman" },
            { type = "list_item", text = "Restoration", level = 0 },
            { type = "list_item", text = "All healing increased by 4%. This does not apply to PvP combat.", level = 1 },
            { type = "h2", text = "PLAYER VERSUS PLAYER" },
            { type = "h3", text = "Demon Hunter" },
            { type = "list_item", text = "Devourer", level = 0 },
            { type = "dev_note", text = "Devourer Demon Hunters have been performing above expectations, especially in defensive metrics, so self-healing is being reduced.", level = 1 },
            { type = "list_item", text = "Shattered Souls now heals for 0.5% of maximum Health per Soul Fragment consumed (was 1%) in PvP combat.", level = 1 },
            { type = "h3", text = "Death Knight" },
            { type = "list_item", text = "Unholy", level = 0 },
            { type = "dev_note", text = "Unholy’s burst damage is overwhelming too frequently, so contributing abilities are receiving a reduction with some of that overall damage moving into the steadier output from Dread Plague.", level = 1 },
            { type = "list_item", text = "Putrify damage reduced by 15% in PvP combat.", level = 1 },
            { type = "list_item", text = "Soul Reaper damage reduced by 15% in PvP combat.", level = 1 },
            { type = "list_item", text = "Dread Plague damage increased by 15% in PvP combat.", level = 1 },
            { type = "h3", text = "Druid" },
            { type = "list_item", text = "Guardian", level = 0 },
            { type = "dev_note", text = "Guardians’ burst potential with their apex talent has been higher than we would like for a tank specialization in PvP.", level = 1 },
            { type = "list_item", text = "Wild Guardian now echoes at 50% effectiveness (was 200%) in PvP combat.", level = 1 },
            { type = "h3", text = "Evoker" },
            { type = "list_item", text = "Augmentation", level = 0 },
            { type = "list_item", text = "All damage increased by 8% in PvP combat.", level = 1 },
            { type = "list_item", text = "Preservation", level = 0 },
            { type = "dev_note", text = "Preservation Evoker is slightly overperforming in PvP, so we’re making one additional targeted nerf to them in this pass. Temporal Burst makes it hard for enemies to react to important casts like Sleep Walk, so we’re reducing its effectiveness.", level = 1 },
            { type = "list_item", text = "Temporal Burst increases haste, movement speed, and cooldown recovery rate by 15% in PvP combat (was 30%).", level = 1 },
            { type = "h3", text = "Hunter" },
            { type = "list_item", text = "Marksmanship", level = 0 },
            { type = "list_item", text = "Double tap now causes Aimed Shot to fire at 16% effectiveness or your next Rapid Fire to fire 16% additional shots (was 40%).", level = 1 },
            { type = "dev_note", text = "We’re reducing Double Shot’s burst potential to allow enemy players to have more time to react to the Marksmanship Hunter’s incoming damage.", level = 1 },
            { type = "list_item", text = "Survival", level = 0 },
            { type = "list_item", text = "All damage increased by 3% in PvP Combat.", level = 1 },
            { type = "h3", text = "Mage" },
            { type = "list_item", text = "Frost", level = 0 },
            { type = "dev_note", text = "We are redistributing some of Frost Mage’s damage out of Ray of Frost and into the rest of its kit with the intention of decreasing its burst capabilities and improving its steady-state pressure.", level = 1 },
            { type = "list_item", text = "Ray of Frost damage decreased by 20% in PvP combat. All damage increased 3% in PvP combat.", level = 1 },
            { type = "h3", text = "Paladin" },
            { type = "list_item", text = "Protection", level = 0 },
            { type = "dev_note", text = "Templars’ burst capabilities have made Protection Paladin more of an offensive threat than we would like them to be in PvP.", level = 1 },
            { type = "list_item", text = "Divine Exaction now casts Divine Toll again at 25% effectiveness (was 75%) in PvP combat.", level = 1 },
            { type = "list_item", text = "Hammer of Light damage decreased by 30% in PvP combat.", level = 1 },
            { type = "list_item", text = "Retribution", level = 0 },
            { type = "dev_note", text = "Retribution has been performing better than expected, so we are applying a small damage reduction.", level = 1 },
            { type = "list_item", text = "All ability damage reduced by 3% in PvP combat.", level = 1 },
            { type = "h3", text = "Priest" },
            { type = "list_item", text = "Discipline", level = 0 },
            { type = "dev_note", text = "Voidweaver Priests are dealing too much damage in PvP. We’re reducing some of that damage and increasing their healing to compensate.", level = 1 },
            { type = "list_item", text = "Expiation deals damage equal to 200% of the of the amount consumed from Shadow Word: Pain in PvP combat (was 300%).", level = 1 },
            { type = "list_item", text = "Inescapable Torment damage reduced by 25% in PvP combat.", level = 1 },
            { type = "list_item", text = "Shadow Word: Pain damage reduced by 10% in PvP combat.", level = 1 },
            { type = "list_item", text = "Voidweaver: Atonement healing increased by 15%.", level = 1 },
            { type = "list_item", text = "Oracle: Preventive Measures increases damage of Penance, Smite, Holy Nova by 20% (was 15%).", level = 1 },
            { type = "list_item", text = "Ultimate Penitence healing increased by 25%.", level = 1 },
            { type = "list_item", text = "Shadow", level = 0 },
            { type = "dev_note", text = "In addition to a needed boost of overall damage, Shadow Word: Death is also receiving a buff intended to make its damage worthwhile when striking enemies in its low-health threshold.", level = 1 },
            { type = "list_item", text = "All ability damage increased by 4% in PvP combat.", level = 1 },
            { type = "list_item", text = "Shadow Word: Death damage increased by 45% in PvP combat.", level = 1 },
            { type = "h3", text = "Shaman" },
            { type = "list_item", text = "Restoration", level = 0 },
            { type = "dev_note", text = "Farseer Restoration Shaman has been behind in performance in PvP compared to Totemic, we’re increasing the throughput of heals and effects provided by Farseer talents and their Ancestors to help close the gap.", level = 1 },
            { type = "list_item", text = "Farseer: Maelstrom Supremacy increases healing of affected spells in PvP by 20% (was 15%).", level = 1 },
            { type = "list_item", text = "Farseer: Hydrobubble’s effectiveness is no longer reduced in PvP (was a 20% reduction).", level = 1 },
            { type = "list_item", text = "Farseer: Heals cast by Call of the Ancestors increased in PvP by 30% (was 20%).", level = 1 },
            { type = "h3", text = "Warrior" },
            { type = "list_item", text = "Arms, Protection", level = 0 },
            { type = "dev_note", text = "We’re slightly reducing Colossus’ ability to tank damage to make them more of a viable kill target.", level = 1 },
            { type = "list_item", text = "Mountain of Muscle and Scars reduces damage taken by 3% in PvP combat (was 5%).", level = 1 },
            { type = "h3", text = "Warlock" },
            { type = "list_item", text = "Affliction", level = 0 },
            { type = "list_item", text = "All damage increased by 3% in PvP combat.", level = 1 },
            { type = "list_item", text = "Demonology", level = 0 },
            { type = "dev_note", text = "Demonology damage while freecasting has not been as effective as we would like, so we’re targeting a few adjustments to Shadow Bolt and Demonbolt with the intention of increasing their ability to punish enemies for allowing them to chain casts together.", level = 1 },
            { type = "list_item", text = "Shadow Bolt damage increased by 200% in PvP combat.", level = 1 },
            { type = "list_item", text = "Demonbolt damage increased by 30% in PvP combat.", level = 1 },
            { type = "list_item", text = "Destruction", level = 0 },
            { type = "list_item", text = "Incinerate damage increased by 50% in PvP combat.", level = 1 },
            },
        },
