        ["2026-06-29-julys-trading-post-ignites-a-true-blue-celebration-94d51ceecc"] = {
            id = "2026-06-29-julys-trading-post-ignites-a-true-blue-celebration-94d51ceecc",
            post_key = "94d51ceecc",
            title = "July’s Trading Post Ignites a True-Blue Celebration",
            category = "General Discussion (US)",
            timestamp = 1782752473,
            url = "https://us.forums.blizzard.com/en/wow/t/2321806/1",
            content = {
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-29-julys-trading-post-ignites-a-true-blue-celebration-94d51ceecc\\image-1.jpg" },
            { type = "p", text = "July’s Trading Post is taking on a brilliant blue streak, with fresh finds ready to add a bold splash of color to your collection. Complete activities to earn Trader’s Tender, fill your Traveler’s Log, and rocket away with the Bilgewater X-TREME mount." },
            { type = "p", text = "View Full Article" },
            },
        },
        ["2026-06-29-julys-trading-post-ignites-a-true-blue-celebration-76d31dc8d5"] = {
            id = "2026-06-29-julys-trading-post-ignites-a-true-blue-celebration-76d31dc8d5",
