            content = {
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-29-julys-trading-post-ignites-a-true-blue-celebration-76d31dc8d5\\image-1.jpg" },
