        },
        ["2026-06-25-the-venomous-abyss-raid-testing-scheduler-1cc158c320"] = {
            id = "2026-06-25-the-venomous-abyss-raid-testing-scheduler-1cc158c320",
            post_key = "1cc158c320",
            title = "The Venomous Abyss Raid Testing Scheduler",
            category = "Midnight: Curse of Ula'tek Public Test Realm (US)",
            timestamp = 1782414597,
            url = "https://us.forums.blizzard.com/en/wow/t/2317466/1",
            content = {
            { type = "p", text = "Greetings!" },
            { type = "p", text = "The raid testing schedule is very fluid and subject to the realities of a test environment. There’s the possibility of having to change the time of a testing session, change the bosses being tested, or cancel a test entirely due to bugs, server hardware issues, etc." },
            { type = "p", text = "Multiple vendors are set up on the PTR in Silvermoon City, Stormwind and Orgrimmar to allow players to quickly and easily test out end-game content (Profession Vendors and Trainers, Class Set Vendors, PvP Gear Vendors, and Trinket Vendors)." },
            { type = "p", text = "Keep an eye on the PTR forum for the encounter feedback threads and the latest information. Thank you in advance for testing and providing feedback." },
            { type = "h2", text = "THE VENOMOUS ABYSS RAID TESTING SCHEDULE" },
            { type = "p", text = "The final boss in the Venomous Abyss will not be available for testing." },
            { type = "h2", text = "THURSDAY, JUNE 25" },
            { type = "list_item", text = "Heroic", level = 0 },
            { type = "list_item", text = "Nek’zali the Soulcoiler – 12:00 PDT (15:00 EDT, 21:00 CEST)", level = 1 },
            { type = "list_item", text = "The Lost Explorers – 13:00 PDT (16:00 EDT, 22:00 CEST)", level = 1 },
            { type = "list_item", text = "Entombed Sentinels – 14:00 PDT (17:00 EDT, 23:00 CEST)", level = 1 },
            { type = "h2", text = "FRIDAY, JUNE 26" },
            { type = "list_item", text = "Heroic", level = 0 },
            { type = "list_item", text = "Sszorak – 11:00 PDT (14:00 EDT, 20:00 CEST)", level = 1 },
            { type = "list_item", text = "Vashnik the Malignant – 12:00 PDT (15:00 EDT, 21:00 CEST)", level = 1 },
            { type = "list_item", text = "The Twin Fangs – 13:00 PDT (16:00 EDT, 22:00 CEST)", level = 1 },
            { type = "list_item", text = "The Coiled Altar – 14:00 PDT (17:00 EDT, 23:00 CEST)", level = 1 },
            { type = "h2", text = "THURSDAY, JULY 9" },
            { type = "list_item", text = "Mythic", level = 0 },
            { type = "list_item", text = "Nek’zali the Soulcoiler – 12:00 PDT (15:00 EDT, 21:00 CEST)", level = 1 },
            { type = "list_item", text = "The Lost Explorers – 13:00 PDT (16:00 EDT, 22:00 CEST)", level = 1 },
            { type = "list_item", text = "Entombed Sentinels – 14:00 PDT (17:00 EDT, 23:00 CEST)T)", level = 1 },
            { type = "h2", text = "FRIDAY, JULY 10" },
            { type = "list_item", text = "Mythic", level = 0 },
            { type = "list_item", text = "Sszorak – 11:00 PDT (14:00 EDT, 20:00 CEST)", level = 1 },
            { type = "list_item", text = "Vashnik the Malignant – 12:00 PDT (15:00 EDT, 21:00 CEST)", level = 1 },
            { type = "list_item", text = "The Twin Fangs – 13:00 PDT (16:00 EDT, 22:00 CEST)", level = 1 },
            { type = "list_item", text = "The Coiled Altar – 14:00 PDT (17:00 EDT, 23:00 CEST)", level = 1 },
            { type = "list_item", text = "The Venomous Abyss - Normal", level = 0 },
            { type = "list_item", text = "Start – 15:00 PDT (18:00 EDT, 00:00 CEST)", level = 1 },
            { type = "list_item", text = "End – Monday, July 13 at 10:00 PDT (13:00 EDT, 19:00 CEST)", level = 1 },
            { type = "h3", text = "Q: How do I get into the raid zone?" },
            { type = "p", text = "A: In Silvermoon City, Orgrimmar, or Stormwind, you may speak to Nexus-Lord Donjon Rade to teleport into the raid zone while it is open for testing. (The option to teleport will not be available when the zone is not open for testing.)" },
            { type = "h3", text = "Q: What character should I use to test the raid?" },
            { type = "p", text = "A: Whichever you prefer. We will be scaling players’ effective level to 90 for raid testing, and their item level to an appropriate threshold for the encounter(s) being tested." },
            { type = "h3", text = "Q: How long does testing last?" },
            { type = "p", text = "A: The primary purpose of testing is to give us the information we need to balance the encounters, evaluate how mechanics are playing out in practice, and identify bugs. Once we’re satisfied that we’ve received that information for a given encounter, we’ll be shutting down testing. Usually this takes around 1 hour per encounter, but there are no guarantees." },
            { type = "h3", text = "Q: How do I report feedback or bugs?" },
            { type = "p", text = "A: We’ll be posting encounter feedback threads each week prior to the start of the raid tests. Additionally, you can also submit your feedback through the in-game Issue Reporter tool." },
            },
        },
        ["2026-06-24-midnight-season-2-mythic-dungeon-philosophy-and-design-goals-3addf6c730"] = {
            id = "2026-06-24-midnight-season-2-mythic-dungeon-philosophy-and-design-goals-3addf6c730",
            post_key = "3addf6c730",
            title = "Midnight Season 2 Mythic+ Dungeon Philosophy and Design Goals",
            category = "Midnight: Curse of Ula'tek Public Test Realm (US)",
            timestamp = 1782332843,
            url = "https://us.forums.blizzard.com/en/wow/t/2320056/1",
            content = {
            { type = "p", text = "We’ve been paying close attention to the discussion around the Midnight Season 2 dungeon pool. Some of that discussion has focused on returning dungeons with pain points from past seasons, and some has focused on the unique mechanics in the Midnight dungeons. That feedback is useful, and it lines up with the work we do internally when building a season. We want to take this opportunity to share more about how we choose dungeons, how we update them for Mythic+, and what we’ve already done for Midnight Season 2." },
            { type = "h2", text = "CHOOSING DUNGEONS" },
            { type = "p", text = "When we begin choosing dungeons for a Mythic+ season, the first thing we look at is which dungeons might fit the theme of the upcoming update. Sometimes that means reconnecting players with a story, character, or place that is relevant to the game’s current story. With L’ura threatening the Sunwell in March on Quel’danas, it was a great time to bring that character back and show the start of her relationship with Alleria in Seat of the Triumvirate. Other times, it is more about shared themes, like the connection between trolls, snakes, and the Curse of Ul’atek. Not every dungeon needs to point at the same story or tone, though. A dungeon like Ruby Life Pools can help the pool feel more varied by giving players a change of pace from the patch’s main themes, as can a dungeon like Skyreach from Midnight Season 1." },
            { type = "p", text = "From there, we think about the shape of the full pool. Each dungeon should bring something distinct, whether that is its theme, layout, pacing, visual style, or mechanical identity. We want the season to feel varied from key to key, with a strong mix of different places, different problems to solve, and different reasons to be excited about each dungeon in the pool." },
            { type = "h2", text = "UPDATING DUNGEONS" },
            { type = "p", text = "Selecting a dungeon for a new season is a big commitment. We need to believe that the dungeon can contribute to the goals of the season, but we also must commit to addressing aspects of the dungeon that didn’t play out well last time it was featured in a Mythic+ season." },
            { type = "p", text = "Once we know a dungeon is returning, we look at it from a few angles: feedback from its previous appearance, our own experiences playing the live game, our internal playtests, and early discussion during the current expansion beta." },
            { type = "p", text = "Some older dungeons give us more of a blank canvas. In those cases, our goal is to capture the essence and themes of the dungeon without players feeling like it has become something entirely different. Pit of Saron is a good example from Midnight Season 1. We rebuilt it from the ground up while keeping its core themes, spaces, and mechanics in mind, so it still felt like Pit of Saron." },
            { type = "p", text = "Every dungeon gets a full creature review. We look at health, damage, ability packages, cast frequency, enemy placement, and how each pull contributes to the dungeon as a whole. The goal is not for every creature to feel the same, but for the dungeon to have a balanced mix of challenges within itself and alongside the rest of the season." },
            { type = "p", text = "We also look closely at how those challenges are distributed. A mechanic can be appropriate on its own but become frustrating if too many similar asks are packed into the same section of a dungeon. The density of interruptible spells is a good example of something we watched closely in Midnight Season 1, and it is the kind of thing we’ll continue to evaluate when building a new pool." },
            { type = "p", text = "Boss encounters are reviewed individually. Some bosses already have a strong foundation and mostly need visual polish, tuning, and pacing adjustments. Others need more substantial updates because their mechanics were too complex, did not challenge players in a compelling way, or relied too heavily on players remembering how the encounter worked in a previous season. In some cases, we see an opportunity to lean further into a boss’s core idea, giving returning players something new to engage with while reducing the knowledge gap for players seeing the dungeon for the first time." },
            { type = "h2", text = "OVERALL CHALLENGE AND FEEL" },
            { type = "p", text = "Speaking to the discussions around difficulty, the difficulty of dungeons in Midnight Season 1 met a lot of our design goals, and our aim for Season 2 dungeons is that they feel similar overall. One key difference is that we’d like the difficulty of a dungeon to be more evenly shared across the group. Specifically, we’d like the DPS role to factor more strongly into a group’s success." },
            { type = "p", text = "Tank and healer players often have the most immediate pressure in Mythic+. When something goes wrong, they are usually the first roles asked to solve it, whether that means surviving the pull, recovering the group, or covering mistakes long enough for the key to continue. In Season 1, key success could be too heavily shaped by those moments, while damage throughput and damage dealer execution did not always have the same impact on whether a group timed the key." },
            { type = "p", text = "In Season 2, you’ll see slightly increased creature health pools, a larger emphasis on skills like target prioritization and damage checks, and some abilities trading raw damage effects for penalties to damage output or mobility. We still want dungeons to move at a good pace. The health changes are there so priority targets, cooldown usage, and damage checks have more room to matter. Tanks and healers will still have plenty to manage, but success should feel more evenly shared across the group." },
            { type = "h2", text = "MIDNIGHT SEASON 2" },
            { type = "p", text = "Before we get into dungeon specific notes, we also want to call out a broader visual clarity update that has been part of recent discussions." },
            { type = "h3", text = "General" },
            { type = "list_item", text = "Cone and line abilities have received updated precast visuals to better communicate their impact areas.", level = 0 },
            { type = "p", text = "Over the years, cone and line attacks have used a variety of visual treatments across different eras of the game. As those dungeons rotate into Mythic+, we want that visual language to be more consistent and easier to read at a glance." },
            { type = "p", text = "Throughout PTR, we’re introducing standardized cone and line precast visuals that share the visual style of our circular ground target effects and rims. These visuals are intended for attacks that hit instantly, such as breaths or lasers. Charges, projectiles, and other similar mechanics may use different visual treatments with a consideration for travel time of the attack. When a cone or line attack tracks its target during a cast, it will use an edge only variant of the visual, along with an arrow above the target’s head. Vaelgor’s Dread Breath in Voidspire is an example of an ability that would use this treatment." },
            { type = "image", width = 720, height = 385, u = 0.703125, v = 0.751953, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-24-midnight-season-2-mythic-dungeon-philosophy-and-design-goals-3addf6c730\\image-1.jpg" },
            { type = "image", width = 720, height = 385, u = 0.703125, v = 0.751953, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-24-midnight-season-2-mythic-dungeon-philosophy-and-design-goals-3addf6c730\\image-2.jpg" },
            { type = "image", width = 720, height = 385, u = 0.703125, v = 0.751953, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-24-midnight-season-2-mythic-dungeon-philosophy-and-design-goals-3addf6c730\\image-3.jpg" },
            { type = "image", width = 720, height = 385, u = 0.703125, v = 0.751953, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-24-midnight-season-2-mythic-dungeon-philosophy-and-design-goals-3addf6c730\\image-4.jpg" },
            { type = "h2", text = "DUNGEONS" },
            { type = "p", text = "Below, we’ll walk through each dungeon in the Season 2 pool, call out some of the pain points we saw from previous appearances and discussions, and share some of the updates we’ve made to help it fit this season." },
            { type = "h3", text = "Murder Row" },
            { type = "p", text = "During our internal testing as well as during the Midnight Preseason, we identified the cantina event as a potential pain point in Mythic+, as well as the large number creatures with interruptible casts following the Zaen Bladesorrow encounter. Here’s some examples of the changes we’ve made to address pain points like these:" },
            { type = "list_item", text = "Increased the progress contributed towards cantina event completion from successful execution of a task.", level = 0 },
            { type = "list_item", text = "Significantly reduced the loss of progress when failing to perform a task during the cantina event.", level = 0 },
            { type = "list_item", text = "Removed job switching during the cantina event.", level = 0 },
            { type = "list_item", text = "Reduced the total number of caster enemies after Zaen Bladesorrow.", level = 0 },
            { type = "list_item", text = "Removed some casted abilities from Corrupted Warlocks, Trained Fel Hunters, and Felcaster Neophytes.", level = 0 },
            { type = "h3", text = "Den of Nalorakk" },
            { type = "p", text = "During the Midnight Preseason, we received feedback that the pacing of the gauntlet before the Sentinel of Winter could feel frustrating. Additionally, we identified that the Sentinel of Winter’s absorb shield would not scale well into higher Mythic+ keys. Also, we saw feedback that certain RP moments across the dungeon overstayed their welcome. Here are some of the adjustments made to address feedback like the above:" },
            { type = "list_item", text = "Adjusted RP sequences to resolve quicker.", level = 0 },
            { type = "list_item", text = "Adjusted the pacing and effects of the winter gauntlet to increase ease of navigation.", level = 0 },
            { type = "list_item", text = "Updated the Sentinel of Winter’s Eternal Winter to no longer grant an absorb shield and to channel for a fixed duration.", level = 0 },
            { type = "list_item", text = "Updated the Avatar of Starvation’s Starvation Effigy to now have a 5 second cast time before afflicting players with its health debuff.", level = 0 },
            { type = "list_item", text = "Updated the Avatar of Determination’s Pulverize to no longer stun the targeted player.", level = 0 },
            { type = "h3", text = "The Blinding Vale" },
            { type = "p", text = "A pain point we identified in this dungeon is the presence of certain boss mechanics that disproportionally challenge pickup groups such as in the Ikuzz the Light Hunter and Ziekket encounters. There are also a few creature packs with an excessive amount of casters. These are some of the changes we made to address these types of issues:" },
            { type = "list_item", text = "Reduced the number of Bloodthorn Roots summoned by Ikuzz the Light Hunter.", level = 0 },
            { type = "list_item", text = "Reduced the health of Lightspawn Lashers in Ziekket’s encounter.", level = 0 },
            { type = "list_item", text = "Addressed an issue that could cause players to unfairly fail the Lightbloom’s Essence mechanic in Ziekket’s encounter.", level = 0 },
            { type = "list_item", text = "Updated spawning across the dungeon to reduce the amount of casters found in a single creature pack.", level = 0 },
            { type = "h3", text = "Voidscar Arena" },
            { type = "p", text = "During internal playtests, we felt there was an opportunity to do more with routing and for more engaging mechanics in some of the boss encounters. To that end, we made adjustments such as the following:" },
            { type = "list_item", text = "Updated spawning prior to the first boss to make the left side melee-focused and the right side caster-focused, with each side now featuring a miniboss that provides a unique stat buff for players.", level = 0 },
            { type = "list_item", text = "Reworked the Taz’Rah’s encounter with a new set of abilities.", level = 0 },
            { type = "list_item", text = "Designed new abilities for Watchful Harrowers and gave them significant contribution towards completing enemy forces.", level = 0 },
            { type = "list_item", text = "Updated spawning prior to the Charonus encounter to change creature composition and replace the four minibosses with new Domanaar lieutenants, who must be defeated in order to engage Charonus.", level = 0 },
            { type = "list_item", text = "Adjusted mechanics in the Charonus encounter to improve their interactions with each other.", level = 0 },
            { type = "h3", text = "Kings’ Rest" },
            { type = "p", text = "While reviewing Kings’ Rest during our planning of the season 2 dungeon pool, we identified that Shadow of Zul’s damage was exceptionally high and did not scale well into higher Mythic+ keys. Additionally, the lack of checkpoints after each boss along with long sequences of RP scenes hurt the flow of the dungeon when compared to modern M+ dungeons. Additionally, while it was interesting for The Council of Tribes to have a different boss order from week to week, this created situations where some weeks would feel more punishing than others. We also found that Dazar, The First King featured some mechanics that felt out-of-date with modern dungeon boss design. These are some of the changes we made to the dungeon to address these issues:" },
            { type = "list_item", text = "Adjusted RP sequences to resolve quicker.", level = 0 },
            { type = "list_item", text = "Switched the Council of Tribes to a fixed sequence: Kula the Butcher, then Aka’alil the Conqueror, then Zanazal the Wise.", level = 0 },
            { type = "list_item", text = "Adjusted the Shadow of Zul’s abilities to fit modern M+ design standards.", level = 0 },
            { type = "list_item", text = "Reworked the Dazar, The First King encounter with a new set of abilities.", level = 0 },
            { type = "h3", text = "Temple of Sethraliss" },
            { type = "p", text = "Certain bosses like Adderis and Aspix presented mechanics in a subtle and inconsistent manner, and Merektha had long forced downtime during Burrow. The gauntlet section prior to the last boss saw issues with bugs and general gameplay flow. Additionally, the final encounter was heavily weighted on the healer while lacking gameplay for other roles. This dungeon was heavily adjusted in terms of both trash creatures and boss encounters to address these pain points. In particular:" },
            { type = "list_item", text = "Adjusted Adderis and Aspix to now swap their shields on a health threshold, and their shield now provides damage resistance rather than inflicting damage to the attacker.", level = 0 },
            { type = "list_item", text = "Reworked Merektha’s ability package to improve engagement and changed Burrow so that she now re-emerges after the defeat of her adds rather than on a timer.", level = 0 },
            { type = "list_item", text = "Reworked the gauntlet sequence prior to the final boss to address concerns with bugs and to remove the need for a player to be in “timeout” while energizing an orb.", level = 0 },
            { type = "list_item", text = "Reworked the final encounter to encourage more group participation in the healing of the Avatar of Sethraliss.", level = 0 },
            { type = "list_item", text = "Reworked Cheap Shot on Shrouded Fangs to provide more opportunity for counterplay.", level = 0 },
            { type = "h3", text = "Ruby Life Pools" },
            { type = "p", text = "Ruby Life Pools had many pulls that felt chaotic and cramped, particularly in the first section. Additionally, the flying patrols of Thunderhead and Flamegullet were confusing to navigate around. Pulls across the dungeon often featured fast and frequent casting as well as frequent bursts of unavoidable damage. Additionally, certain abilities were presented in a way that increased the likelihood of “snowballing” mistakes or were otherwise unclear. These are some of the changes we made to address these issues:" },
            { type = "list_item", text = "Removed some creature packs from the first section.", level = 0 },
            { type = "list_item", text = "Reworked abilities like Flashfrost Earthshaper’s Tectonic Slam to remove cast bar clutter and bursty group damage.", level = 0 },
            { type = "list_item", text = "Slowed down the ability schedule and reduced the movement forces of Melidrussa Chillworn.", level = 0 },
            { type = "list_item", text = "Changed the patrols of Thunderhead and Flamegullet to occur on the ground.", level = 0 },
            { type = "list_item", text = "Adjusted Kyrakka’s Flaming Embers to no longer apply Infernocore and Kokia Blazehoof’s Ritual of Blazebinding to now mark the targeted player before it casts.", level = 0 },
            { type = "list_item", text = "Changed creature pack composition and adjusted ability packages to simplify the pacing and mechanical asks of each pull", level = 0 },
            },
        },
        ["2026-06-24-hotfixes-june-22-2026-431dbc3a26"] = {
            id = "2026-06-24-hotfixes-june-22-2026-431dbc3a26",
            post_key = "431dbc3a26",
            title = "Hotfixes: June 22, 2026",
            category = "Blogs (EU)",
            timestamp = 1782262414,
            url = "https://news.blizzard.com/en-gb/article/24276957/hotfixes-june-23-2026",
            content = {
            { type = "p", text = "Here you'll find a list of hotfixes that address various issues related to World of Warcraft: Midnight, Mists of Pandaria Classic, Season of Discovery, Burning Crusade Classic, WoW Classic Era, and Hardcore. Some of the hotfixes below take effect the moment they were implemented, while others may require scheduled realm restarts to go into effect. Please keep in mind that some issues cannot be addressed without a client-side patch update. This list will be updated as additional hotfixes are applied." },
            { type = "h2", text = "HOTFIXES" },
            { type = "hr" },
            { type = "h3", text = "June 23, 2026" },
            { type = "h3", text = "Items" },
            { type = "list_item", text = "Rotmire's Sporeheart once again triggers from Leech healing.", level = 0 },
            { type = "h3", text = "Lorewalking" },
            { type = "list_item", text = "During Loa Lorewalking (and Darkspear Heritage), Lukou's portals will now allow transport while in combat.", level = 0 },
            { type = "h3", text = "Midsummer Fire Festival" },
            { type = "list_item", text = "“Reignite the Skies: Orgrimmar” and “Reignite the Skies: Stormwind” Midsummer dailies unlocks are now account-wide.", level = 0 },
            { type = "list_item", text = "Fixed an issue that allowed the contents Satchel of Chilled Goods to reroll each time it was opened.", level = 0 },
            { type = "list_item", text = "Sun Festival Painted Roc’s chance to drop in Satchel of Chilled Goods has been doubled for the first drop of the day on the account. The drop rate from the first satchel will continue to increase each day until it is obtained.", level = 0 },
            { type = "h3", text = "Player versus Player" },
            { type = "list_item", text = "Fixed an issue where some important effects and major defensives were not displaying on enemy player nameplates.", level = 0 },
            { type = "h3", text = "Professions" },
            { type = "list_item", text = "Fixed an issue where Empowered Mulch would result in no herbs being gathered.", level = 0 },
            { type = "h3", text = "Quests" },
            { type = "list_item", text = "The weekly offerings from Lady Liadrin should once again offer four choices to players.", level = 0 },
            { type = "h3", text = "Val" },
            { type = "list_item", text = "Adjustments made to the \"Until it is Done\" world quest, improving quest credit earned and increasing creature respawn rates.", level = 0 },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Challenge Mode", level = 0 },
            { type = "list_item", text = "Challenge Conqueror: Platinum (Season 3) is now correctly earnable.", level = 1 },
            { type = "dev_note", text = "Realm First! Challenge Conqueror: Platinum (Season 3) has been disabled in North America while we work on granting the achievement to the correct winners.", level = 2 },
            { type = "list_item", text = "Mists of Pandaria Classic can no longer be installed on Windows 7 and 8 operating systems.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "June 22, 2026" },
            { type = "h3", text = "Delves" },
            { type = "list_item", text = "The Excavation Site 9 and Sidestreet Sluice delves should be reliably displaying the correct names again.", level = 0 },
            { type = "h3", text = "Items" },
            { type = "list_item", text = "Fixed an issue causing the Draconic Nullcape cloak to use an unintended appearance. This item now contributes towards the Luminant Verdict's Vestments transmog sets.", level = 0 },
            { type = "h3", text = "Naigtal" },
            { type = "list_item", text = "More bouncy mushrooms have been added to help with some hard-to-reach locations.", level = 0 },
            { type = "list_item", text = "The Spore Buoy's slowfall effect now works on mounted players.", level = 0 },
            { type = "h3", text = "Omnium Folio" },
            { type = "list_item", text = "Fixed an issue with Rune of Void-Tainted Shell’s tooltip.", level = 0 },
            { type = "h3", text = "Quests" },
            { type = "list_item", text = "“Defying Gravity” should once again function with the Lair of Predaxas restored.", level = 0 },
            { type = "h3", text = "Ritual Sites" },
            { type = "list_item", text = "Players can now pick up Lady Darkglen's new quest for Tier 6 Ritual Sites in the Silvermoon hub in addition to outside the active Ritual Site.", level = 0 },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Fixed an issue that was causing Midsummer Festival Bonfires to deal more damage to players than expected.", level = 0 },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Siege of Orgrimmar cooldown reduction trinkets will now correctly re-evaluate their effects when starting a Challenge Mode dungeon.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "June 18, 2026" },
            { type = "h3", text = "Items" },
            { type = "list_item", text = "Fixed an issue that could prevent Rotmire's Sporeheart’s effect from triggering from certain sources of healing.", level = 0 },
            { type = "h3", text = "Lorewalking" },
            { type = "list_item", text = "Rewards from the Loa Lorewalking campaign should now scale all the way to level 90.", level = 0 },
            { type = "h3", text = "Naigtal" },
            { type = "list_item", text = "Rares are now enveloped in shadow for the first 3 minutes after spawning and cannot be attacked, giving players additional time to reach the encounter.", level = 0 },
            { type = "h3", text = "Player versus Player" },
            { type = "list_item", text = "Resolved an issue that could cause Horde to lose reinforcements instead of Alliance when they capture the Sparring Grounds in Slayer's Rise.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "June 17, 2026" },
            { type = "h3", text = "Abundance" },
            { type = "list_item", text = "Fixed an issue where players could not begin Abundance in Voidstorm. All players who lost Shards of Dundun due to this issue will be refunded with Unalloyed Abundance in an upcoming hotfix.", level = 0 },
            { type = "h3", text = "Island Expeditions" },
            { type = "list_item", text = "Island Expeditions should be queueing correctly once again.", level = 0 },
            { type = "h3", text = "Items" },
            { type = "list_item", text = "Fixed an issue where the Void-Touched Torch had lower Intellect than intended.", level = 0 },
            { type = "h3", text = "Lorewalking" },
            { type = "list_item", text = "Fixed an issue where the initial objective conversation for “The Prince Who Would Be King” would not complete.", level = 0 },
            { type = "h3", text = "Naigtal" },
            { type = "list_item", text = "The \"Bouncy Mushrooms,\" \"Aerospores\", and \"The Grappler\" unlocks in Naigtal are now account wide.", level = 0 },
            { type = "list_item", text = "Fixed an issue that prevented Nexus-Captain Leth'ir from dropping the quest item for “Knocking Off the Top (Heroic).” Characters that encountered the issue can earn their emblem from another Heroic kill of Nexus-Captain Leth'ir or from a wrapper quest they have not completed.", level = 0 },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Siege of Orgrimmar", level = 0 },
            { type = "list_item", text = "Garrosh Hellscream", level = 1 },
            { type = "list_item", text = "Beginning with realm maintenance this week, defeating Garrosh will now give you a chance to bonus roll for an extra piece of loot.", level = 2 },
            { type = "list_item", text = "Celestial Dungeons", level = 0 },
            { type = "list_item", text = "Kor'kron Arcweavers no longer ignore line of sight and Magistrike has had its damage reduced.", level = 1 },
            { type = "list_item", text = "Kor'kron Banners have had their health significantly reduced.", level = 1 },
            { type = "list_item", text = "The respawn rate of the Kor'kron forces has been adjusted to be every 2 hours (was 5 minutes).", level = 1 },
            { type = "list_item", text = "August Stone Clusters now cap at 200 (was 70).", level = 1 },
            { type = "list_item", text = "The Coffer of Celestial Chance now awards 50-60 Lesser Charms of Good Fortune (was 20-30).", level = 1 },
            { type = "hr" },
            { type = "h3", text = "June 12, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Fixed an issue that caused Darkmoon Faire to not properly run on the first Friday of every month.", level = 0 },
            { type = "list_item", text = "An extra Darkmoon Faire holiday will be available in Terrokkar Forest starting June 15 until June 22.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "June 10, 2026" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Siege of Orgrimmar", level = 0 },
            { type = "list_item", text = "Siegecrafter Blackfuse", level = 1 },
            { type = "list_item", text = "Saw Blades now deal damage to Automated Shredders.", level = 2 },
            { type = "h3", text = "Season of Discovery" },
            { type = "list_item", text = "Players may now disable or re-enable XP gains by speaking with Grendag Brightbeard in Ironforge in the Forlorn Cavern or the Valley of Strength in Orgrimmar.", level = 0 },
            { type = "dev_note", text = "There is a known issue where if you disable XP gains, this change does not persist after logging out and back in. We are temporarily removing the 1g cost for disabling and re-enabling XP gains while we investigate a fix for this issue.", level = 1 },
            { type = "hr" },
            { type = "h3", text = "June 9, 2026" },
            { type = "h3", text = "Delves" },
            { type = "list_item", text = "Valeera will no longer ignore Vile Cursed Toads when they attack you in a delve.", level = 0 },
            { type = "h3", text = "Dungeons" },
            { type = "list_item", text = "Darkflame Cleft", level = 0 },
            { type = "list_item", text = "Fixed an issue that could prevent the candle cart from progressing.", level = 1 },
            { type = "h3", text = "Quests" },
            { type = "list_item", text = "Fixed an issue where the quest “Overcoming the Unknown: Rage-Riddled Drifter” was not properly appearing for players.", level = 0 },
            { type = "list_item", text = "Fixed an issue that could prevent some characters from being able to complete \"Lost Legends\". Affected characters will need to abandon the quest \"Lost Legends\" and pick it back up from Zur'Ashar Kassameh in The Den in Harandar.", level = 0 },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Hilda Hornswaggle and other relevant NPCs should now be present for their daily quests in Ruins of Ogudei.", level = 0 },
            { type = "list_item", text = "Cooldown-reduction trinkets will continue to work while loading screens are active.", level = 0 },
            { type = "list_item", text = "Sylstrasza and Kyanite Stonetender should once again be present atop of Grommash Hold.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "June 5, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "If multiple players use a Crystalforged Darkrune at Shartuul's Transporter simultaneously, any player who does not take control of the Felguard will keep their Crystalforged Darkrune.", level = 0 },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Tyrannical Gladiator's Waistbands for Season 14 now correctly cost Honor.", level = 0 },
            { type = "list_item", text = "Nitro Boosts no longer send players upward in Scarlet Monastery.", level = 0 },
            { type = "list_item", text = "Players can now voluntarily exit the Highwind Albatross in Timeless Isle.", level = 0 },
            { type = "list_item", text = "Players should no longer be immediately removed from the Halfhill Noodle Time daily cooking scenario.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "June 3, 2026" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Reduced the gold costs of Transmog outfit and slots by 90%.", level = 0 },
            { type = "dev_note", text = "Patch 5.5.4 was released with these gold costs unintentionally set too high.", level = 1 },
            { type = "list_item", text = "Removed Prideful Gladiator gear that was temporarily, unintentionally rewarded from World Bosses.", level = 0 },
            { type = "list_item", text = "Fixed a bug causing Battle Fatigue to work incorrectly in PvP.", level = 0 },
            { type = "list_item", text = "Fixed a bug preventing Warforged Seals from having a rolling weekly cap as expected.", level = 0 },
            { type = "list_item", text = "Fixed a bug preventing players from mounting Spectral Gryphon or Spectral Wind Rider as intended.", level = 0 },
            { type = "list_item", text = "Fixed a bug that briefly prevented players on some realms from buying replacement cloaks or starting legendary quests or campaign quests.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "June 2, 2026" },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Death Knight", level = 0 },
            { type = "list_item", text = "Unholy", level = 1 },
            { type = "list_item", text = "Resolved an issue causing Unholy Aura and Forbidden Ritual to be canceled earlier than expected.", level = 2 },
            { type = "h3", text = "Items" },
            { type = "list_item", text = "Fixed an issue with the Darkmoon Dominion: Blood trinket proccing for multiple stats if they're all equally the lowest stat.", level = 0 },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Player versus Player", level = 0 },
            { type = "list_item", text = "Following an Arena match, the user interface now displays the pre-match Matchmaking Ratings (MMR) for each team.", level = 1 },
            { type = "dev_note", text = "Our goal is to provide more information, so that players can better contextualize their changing MMR.", level = 2 },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Classes", level = 0 },
            { type = "list_item", text = "Death Knight", level = 1 },
            { type = "list_item", text = "Blood", level = 2 },
            { type = "list_item", text = "Bloodworms again have avoidance of area-of-effect spells.", level = 3 },
            { type = "hr" },
            { type = "h3", text = "May 26, 2026" },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Demon Hunter", level = 0 },
            { type = "dev_note", text = "Aldrachi Reaver performance has been below its alternative Hero Talent options, so we’re buffing some of its effects to reduce the disparity.", level = 1 },
            { type = "list_item", text = "Havoc", level = 1 },
            { type = "list_item", text = "Death Sweep damage increased by 10%.", level = 2 },
            { type = "dev_note", text = "This resolves an issue from a previous update where Blade Dance damage was increased, but Death Sweep’s damage was not correctly updated to match. The base damage of Death Sweep is intended to be 30% more than that of Blade Dance.", level = 2 },
            { type = "list_item", text = "Aldrachi Reaver: Reaver’s Glaive damage increased by 15%.", level = 2 },
            { type = "list_item", text = "Aldrachi Reaver: Warblade’s Hunger damage increased by 55%.", level = 2 },
            { type = "list_item", text = "Aldrachi Reaver: Wounded Quarry now deals 30% of Physical damage to the target of your Reaver’s Mark (was 25%).", level = 2 },
            { type = "list_item", text = "Vengeance", level = 1 },
            { type = "list_item", text = "Aldrachi Reaver: Reaver’s Glaive damage increased by 30%.", level = 2 },
            { type = "list_item", text = "Aldrachi Reaver: Warblade’s Hunger damage increased by 55%.", level = 2 },
            { type = "list_item", text = "Aldrachi Reaver: Wounded Quarry now deals 25% of Physical damage to the target of your Reaver’s Mark (was 20%).", level = 2 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Feral", level = 1 },
            { type = "list_item", text = "All damage dealt increased by 4%.", level = 2 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Arcane", level = 1 },
            { type = "dev_note", text = "In addition to an overall damage buff, we’d like to get Sunfury’s damage closer to Spellslinger’s.", level = 2 },
            { type = "list_item", text = "All ability damage increased by 5%. Does not apply to PvP.", level = 2 },
            { type = "list_item", text = "Arcane Missiles damage increased by 10%. Does not apply to PvP.", level = 2 },
            { type = "list_item", text = "Sunfury: Burden of Power - Arcane Blast damage bonus increased to 30% (was 25%). Arcane Pulse damage bonus increased to 20% (was 15%).", level = 2 },
            { type = "list_item", text = "Fire", level = 1 },
            { type = "dev_note", text = "These changes are intended to increase Fire’s single target damage. The value of the increase should be comparable for all Hero Talent options.", level = 2 },
            { type = "list_item", text = "Pyroblast damage increased by 8%. Does not apply to PvP.", level = 2 },
            { type = "list_item", text = "Frostfire: Frostfire Bolt damage increased by 5%. Does not apply to PvP.", level = 2 },
            { type = "list_item", text = "Frost", level = 1 },
            { type = "dev_note", text = "Frostfire performance is farther behind Spellslinger than we’re happy with, so we’re boosting a number of its talents to increase their single target and AOE damage.", level = 2 },
            { type = "list_item", text = "Frostfire: Frostfire Bolt damage increased by 5%. Does not apply to PvP", level = 2 },
            { type = "list_item", text = "Frostfire: Duality - Pyroblast damage increased by 25%.", level = 2 },
            { type = "list_item", text = "Frostfire: Dualcasting Adept - Shatter damage bonus increased to 40% (was 15%).", level = 2 },
            { type = "list_item", text = "Frostfire: Heat Sink - Flurry damage bonus increased to 25% (was 10%).", level = 2 },
            { type = "list_item", text = "Frostfire: Blast Radius - Comet Storm damage bonus increased to 50% (was 20%).", level = 2 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Retribution", level = 1 },
            { type = "dev_note", text = "Herald of the Sun has been trailing behind Templar in overall throughput. To improve its output, we’re extending its effective damage window by granting an additional Dawnlight charge. We’re also aiming to further improve its AoE performance by increasing the duration extension provided by Divine Storm.", level = 2 },
            { type = "list_item", text = "Wake of Ashes now causes the next 3 Holy Power spending abilities to apply a Dawnlight (was 2).", level = 2 },
            { type = "list_item", text = "Endless Gleam now extends Dawnlight’s duration by an additional 0.5 seconds when Divine Storm strikes at least 2 Dawnlights (was 0.3 seconds).", level = 2 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "dev_note", text = "We’re reducing the mana costs of some core spell casts so Holy Priest can feel more comfortable casting Prayer of Healing and Flash Heal, particularly in raid settings.", level = 2 },
            { type = "list_item", text = "Flash Heal mana cost reduced by 8%.", level = 2 },
            { type = "list_item", text = "Benediction mana cost reduced by 8%.", level = 2 },
            { type = "list_item", text = "Prayer of Mending mana cost reduced by 8%.", level = 2 },
            { type = "list_item", text = "Prayer of Healing mana cost reduced by 8%.", level = 2 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "dev_note", text = "Deathstalker damage is below the other Hero Talent options for most content and damage profiles, especially for Assassination, and to the least degree for Subtlety single target output. Changes are targeted at improving Deathstalker’s total performance compared to each specialization’s alternative.", level = 1 },
            { type = "list_item", text = "Assassination", level = 1 },
            { type = "list_item", text = "Deathstalker: Deathstalker’s Mark damage increased by 30%.", level = 2 },
            { type = "list_item", text = "Deathstalker: Clear the Witnesses now increases Fan of Knives damage by 60% (was 40%).", level = 2 },
            { type = "list_item", text = "Deathstalker: Hunt Them Down damage increased by 25%.", level = 2 },
            { type = "list_item", text = "Deathstalker: Corrupt the Blood now increases Rupture damage by 20% (was 10%).", level = 2 },
            { type = "list_item", text = "Deathstalker: Darkest Night effect now increases Envenom damage by 35% (was 30%).", level = 2 },
            { type = "list_item", text = "Subtlety", level = 1 },
            { type = "list_item", text = "Deathstalker: Deathstalker’s Mark damage increased by 30%.", level = 2 },
            { type = "list_item", text = "Deathstalker: Clear the Witnesses now increases Shuriken Storm damage by 60% (was 40%).", level = 2 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "Elemental", level = 1 },
            { type = "list_item", text = "Farseer: Ancestral Spirits from the Farseer Hero Talent tree now benefit from the critical damage increase of the Elemental Fury talent.", level = 2 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "dev_note", text = "We’re adjusting the mana costs of some of Restoration Shaman’s basic spell casts to give them more room to spend mana on things like Chain Heal particularly in raid settings.", level = 2 },
            { type = "list_item", text = "The mana cost of Chain Heal, Healing Wave, and Riptide has been reduced by 5%.", level = 2 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "dev_note", text = "These change aim to improve Colossus’ performance in single target and Mountain Thane’s performance in AOE relative to other Hero Talent options.", level = 1 },
            { type = "list_item", text = "Arms", level = 1 },
            { type = "list_item", text = "Colossus: Practiced Strikes - Mortal Strike and Slam damage increased by 25% (was 15%). Does not apply to PvP.", level = 2 },
            { type = "list_item", text = "Fury", level = 1 },
            { type = "list_item", text = "Mountain Thane: Thunder Blast damage increased by 30%. Does not apply to PvP.", level = 2 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "list_item", text = "Colossus: Practiced Strikes - Shield Slam damage increased by 25% (was 15%). Does not apply to PvP.", level = 2 },
            { type = "list_item", text = "Mountain Thane: Thunder Blast damage increased by 30%. Does not apply to PvP.", level = 2 },
            { type = "h3", text = "Player versus Player" },
            { type = "list_item", text = "Death Knight", level = 0 },
            { type = "list_item", text = "Unholy", level = 1 },
            { type = "list_item", text = "San’layn: Vampiric Strike damage increased by 30% in PvP combat.", level = 2 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Balance", level = 1 },
            { type = "list_item", text = "Elune’s Chosen: Lunar Calling now increases Starfire damage by an additional 20% in PvP combat.", level = 2 },
            { type = "list_item", text = "Feral", level = 1 },
            { type = "list_item", text = "Druid of the Claw: Ravage damage increased by 20% in PvP combat.", level = 2 },
            { type = "list_item", text = "Evoker", level = 0 },
            { type = "list_item", text = "Preservation", level = 1 },
            { type = "dev_note", text = "Preservation has pulled ahead of the other healers partially due to their ability to withstand crowd control but also due to their raw healing output. We’re reducing some of their throughput capabilities and also the uptime on Nullifying Shroud to bring them in line.", level = 2 },
            { type = "list_item", text = "All healing reduced by 5% in PvP combat.", level = 2 },
            { type = "list_item", text = "Nullifying Shroud duration reduced to 3 seconds (was 4 seconds).", level = 2 },
            { type = "list_item", text = "Dream Breath instant healing reduced by 17% in PvP combat.", level = 2 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Survival", level = 1 },
            { type = "dev_note", text = "Survival has a strong burst window with Takedown, but outside of that, they are lacking. We’d like to reduce the heavy burst of Takedown and redistribute that power to compensate.", level = 2 },
            { type = "list_item", text = "Takedown damage reduced by 25% in PvP.", level = 2 },
            { type = "list_item", text = "Damage of all spells and abilities increased by 6% in PvP.", level = 2 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Fire", level = 1 },
            { type = "dev_note", text = "We’d like to increase Fire’s steady state damage by adjusting Fireball to reward casting, and Meteor has been harder to justify picking up than we would like in PvP.", level = 2 },
            { type = "list_item", text = "Fireball and Frostfire Bolt damage increased by 35% in PvP combat.", level = 2 },
            { type = "list_item", text = "Meteor direct damage increased by 30% in PvP combat.", level = 2 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "dev_note", text = "Holy Light’s mana cost is more restrictive in PvP than intended, so we’re adjusting Divine Favor to make its use less punishing long-term. Divine Favor now reduces the mana cost of Holy Light by 30% (was 10%) in PvP combat.", level = 2 },
            { type = "list_item", text = "Fixed an issue that caused Denounce to not scale its damage with level or with buffs such as Avenging Wrath. This is about a 90% increase to its baseline output.", level = 2 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "dev_note", text = "Protection Paladin’s damage capabilities have been higher than healthy for a spec with its utility.", level = 2 },
            { type = "list_item", text = "All damage reduced by 10% in PvP combat.", level = 2 },
            { type = "list_item", text = "Retribution", level = 1 },
            { type = "dev_note", text = "We’re adjusting Divine Exaction’s effectiveness to reduce Retribution’s burst window.", level = 2 },
            { type = "list_item", text = "Templar: Divine Exaction down to 75% (was 150%) in PvP combat.", level = 2 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "dev_note", text = "We’re reducing the mana cost of a few core spells for Holy Priest this week (see PvE changes for details) which is intended to help with healing in longer engagements. Additionally, Archon has felt weak compared to Oracle, so we’re targeting a buff to Halo to improve its viability.", level = 2 },
            { type = "list_item", text = "Archon: Halo damage and healing increased by 25% in PvP combat.", level = 2 },
            { type = "list_item", text = "Shadow", level = 1 },
            { type = "dev_note", text = "We feel Voidweaver is in a good position in PvP. Archon’s pressure is lacking in comparison, so we’re targeting some of its spells to improve its output.", level = 2 },
            { type = "list_item", text = "Archon: Halo damage and healing increased by 25% in PvP combat.", level = 2 },
            { type = "list_item", text = "Archon: Mind Flay Insanity damage increased by 25% in PvP combat.", level = 2 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "Elemental", level = 1 },
            { type = "dev_note", text = "Elemental is often relying on Ascendance for kills due to its high burst potential. These changes are intended to increase overall pressure while reducing reliance on cooldowns to score skills.", level = 2 },
            { type = "list_item", text = "Bloodlust and Heroism from Shamanism now increases haste by 15% (was 20%)", level = 2 },
            { type = "list_item", text = "Ascendance now increases Elemental Overload damage by 10% in PvP Combat (was 25%).", level = 2 },
            { type = "list_item", text = "Lava Burst damage increased by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Lightning Bolt damage increased by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Enhancement", level = 1 },
            { type = "dev_note", text = "Enhancement burst has been hard to react to during cooldowns due to a Maelstrom Weapon bug we’re fixing. In addition, we’re toning down the haste gained from Shamanism to reduce the cooldown pressure from Shaman DPS specializations.", level = 2 },
            { type = "list_item", text = "Bloodlust and Heroism from Shamanism now increases haste by 15% (was 20%) in PvP.", level = 2 },
            { type = "list_item", text = "Resolved an issue causing Malestrom Weapon spenders from Thorim’s Invocation during Doom Winds to deal more damage than intended.", level = 2 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Affliction", level = 1 },
            { type = "dev_note", text = "Hellcaller has underperformed compared to Soul Harvester and we would like to shrink that gap.", level = 2 },
            { type = "list_item", text = "Hellcaller: Blackened Soul damage increased by 35% in PvP combat.", level = 2 },
            { type = "list_item", text = "Hellcaller: Wither damage increased by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Hellcaller: Mark of Xavius now causes Blackened Soul to deal 4% increased damage per stack of Wither in PvP combat (was 2%).", level = 2 },
            { type = "list_item", text = "Demonology", level = 1 },
            { type = "dev_note", text = "For Demonology and Destruction, we’re pulling back on some of the previous reductions to Conflagrate and Ruination as they were proving to be a little heavy handed. We’re also bringing up the damage of core casts like Incinerate and Hand of Gul’dan to reward Warlocks more for successful casts.", level = 2 },
            { type = "list_item", text = "Hand of Gul’dan damage increased by 30% in PvP combat.", level = 2 },
            { type = "list_item", text = "Diabolist: Ruination damage increased by 100% in PvP combat.", level = 2 },
            { type = "list_item", text = "Destruction", level = 1 },
            { type = "list_item", text = "Incinerate damage increased by 30% in PvP combat.", level = 2 },
            { type = "list_item", text = "Conflagrate damage increased by 60% in PvP combat.", level = 2 },
            { type = "list_item", text = "Diabolist: Ruination damage increased by 100% in PvP combat.", level = 2 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "dev_note", text = "Berserker Roar’s duration has been overly disruptive. Decreasing it should open up more options when deciding how to handle its effect.", level = 1 },
            { type = "list_item", text = "Berserker Roar’s duration reduced to 5 seconds (was 10 seconds).", level = 1 },
            { type = "list_item", text = "Arms", level = 1 },
            { type = "dev_note", text = "Arms’ overall pressure output has been slightly higher than we would like, so we’re tweaking their damage down to land them in a healthier spot.", level = 2 },
            { type = "list_item", text = "All damage reduced by 3% in PvP combat.", level = 2 },
            { type = "hr" },
            { type = "h3", text = "May 22, 2026" },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Death Knight", level = 0 },
            { type = "list_item", text = "Unholy", level = 1 },
            { type = "list_item", text = "Resolved an issue causing Forbidden Ritual aura to remain permanently on the Death Knight.", level = 2 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "list_item", text = "Reduced the number of sounds and visuals that play when using the talent Flourish with Tranquility.", level = 2 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Discipline", level = 1 },
            { type = "list_item", text = "Master the Darkness can now be tracked in the cooldown manager.", level = 2 },
            { type = "h3", text = "Player versus Player" },
            { type = "list_item", text = "There is no longer a cap on the total number of Bloody Tokens a player may accumulate.", level = 0 },
            { type = "list_item", text = "Resolved an issue that could prevent players from earning Slayer's Rise Dominance while holding all bases.", level = 0 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "list_item", text = "Fixed an issue where Guardian of the Forgotten Queen could not be interrupted by some crowd control effects as intended.", level = 2 },
            { type = "hr" },
            { type = "h3", text = "May 19, 2026" },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Retribution", level = 1 },
            { type = "list_item", text = "Templar: Resolved an issue causing Hammer of Light to not cast properly in high haste situations.", level = 2 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Affliction", level = 1 },
            { type = "list_item", text = "Fixed an issue where Soul Swap would carry Unstable Affliction stacks when entering or exiting an instanced area.", level = 2 },
            { type = "h3", text = "Dungeons and Raids" },
            { type = "list_item", text = "March on Quel’Danas", level = 0 },
            { type = "list_item", text = "The Hall of Fame for players who have completed Mythic difficulty is now closed.", level = 1 },
            { type = "list_item", text = "Midnight Falls", level = 1 },
            { type = "list_item", text = "Fixed an issue causing The Dark Archangel to sometimes not cancel upon triggering the final phase on Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Heaven’s Glaives maximum duration reduced to 1 minute (was 2 minutes).", level = 2 },
            { type = "list_item", text = "Reduced the spread of Midnight Crystals on Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Starsplinter initial damage reduced by 20% on Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Criticality damage reduced by 20%.", level = 2 },
            { type = "h3", text = "Items and Rewards" },
            { type = "list_item", text = "There is no longer a cap on the amount of upgrade Crests that can be accumulated by each player.", level = 0 },
            { type = "h3", text = "Player versus Player" },
            { type = "list_item", text = "There is no longer a cap on the amount of Conquest that can be earned, for the rest of Season 1.", level = 0 },
            { type = "h3", text = "Quests" },
            { type = "list_item", text = "The repeatable “Legends of the Haranir” quests are now available to player-characters who belong to a Warband that includes a character who has completed the first-time versions of the quests, and they may now be obtained by more than one character in your warband per week.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "May 15, 2026" },
            { type = "h3", text = "Achievements" },
            { type = "list_item", text = "Reservation for One will now be granted to players who collect Mythic-tier fish meat multiple times in the same run.", level = 0 },
            { type = "list_item", text = "Additionally fixed issues with the Champion of Pahk creature in Abyss Anglers that caused it to disappear before players could catch it.", level = 1 },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Delves", level = 0 },
            { type = "list_item", text = "Nemesis Squads should no longer spawn under the world in Parhelion Plaza.", level = 1 },
            { type = "h3", text = "Decor Duel" },
            { type = "list_item", text = "Hiders can no longer swap with Enchanted Decoys.", level = 0 },
            { type = "h3", text = "Dungeons and Raids" },
            { type = "list_item", text = "The Voidspire", level = 0 },
            { type = "list_item", text = "A teleport pad now appears in the Isle of Quel'Danas for raid groups that used the raid shortcut and have bosses to defeat.", level = 1 },
            { type = "list_item", text = "Fallen-King Salhadaar", level = 1 },
            { type = "list_item", text = "Resolved an issue making the Broken Oath warning unmovable in Edit Mode.", level = 2 },
            { type = "h3", text = "Player versus Player" },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Beast Mastery", level = 1 },
            { type = "list_item", text = "Bestial Wrath now displays as important on enemy nameplates.", level = 2 },
            { type = "hr" },
            { type = "h3", text = "May 12, 2026" },
            { type = "h3", text = "Achievements" },
            { type = "list_item", text = "Abyss Anglers: Depth Grease no longer requires the Reinforced Joints upgrade.", level = 0 },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Death Knight", level = 0 },
            { type = "list_item", text = "Blood", level = 1 },
            { type = "dev_note", text = "We are looking at smoothing out the damage intake of Blood outside of their cooldown window by increasing the consistency and uptime of their Apex Talent. To further help these windows of high damage intake we are also increasing their Health and Death Strike healing.", level = 2 },
            { type = "list_item", text = "Dancing Rune Weapon grants 25% Parry (was 20%).", level = 2 },
            { type = "list_item", text = "Blood Fortification grants 40% Stamina (was 35%).", level = 2 },
            { type = "list_item", text = "Improved Death Strike healing increased to 15% (was 5%).", level = 2 },
            { type = "list_item", text = "Dance of Midnight grants Dancing Rune Weapon for 8 seconds (was 6 seconds).", level = 2 },
            { type = "list_item", text = "Dance of Midnight chance to proc increased to 12.5% (was 10%).", level = 2 },
            { type = "list_item", text = "Unholy", level = 1 },
            { type = "list_item", text = "Death and Decay can now be tracked in the cooldown manager.", level = 2 },
            { type = "list_item", text = "Demon Hunter", level = 0 },
            { type = "list_item", text = "Vengeance", level = 1 },
            { type = "dev_note", text = "Vengeance Demon Hunter’s baseline defenses are its most lacking, while cooldown availability and values are currently serving the spec well. As a result, we will be primarily targeting core values for Health and damage reduction, with an additional smaller increase specifically to Armor.", level = 2 },
            { type = "list_item", text = "Demonic Wards now reduces all damage taken by 12% (was 8%).", level = 2 },
            { type = "list_item", text = "Thick Skin now grants 55% increased Stamina (was 50%).", level = 2 },
            { type = "list_item", text = "Effectiveness of Mastery: Fel Blood increased by 20%.", level = 2 },
            { type = "list_item", text = "Void Reaver now causes Frailty to reduce damage taken by 5% (was 4%).", level = 2 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Guardian", level = 1 },
            { type = "list_item", text = "Thrash direct damage reduced by 25%.", level = 2 },
            { type = "list_item", text = "Elune’s Favored now heals for 15% of Arcane damage dealt (was 25%).", level = 2 },
            { type = "dev_note", text = "These changes aim to bring this build closer to its expected output: high-damage relative to other tanks, but not abnormally so. Recent previous adjustments to Guardian have made the Elune’s Chosen build stronger than intended. With this tuning, we’re choosing to not break the Elune’s Chosen build or require the Apex talent. We have further plans to update the Guardian Apex Talent in a future patch to give us more flexibility with it and alleviate some of the current pain points for Druids.", level = 2 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Marksmanship", level = 1 },
            { type = "list_item", text = "Corrected an issue where Explosive Shot applied from the Salvo talent did not properly grant Lock and Load from the Shrapnel Shot talent when applied.", level = 2 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "dev_note", text = "With these changes, we’re aiming to improve baseline durability for Protection Paladins by increasing passive effects which contribute to effective health. We’re also addressing on-demand survivability with adjustments to defensive cooldown coverage and strength.", level = 2 },
            { type = "list_item", text = "Blessing of Dusk reduces damage taken by up to 20%, increasing as your health decreases (was 10%).", level = 2 },
            { type = "list_item", text = "Sanctified Plates increases stamina by 7/15% (was 5/10%).", level = 2 },
            { type = "list_item", text = "Ardent Defender duration increased to 12 seconds (was 8 seconds).", level = 2 },
            { type = "list_item", text = "Ardent Defender now reduces damage taken by 30% (was 20%).", level = 2 },
            { type = "list_item", text = "Sentinel duration increased to 20 seconds (was 16 seconds).", level = 2 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "list_item", text = "Corrected an issue where Downpour would consume Nature's Swiftness and Ancestral Swiftness.", level = 2 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Diabolist: Fixed an issue where Diabolic Oculi would target creatures that are not in combat with their summoner.", level = 1 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "dev_note", text = "Protection melee damage mitigation is quite strong, but is a bit behind for magical attacks and damage-over-time effects. These changes are aimed at strengthening those areas as well as making it easier to maintain healthy Ignore Pain values.", level = 2 },
            { type = "list_item", text = "Fight Through Flames reduces magic damage taken by 6% (was 4%).", level = 2 },
            { type = "list_item", text = "Phalanx reduces damage enemies deal to you by 8% (was 5%).", level = 2 },
            { type = "list_item", text = "Ignore Pain effectiveness increased by 8%.", level = 2 },
            { type = "h3", text = "Delves" },
            { type = "list_item", text = "Light spores in Sunkiller Sanctum should no longer interrupt channeled spells.", level = 0 },
            { type = "h3", text = "Housing" },
            { type = "list_item", text = "Players who purchased the Roofus bundle can now buy additional copies of the decor in that bundle from promotional decor resupply vendors in Stormwind (Tuuran), Orgrimmar (Gabbi), and Silvermoon City (Dennia Silvertongue).", level = 0 },
            { type = "h3", text = "Items" },
            { type = "list_item", text = "Fixed an issue where the Dundun's Abundant Travel Method toy would teleport players to the incorrect location.", level = 0 },
            { type = "list_item", text = "Fixed an issue preventing weapons and trinkets crafted before 12.0.5 from being eligible for Ascendant Voidcore upgrades.", level = 0 },
            { type = "h3", text = "Prey" },
            { type = "list_item", text = "Removed the once per week restriction on Preferential Killing which generates a hunt with custom parameters. Players may complete Custom Hunts as often as desired after reaching rank 10 in the Season 1 Prey Journey, but subsequent Custom Hunts in a week give reduced rewards.", level = 0 },
            { type = "list_item", text = "Increased Prey hunt progress gained from completing World Quests, defeating Ambushes, delivering Ripostes, and interacting with Remnants of Anguish.", level = 0 },
            { type = "list_item", text = "Removed Hunter's Momentum from Hard and Nightmare mode Prey hunts.", level = 0 },
            { type = "list_item", text = "Significantly increased the number of the Coalescing Anguish spawns in the outdoor world.", level = 0 },
            { type = "h3", text = "Player versus Player" },
            { type = "list_item", text = "Significantly increased rating gains from completing 2v2, 3v3, and Solo Shuffle matches.", level = 0 },
            { type = "dev_note", text = "This adjustment is intended to meaningfully improve progression as the season continues to support healthier ladder movement. We'll continue to monitor rating distribution and make further adjustments if needed.", level = 0 },
            { type = "h3", text = "Void Assaults" },
            { type = "list_item", text = "Increased the progress gained for certain Void Assault steps.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "May 8, 2026" },
            { type = "h3", text = "Abyss Anglers" },
            { type = "list_item", text = "Resolved an issue in Abyss Anglers where some players weren't able to complete the Achievement Depth Grease , even if they had met the correct conditions.", level = 0 },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Monk", level = 0 },
            { type = "list_item", text = "Mistweaver", level = 1 },
            { type = "list_item", text = "Fixed an issue that caused Rushing Wind Kick's heal to sometimes fail.", level = 2 },
            { type = "h3", text = "Dungeons and Raids" },
            { type = "list_item", text = "Magisters Terrace", level = 0 },
            { type = "list_item", text = "Fixed an issue where sometimes Gemellus would fail to resume using abilities if a player died during Astral Grasp.", level = 1 },
            { type = "list_item", text = "Nexus-Point Xenas", level = 0 },
            { type = "list_item", text = "Fixed an issue causing Mana Batteries to appear as a neutral faction while casting Corespark Overload.", level = 1 },
            { type = "list_item", text = "The Voidspire", level = 0 },
            { type = "list_item", text = "Using the raid skip no longer causes players to automatically teleport when returning to the entrance.", level = 1 },
            { type = "h3", text = "Quests" },
            { type = "list_item", text = "Fixed an issue that prevented repeat play of \"The Story of the Cauldron of Echoes\".", level = 0 },
            { type = "list_item", text = "Resolved an issue where players could be blocked from accepting \"Rescue in the Shadows\" if they had completed \"Crypt in the Mist\" during the Zul'Aman campaign.", level = 0 },
            { type = "h3", text = "User Interface" },
            { type = "list_item", text = "Fixed a bug causing Wings of the Void to unintentionally appear in the Spellbook.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "May 6, 2026" },
            { type = "h3", text = "Abyss Anglers" },
            { type = "list_item", text = "Ka'bubb the capybara will now join your Abyss Anglers dives once you've earned the Certified Depthdiver", level = 0 },
            { type = "list_item", text = "Solved an issue in Abyss Anglers where some players couldn’t complete the Achievement Depth Grease , even if they had accomplished the correct conditions.", level = 0 },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "list_item", text = "Incarnation: Tree of Life's duration can now be tracked in the cooldown manager while talented into Reforestation without Incarnation: Tree of Life.", level = 2 },
            { type = "list_item", text = "Monk", level = 0 },
            { type = "list_item", text = "Brewmaster", level = 1 },
            { type = "list_item", text = "Fixed an issue where Flurry Strikes did not correctly generate threat.", level = 2 },
            { type = "list_item", text = "Fixed an issue where Vital Flame and Refreshing Drink incorrectly generated healing threat.", level = 2 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Affliction", level = 1 },
            { type = "list_item", text = "Fixed an issue where sometimes Wither would not replace Corruption.", level = 2 },
            { type = "list_item", text = "Soul Harvester: Fixed an issue where Sataiel's Volition would sometimes stop providing its Corruption modifier.", level = 2 },
            { type = "list_item", text = "Destruction", level = 1 },
            { type = "list_item", text = "Fixed an issue where Conflagration of Chaos would not increase the damage of Shadowburn.", level = 2 },
            { type = "h3", text = "Decor Duel" },
            { type = "list_item", text = "Groups may now queue into Decor Duel through the Group Finder.", level = 0 },
            { type = "h3", text = "Dungeons and Raids" },
            { type = "list_item", text = "Pit of Saron", level = 0 },
            { type = "list_item", text = "Risen Soldiers and Arcanist Cadavers can no longer be charmed.", level = 1 },
            { type = "list_item", text = "Ick and Krick", level = 1 },
            { type = "list_item", text = "Addressed an issue where Krick could fail to cast Get 'Em, Ick!", level = 2 },
            { type = "list_item", text = "Windrunner Spire", level = 0 },
            { type = "list_item", text = "Derelict Duo", level = 1 },
            { type = "list_item", text = "Added an arrow over the head of the player being aimed at by Latch's Heaving Yank (in addition to the existing dynamic marker showing the closet target within the path).", level = 2 },
            { type = "list_item", text = "Added a screen effect for when a player is standing in the path of Latch's Heaving Yank.", level = 2 },
            { type = "list_item", text = "Addressed a few situations where Latch's Heaving Yank could behave unexpectedly.", level = 2 },
            { type = "list_item", text = "Adjusted Kalis's teleport locations during Heaving Yank to leave more space between her and the edges of the arena.", level = 2 },
            { type = "list_item", text = "The Voidspire", level = 0 },
            { type = "list_item", text = "Corrected an issue where players were unable to teleport to The Approach after the instance has been soft reset.", level = 1 },
            { type = "h3", text = "Player versus Player" },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "Berserker Roar now displays as an important buff on enemy nameplates.", level = 1 },
            { type = "hr" },
            { type = "h3", text = "May 5, 2026" },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Death Knight", level = 0 },
            { type = "list_item", text = "Frost", level = 1 },
            { type = "list_item", text = "All damage increased by 5%. Does not affect PvP combat.", level = 2 },
            { type = "list_item", text = "Unholy", level = 1 },
            { type = "dev_note", text = "Unholy Death Knight is performing better than intended after recent bugfixes and the 12.0.5 changes.", level = 2 },
            { type = "list_item", text = "Magus of the Dead Shadow Bolt damage reduced by 15%. Does not affect PvP combat.", level = 2 },
            { type = "list_item", text = "Graveyard damage reduced by 15%. Does not affect PvP combat.", level = 2 },
            { type = "list_item", text = "Rider of the Apocalypse: Whitemane’s Epidemic damage reduced by 25%. This does not affect PvP combat.", level = 2 },
            { type = "list_item", text = "Rider of the Apocalypse: Trolbane’s Icy Fury damage reduced by 25%. Does not affect PvP combat.", level = 2 },
            { type = "list_item", text = "San’layn: Thrill of Blood now increases the damage of Dread Plague and Virulent Plague by 10% (was 5%).", level = 2 },
            { type = "list_item", text = "Demon Hunter", level = 0 },
            { type = "list_item", text = "Devourer", level = 1 },
            { type = "list_item", text = "All damage reduced by 3%.", level = 2 },
            { type = "list_item", text = "Annihilator: Voidfall Meteor damage reduced by 12%.", level = 2 },
            { type = "list_item", text = "Annihilator: Meteoric Rise damage bonus for Void Ray reduced to 10% (was 15%).", level = 2 },
            { type = "list_item", text = "Vengeance", level = 1 },
            { type = "list_item", text = "Thick Skin now increases Armor by 190% (was 150%).", level = 2 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Guardian", level = 1 },
            { type = "list_item", text = "Wild Guardian now clears when entering Arena and Battlegrounds, and when starting a Mythic+ dungeon or a raid encounter.", level = 2 },
            { type = "dev_note", text = "Guardian Druids have continued to overperform in single target contexts, while experiencing difficulties with threat and sustained damage outside of cooldowns. With these changes, we’re aiming to reduce burst potential and transfer some of that power into more reliable and consistent abilities to aid in generating and maintaining threat.", level = 2 },
            { type = "list_item", text = "Wild Guardian echo effectiveness reduced to 200% (was 300%).", level = 2 },
            { type = "list_item", text = "Red Moon damage reduced by 20%.", level = 2 },
            { type = "list_item", text = "Maul damage reduced by 15%.", level = 2 },
            { type = "list_item", text = "Raze damage reduced by 15%.", level = 2 },
            { type = "list_item", text = "Ravage damage reduced by 15%.", level = 2 },
            { type = "list_item", text = "Thrash direct damage increased by 200%.", level = 2 },
            { type = "list_item", text = "Thrash bleed damage increased by 100%.", level = 2 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "list_item", text = "All healing reduced by 3%. Does not apply to PvP combat.", level = 2 },
            { type = "list_item", text = "Everbloom heals for 20/40% of Lifebloom’s final heal (was 25/50%). Does not apply to PvP combat.", level = 2 },
            { type = "list_item", text = "Call of the Elder Druid's cooldown is now trackable in the cooldown manager.", level = 2 },
            { type = "list_item", text = "Evoker", level = 0 },
            { type = "list_item", text = "Augmentation", level = 1 },
            { type = "list_item", text = "All ability damage and pet damage reduced by 5%.", level = 2 },
            { type = "list_item", text = "Fixed an issue where Inferno’s Blessing damage was not properly modified by the specialization baseline passive. Inferno’s Blessing’s spell damage coefficient has been adjusted to compensate, so its effective damage will only be changed per the above adjustment.", level = 2 },
            { type = "list_item", text = "Scalecommander: Fixed an issue where Bombardment damage was not properly modified by the specialization’s baseline passives. Bombardment’s damage calculations have been adjusted to compensate.", level = 2 },
            { type = "dev_note", text = "Effective damage will be unchanged for Devastation and only reduced by 5% for Augmentation with the above adjustment.", level = 3 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Pack Leader: Corrected an issue where Howl of the Pack Leader would not summon a Boar or a Bear if the Kill Command that would summon the Boar or Bear killed your target.", level = 1 },
            { type = "list_item", text = "Pack Leader: Corrected an issue where the Pack Leader Boar's charge would not grant any of the Hogstrider damage bonuses or deal area damage if your Boar's primary target died before the Boar reached it.", level = 1 },
            { type = "list_item", text = "Beast Mastery", level = 1 },
            { type = "list_item", text = "All damage dealt by you and your pets increased by 4%. Does not apply to PvP combat.", level = 2 },
            { type = "list_item", text = "Corrected an issue where the Piercing Fangs talent did not apply a critical damage bonus to the bonus pet summoned from Nature's Ally.", level = 2 },
            { type = "list_item", text = "Marksmanship", level = 1 },
            { type = "list_item", text = "Rapid Fire damage increased by 20%. Does not affect PvP combat.", level = 2 },
            { type = "list_item", text = "Explosive Shot damage increased by 100%.", level = 2 },
            { type = "list_item", text = "Arcane Shot and Multi-Shot damage increased by 30%.", level = 2 },
            { type = "list_item", text = "Steady Shot damage increased by 100%.", level = 2 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Frost", level = 1 },
            { type = "list_item", text = "Shatter damage to the primary target reduced by 6%.", level = 2 },
            { type = "dev_note", text = "Bug fixes last week to Hand of Frost and Flurry provided a meaningful damage increase to Frost. This change is primarily intended to offset the boost from those fixes.", level = 3 },
            { type = "list_item", text = "Monk", level = 0 },
            { type = "list_item", text = "Brewmaster", level = 1 },
            { type = "list_item", text = "High Tolerance refunds 2/4 seconds of Purifying Brew’s cooldown when cast at Elevated Stagger (was 3/6 seconds).", level = 2 },
            { type = "list_item", text = "Zen State increases stagger effectiveness by 15%, based on missing health (was 20%).", level = 2 },
            { type = "list_item", text = "Fixed an issue where the Season 1 class set 4-piece Extra Kick could target unintended creatures.", level = 2 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "list_item", text = "Eternal Flame healing increased by 15%.", level = 2 },
            { type = "list_item", text = "Word of Glory healing increased by 15%.", level = 2 },
            { type = "list_item", text = "Light of Dawn healing increased by 15%.", level = 2 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "list_item", text = "Base armor increased by 10%.", level = 2 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Discipline", level = 1 },
            { type = "dev_note", text = "Our goal here is to slightly rein in Atonement’s healing contribution in raid environments while keeping its effectiveness in smaller group content.", level = 2 },
            { type = "list_item", text = "Atonement damage transfer has been increased to 30% (was 28%). Not applied to PvP combat.", level = 2 },
            { type = "list_item", text = "Atonement healing now decays more rapidly beyond 5 targets.", level = 2 },
            { type = "dev_note", text = "For example, when healing 20 injured allies with Atonement, it would previously be reduced by 50%. With the new scaling, it will be reduced by 60%.", level = 3 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "list_item", text = "All healing increased by 6%. Not applied to PvP combat.", level = 2 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "Outlaw", level = 1 },
            { type = "list_item", text = "All damage increased by 9%. Does not affect PvP combat.", level = 2 },
            { type = "list_item", text = "Trickster: Cloud Cover primary and secondary duration reduced to 6 seconds (was 10 seconds).", level = 2 },
            { type = "list_item", text = "Trickster: Cloud Cover now causes Fazed to stack 1 additional time (was 2).", level = 2 },
            { type = "list_item", text = "Trickster: No Scruples crit chance bonus increased to 12% (was 10%).", level = 2 },
            { type = "list_item", text = "Trickster: Additional stacks of Fazed granted by Cloud Cover no longer increase the magnitude of secondary effects, such as the damage reduction from the Smoke talent.", level = 2 },
            { type = "list_item", text = "Subtlety", level = 1 },
            { type = "list_item", text = "All damage increased by 7%. Does not affect PvP combat.", level = 2 },
            { type = "list_item", text = "Trickster: Cloud Cover primary and secondary duration reduced to 6 seconds (was 10 seconds).", level = 2 },
            { type = "list_item", text = "Trickster: No Scruples crit chance bonus increased to 12% (was 10%).", level = 2 },
            { type = "list_item", text = "Trickster: Additional stacks of Fazed granted by Cloud Cover no longer increase the magnitude of secondary effects, such as the damage reduction from the Smoke talent.", level = 2 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "Enhancement", level = 1 },
            { type = "dev_note", text = "Enhancement Shaman has been underperforming in both Raid and M+ content. With these changes, we’re aiming to increase throughput and help Stormbringer catch up to Totemic. We’re also resolving a bug, which would have a negative impact on performance, so we’re watching the results carefully.", level = 2 },
            { type = "list_item", text = "All ability damage increased by 5%.", level = 2 },
            { type = "list_item", text = "Auto attack damage increased by 10%.", level = 2 },
            { type = "list_item", text = "Resolved an issue causing Thorim’s Invocation to cast Lightning Bolt, Chain Lightning and Tempest at with more effectiveness than intended when cast below 10 Maelstrom Weapon.", level = 2 },
            { type = "list_item", text = "Stormbringer: Natural Gift now increases Nature damage of abilities by 6% (was 2%).", level = 2 },
            { type = "list_item", text = "Stormbringer: Voltaic Surge now increases the damage of Crash Lightning and Chain Lightning by 20% (was 10%).", level = 2 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Affliction", level = 1 },
            { type = "list_item", text = "Unstable Affliction damage increased by 20%.", level = 2 },
            { type = "list_item", text = "Seed of Corruption damage increased by 10%.", level = 2 },
            { type = "list_item", text = "Corruption damage increased by 20%.", level = 2 },
            { type = "dev_note", text = "This change does not affect Wither.", level = 3 },
            { type = "list_item", text = "Agony damage increased by 10%.", level = 2 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "dev_note", text = "These tuning changes are aimed at improving Warrior performance overall as well as compensating for damage lost due to the Deep Wounds bug fix last week. We will continue to monitor Warrior performance and make further adjustments as needed.", level = 1 },
            { type = "list_item", text = "Arms", level = 1 },
            { type = "list_item", text = "Execute damage increased by 20%.", level = 2 },
            { type = "list_item", text = "Overpower damage increased by 20%.", level = 2 },
            { type = "list_item", text = "Slayer: Slayer’s Strike damage increased by 40%.", level = 2 },
            { type = "list_item", text = "Slayer: Reap the Storm damage increased by 30%.", level = 2 },
            { type = "list_item", text = "Fury", level = 1 },
            { type = "list_item", text = "All damage increased by 5%.", level = 2 },
            { type = "list_item", text = "Execute damage increased by 20%.", level = 2 },
            { type = "list_item", text = "Raging Blow damage increased by 20%.", level = 2 },
            { type = "list_item", text = "Slayer: Slayer’s Strike damage increased by 40%.", level = 2 },
            { type = "list_item", text = "Slayer: Reap the Storm damage increased by 30%.", level = 2 },
            { type = "list_item", text = "Mountain Thane: Ground Current damage increased by 50%.", level = 2 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "list_item", text = "Execute damage increased by 20%.", level = 2 },
            { type = "list_item", text = "Mountain Thane: Thunder Blast damage increased by 30%.", level = 2 },
            { type = "list_item", text = "Mountain Thane: Ground Current damage increased by 50%.", level = 2 },
            { type = "h3", text = "Decor Duel" },
            { type = "list_item", text = "Fixed a bug with the Enchanted Hourglass where the timer would get stuck at 1 second.", level = 0 },
            { type = "list_item", text = "The Enchanted Hourglass can now only be interacted with by the hourglass's owner.", level = 0 },
            { type = "h3", text = "Dungeons and Raids" },
            { type = "list_item", text = "Pit of Saron", level = 0 },
            { type = "list_item", text = "Addressed an issue where Scourgelord Tyrannus could jump out of the playspace and be unable to return.", level = 1 },
            { type = "list_item", text = "Skyreach", level = 0 },
            { type = "list_item", text = "Addressed an issue where Richocheting Chakram can damage pets.", level = 1 },
            { type = "list_item", text = "Amirdrassil, the Dream's Hope", level = 0 },
            { type = "list_item", text = "Addressed an issue that could block progression after defeating Larodar.", level = 1 },
            { type = "list_item", text = "The Voidspire", level = 0 },
            { type = "list_item", text = "Crown of the Cosmos", level = 1 },
            { type = "list_item", text = "Alleria health reduced by 5% in Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Alleria’s berserk timer increased by 15 seconds in Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Demiar, Morium, and Vorelus health in Stage One reduced by 10% in Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Alleria’s energy generation rate in Stage Two reduced by 10% in Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Rift Simulacrum health reduced by 10% in Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Demiar, Morium, and Vorelus energy generation rate in Stage Three reduced by 13% in Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Rift Simulacrum energy generation rate in Stage Two and Three reduced by 13% in Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Spawn time between Rift Simulacrum and Cosmic Portal increased slightly in Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Voidstalker Sting targets 10% fewer players in Stage Three.", level = 2 },
            { type = "list_item", text = "Silverstrike Ricochet width increased to 5 yards (was 4 yards) in Mythic difficulty to match other difficulties.", level = 2 },
            { type = "list_item", text = "March on Quel’Danas", level = 0 },
            { type = "list_item", text = "Belo’ren, Child of Al’ar", level = 1 },
            { type = "list_item", text = "Rebirth is now a 40 second cast on all difficulties (was 30 seconds).", level = 2 },
            { type = "list_item", text = "Reduced the knockback on Light and Void Edict on all difficulties.", level = 2 },
            { type = "list_item", text = "Midnight Falls", level = 1 },
            { type = "list_item", text = "Midnight Crystal health reduced by 5% on Mythic difficulty.", level = 2 },
            { type = "dev_note", text = "The following adjustments are aimed at reducing difficulty for smaller groups, with the greatest reductions applying to 10-player groups. These affect Raid Finder, Normal, and Heroic difficulties.", level = 2 },
            { type = "list_item", text = "Midnight Crystal health reduced by up to 20% in smaller group sizes.", level = 2 },
            { type = "list_item", text = "Cosmic Fracture cast time increased to 14 seconds (was 12 seconds).", level = 2 },
            { type = "list_item", text = "Eclipsed damage reduced by up to 20% in smaller group sizes.", level = 2 },
            { type = "list_item", text = "Starsplinter cast frequency reduced to every 1.3 seconds on Heroic difficulty (was every 1 second).", level = 2 },
            { type = "list_item", text = "Overkill Current damage reduced by 20%.", level = 2 },
            { type = "h3", text = "Enemies and NPCs" },
            { type = "list_item", text = "Rare enemies in Ritual Sites no longer scale incorrectly while in a party.", level = 0 },
            { type = "h3", text = "Items" },
            { type = "list_item", text = "Permafrost Essence now provides 59% less critical strike.", level = 0 },
            { type = "h3", text = "Player versus Player" },
            { type = "dev_note", text = "The pace of PvP combat is a little too fast right now, resulting in quick kills from burst damage. We’re increasing player health in PvP combat to slow this down slightly and give players more time to react.", level = 0 },
            { type = "list_item", text = "Gladiator’s Distinction (PvP trinket set bonus) now increases player Stamina by an additional 5%.", level = 0 },
            { type = "list_item", text = "Voidstone Shielding Array absorption is reduced by 50% in PvP combat.", level = 0 },
            { type = "list_item", text = "Demon Hunter", level = 0 },
            { type = "list_item", text = "Devourer", level = 1 },
            { type = "dev_note", text = "Devourer’s ability to burst enemies down is a little too high.", level = 2 },
            { type = "list_item", text = "Void-Scarred: Voidsurge damage reduced by 20% in PvP combat.", level = 2 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Balance", level = 1 },
            { type = "dev_note", text = "Overall, Balance Druid is performing reasonably well, with the notable exception of Starsurge feeling underwhelming. We’re increasing Starsurge damage to give Balance more opportunities to contribute single-target burst.", level = 2 },
            { type = "list_item", text = "Starsurge damage increased by 18% in PvP combat.", level = 2 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Beast Mastery", level = 1 },
            { type = "list_item", text = "All damage dealt by you and your pets reduced by 3% in PvP combat.", level = 2 },
            { type = "list_item", text = "Marksmanship", level = 1 },
            { type = "dev_note", text = "We reduced Marksmanship damage in a recent hotfix, but those changes were too aggressive. We’re pulling back on some of the reductions to Black Arrow and overall damage to bring Marksmanship back up to a reasonable spot.", level = 2 },
            { type = "list_item", text = "Black Arrow damage increased by 11% in PvP combat.", level = 2 },
            { type = "list_item", text = "All damage increased by 5% in PvP combat.", level = 2 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Arcane", level = 1 },
            { type = "dev_note", text = "Arcane is behind the other Mage specializations, so we’re increasing the damage of some of their core spells. These are the more difficult spells to fully channel, so we’d like them to feel more rewarding when you do cast them.", level = 2 },
            { type = "list_item", text = "Arcane Blast damage increased by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Arcane Missile damage increased by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Fire", level = 1 },
            { type = "dev_note", text = "Fire, particularly Sunfury, is able to deal significant burst during their Combustion windows. We’d like to reduce that with that caveat that casting Fireball should still feel rewarding.", level = 2 },
            { type = "list_item", text = "Pyroblast damage reduced by 6% in PvP combat.", level = 2 },
            { type = "list_item", text = "Fireball damage increased by 80% in PvP combat.", level = 2 },
            { type = "list_item", text = "Sunfury: Codex of the Sunstriders now increases spell damage during Combustion by 1% for each Spellfire Sphere consumed in PvP combat (was 2%).", level = 2 },
            { type = "list_item", text = "Frost", level = 1 },
            { type = "list_item", text = "Ray of Frost damage reduced by 10% in PvP combat.", level = 2 },
            { type = "list_item", text = "Monk", level = 0 },
            { type = "list_item", text = "Brewmaster", level = 1 },
            { type = "list_item", text = "All damage reduced by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "list_item", text = "Mana regeneration is now reduced by 35% in PvP combat (was 45%).", level = 2 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "list_item", text = "Templar: Divine Exaction now causes Divine Toll to cast 2 additional times at 75% effectiveness in PvP combat (was 150%).", level = 2 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Shadow", level = 1 },
            { type = "dev_note", text = "Shadow’s consistent damage over time is quite effective, but their single target spells are lower than intended. We’re increasing Shadow Word: Madness and Mind Blast damage to help them contribute single target burst a bit more effectively.", level = 2 },
            { type = "list_item", text = "Shadow Word: Madness damage increased by 25% in PvP combat.", level = 2 },
            { type = "list_item", text = "Mind Blast and Void Blast damage increased by 20% in PvP combat.", level = 2 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "Outlaw", level = 1 },
            { type = "dev_note", text = "Outlaw’s damage ended up being quite high after recent adjustments, particularly Between the Eyes with patch 12.0.5. We’re reducing that along with some reductions to Cloud Cover for both PvE and PvP.", level = 2 },
            { type = "list_item", text = "Between the Eyes damage reduced by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "All ability damage reduced by 5%.", level = 2 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "list_item", text = "Healing Wave healing increased by 10% in PvP combat.", level = 2 },
            { type = "list_item", text = "Riptide healing increased by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Destruction", level = 1 },
            { type = "list_item", text = "All damage increased by 5% in PvP combat.", level = 2 },
