            { type = "list_item", text = "Fixed an issue where Titan's Gift and Titanic Wrath were not increasing the damage of the final few ticks of Disintegrate for Preservation and Devastation Evokers.", level = 1 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "list_item", text = "All damage dealt increased by approximately 12%.", level = 2 },
            { type = "dev_note", text = "Restoration shamans were intended to gain a 30% damage increase with the release of patch 12.0.5, but an error resulted in them gaining about half of that amount. This 12% increase brings them up to a total of +30% damage when compared to before patch 12.0.5.", level = 2 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Affliction", level = 1 },
            { type = "list_item", text = "Fixed an issue where Fatal Echoes would consume a Soul Shard when activated.", level = 2 },
            { type = "list_item", text = "Fixed an issue where Unstable Affliction would consume all stacks of Shard Instability.", level = 2 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "Arms", level = 1 },
            { type = "list_item", text = "Slams from Fervor of Battle which critically strike will now correctly trigger Mortal Wounds.", level = 2 },
