            { type = "list_item", text = "Imperator Pertinax should no longer die easily during the Eversong Void Incursion.", level = 0 },
            { type = "list_item", text = "Fixed a bug that could prevent some players who were properly in combat with the Void-Corrupted creature from receiving credit toward the Cosmic Slayer achievement.", level = 0 },
