            { type = "list_item", text = "Professions", level = 0 },
            { type = "list_item", text = "Fixed a bug causing players to get a blank window when fishing.", level = 1 },
            { type = "list_item", text = "Fixed a bug that resulted in players being able to learn multiple Alchemy specializations.", level = 1 },
            { type = "list_item", text = "Players who have misplaced Recipe: Banana Infused Rum or Tablet of Ren Yun can now purchase a replacement from Sungshin Ironpaw in Halfhill.", level = 1 },
