            { type = "list_item", text = "Bloodworms again have avoidance of area-of-effect spells.", level = 3 },
            { type = "hr" },
            { type = "h3", text = "February 20, 2026" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "The 4-piece damage Tier 15 set is no longer removed when the player changes stances.", level = 1 },
            { type = "list_item", text = "The 4-piece damage Tier 15 set is now applied to the player even if they cast Recklessness while in Defensive Stance, but it does not provide any effect and will read as granting 0% increased critical strike chance.", level = 1 },
            { type = "list_item", text = "The 4-piece damage Tier 15 set now updates dynamically based on the player’s stance. If the player enters Defensive Stance from Battle or Berserker, the buff is set to 0% instead of removed. If the player enters Battle or Berserker Stance from Defensive Stance, the buff is set back to 35% instead of removed.", level = 1 },
            { type = "h3", text = "February 12, 2026" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Gurthalak, Voice of the Deeps now has a 55-second cooldown when it is activated and removes all active tentacles when the weapon is unequipped.", level = 0 },
            { type = "list_item", text = "Dragon Pillar Toys can no longer be summoned near portals created by NPCs.", level = 0 },
            { type = "h3", text = "February 3, 2026" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "dev_note", text = "With today’s weekly maintenance, we’re removing some temporary power increases that were made to specs at the beginning of MoP Classic. This is a necessary step before we move to the next MoP patch, “Escalation”. These changes only affect servers where the Throne of Thunder is active, and do not impact PvP.", level = 0 },
            { type = "list_item", text = "Classes", level = 0 },
            { type = "list_item", text = "Mage", level = 1 },
            { type = "list_item", text = "Fire", level = 2 },
            { type = "list_item", text = "Combustion now provides an additional 20% of Ignite damage on the target (was 50%).", level = 3 },
            { type = "list_item", text = "Warlock", level = 1 },
            { type = "list_item", text = "Affliction", level = 2 },
            { type = "list_item", text = "Reverted the 10% increase to Malefic Grasp’s DoT.", level = 3 },
            { type = "list_item", text = "Reverted the 15% increase to Malefic Grasp’s damage.", level = 3 },
            { type = "list_item", text = "Reverted the 20% incrase to Drain Soul’s DoT.", level = 3 },
            { type = "list_item", text = "Reverted the 20% increase to Drain Soul’s DoT.", level = 3 },
            { type = "list_item", text = "Demonology", level = 2 },
            { type = "list_item", text = "Reverted the 25% increase to Doom.", level = 3 },
            { type = "list_item", text = "Reverted the 10% increase to Soul Fire.", level = 3 },
            { type = "list_item", text = "Hunter", level = 1 },
            { type = "list_item", text = "Ranged attack power from the Legendary Meta Gem Capacitive Primal Diamond increased by 100%.", level = 2 },
            { type = "dev_note", text = "This adjustment is a separate tuning effort that applies to all Hunter specs.", level = 2 },
            { type = "h3", text = "December 16, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Mogu’shan Vaults, Heart of Fear, and Terrace of Endless Spring now have zone wide debuffs applied to all enemy creatures that players can toggle off if they wish to increase the difficulty to its original level. This debuff starts at 5% and will increase every 2 weeks up to a total of 30%.", level = 0 },
            { type = "list_item", text = "Flurky can now be upgraded to rare quality with a Flawless Battle-Stone.", level = 0 },
            { type = "list_item", text = "Theldurin’s Fist is now correctly mirrored when equipped or transmogrified in the off-hand slot.", level = 0 },
            { type = "list_item", text = "Fixed an issue that was causing the Abominable Greench’s Stolen Treats to not grant quest credit.", level = 0 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Glyph of Focused Mending for Priests shoud now work correctly and is improved. If it can’t find one of the original targets to bounce to, it will no longer fade like it did previously, but instead find a new target.", level = 1 },
            { type = "list_item", text = "While in an Arena or Battleground, Prayer of Mending no longer incorrectly refreshes Renew while in Chakra: Serenity.", level = 1 },
            { type = "list_item", text = "Renews refreshed while Chakra: Serenity is active now correctly refresh to the maximum Duration + 1 tick (was refreshing to the maximum Duration).", level = 1 },
            { type = "list_item", text = "Renews refreshed while Chakra: Serenity is active and Glyph of Renew is active, now correctly do not count the -3 seconds from the Glyph when refreshing the duration of the Renew.", level = 1 },
            { type = "dev_note", text = "This is 15 seconds in Arenas and Battlegrounds, and 18 seconds outside of arenas and battlegrounds. This is how the Glyph functioned in patch 5.4.8, so we’re restoring that behavior.", level = 2 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Warlocks will no longer automatically revive their pets at the start of a Challenge Mode Dungeon, if they have an active Grimoire of Sacrifice.", level = 1 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "Warriors will now correctly get Rage when struck by Rampage on the Megaera encounter.", level = 1 },
            { type = "p", text = "–" },
            { type = "h3", text = "November 26, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Armsmaster Holinka and Roo Desvin now correctly sell the Malevolent Gladaitor’s Wyrmhide set.", level = 0 },
            { type = "h3", text = "November 14, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Glory of the Pandaria Raider no longer requires I Heard You Like Amber .", level = 0 },
            { type = "h3", text = "November 11, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Death Knight", level = 0 },
            { type = "list_item", text = "Frost", level = 1 },
            { type = "list_item", text = "Fixed a bug where Blood Tap with Death Siphon could provide an unintended extra invisible rune.", level = 2 },
            { type = "list_item", text = "Unholy", level = 1 },
            { type = "list_item", text = "Summon Gargoyle will no longer cancel casts of Gargoyle Strike and will now smoothly cast them back-to-back.", level = 2 },
            { type = "list_item", text = "Summon Gargoyle’s Gargoyle Strike attack can no longer go below a 0.5 second cast time.", level = 2 },
            { type = "list_item", text = "Summon Gargoyle will now cast a maximum of 25 Gargoyle Strikes and then depart.", level = 2 },
            { type = "list_item", text = "Shaman", level = 1 },
            { type = "list_item", text = "Healing Tide Totem and Healing Stream Totem will now correctly gain critical strike chance on their spells based on the casting Shaman’s Intellect.", level = 2 },
            { type = "list_item", text = "Warlock", level = 1 },
            { type = "list_item", text = "The Immolate from Fire and Brimstone will now correctly work with Pandemic when used on a group of enemies, causing all active Immolates from Fire and Brimstone to gain the correct duration when refreshed.", level = 2 },
            { type = "h3", text = "November 7, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Using Preserved Holly will no longer incorrectly change the movement speed of the player’s mount.", level = 0 },
            { type = "list_item", text = "The Macabre Marionette Pet should now show up in the Battle Pet Journal.", level = 0 },
            { type = "h3", text = "October 31, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Vampiric Embrace once again correctly splits the healing it does across targets.", level = 0 },
            { type = "list_item", text = "Corrected an issue where a small number of Paladins, Death Knights, and Shamans were simultaneously benefiting from all three of their class’s armor specialization bonuses.", level = 0 },
            { type = "list_item", text = "Fixed a bug that prevented encounters in instanced content from previous expansions from dropping gold as intended.", level = 0 },
            { type = "h3", text = "October 20, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Amber Shaper Un’sok will no longer prefer older characters when casting Reshape Life.", level = 0 },
            { type = "h3", text = "October 13, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Xuen no longer transfers Vengeance to the Brewmaster Monk at an increased rate while a damage reduction effect is active.", level = 0 },
            { type = "h3", text = "October 7, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Players can now upgrade the gear obtained from the Dominance Offensive and Operation: Shieldwall factions.", level = 0 },
            { type = "list_item", text = "The Empowering Flames debuff no longer persists on players when they are not inside of an active Empowering Flames area.", level = 0 },
            { type = "list_item", text = "Players can now start War Games for Tol’viron Arena and The Tiger’s Peak.", level = 0 },
            { type = "h3", text = "September 24, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Roo Desvin and Armsmaster Holinka now offer Leather armor for Honor, as expected.", level = 0 },
            { type = "list_item", text = "Fixed an issue that prevented level 89 characters from queueing for holiday bosses via the Random Dungeon Finder tool.", level = 0 },
            { type = "list_item", text = "Darna Honeybock and the quest “Save Brewfest!” have been removed.", level = 0 },
            { type = "list_item", text = "The requirement for the “A Test of Valor” quest has been reduced to 1600 Valor Points earned (was 3000).", level = 0 },
            { type = "dev_note", text = "This change did not update the text of the quest and the achievement. Those texts in-game will be updated at a later date. Currency conversions such as (August Stone Fragments -to- Valor Points) do not count towards the requirement to earn 1600 Valor Points.", level = 1 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "Storm Bolt’s off-hand damage is now correctly penalized by Dual Wield.", level = 1 },
            { type = "list_item", text = "Crazed Berserker auto-attack damage increased to 35% (was 20%).", level = 1 },
            { type = "h3", text = "September 12, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Players should no longer be prompted for an additional bonus roll when zoning into Terrace of Endless Spring.", level = 0 },
            { type = "list_item", text = "Touch of Sha should no longer target players affected by Spirit of Redemption.", level = 0 },
            { type = "list_item", text = "The following cooldowns will now reset during the Sha of Fear heroic transition: Vigilance, Holy Avenger, Light’s Hammer, Execution Sentence, Spectral Guise, Death’s Advance, Gorefiend’s Grasp, Remorseless Winter, Astral Shift, Windwall Totem, Totemic Projection, Dark Regeneration, Demonic Breath, Sacrificial Pact, Dark Bargain, Blood Horror, Unbound Will, Grimoire of Service Imp / Voidwalker / Succubus / Felhunter / Felguard / Incubus, Mannoroth’s Fury, Invoke Xuen, Diffuse Magic, Dampen Harm, Summon Black Ox Statue, Displacer Beast, Mass Entanglement, Disorienting Roar, Ursol’s Vortex, Heart of the Wild, and Purgatory.", level = 0 },
            { type = "h3", text = "September 9, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Death Knight", level = 0 },
            { type = "list_item", text = "Death Knights who change specialization to Frost while a Death Rune is active over one of their Blood Runes should no longer lose their permanent Death Rune.", level = 1 },
            { type = "h3", text = "September 4, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Mogu’shan Vaults", level = 0 },
            { type = "list_item", text = "Force of Nature from Balance, Guardian, and Feral Druids will now correctly be able to attack Elegon on Heroic difficulty.", level = 1 },
            { type = "list_item", text = "Dancing Rune Weapon should now always correctly copy the Death Knight’s abilities used against Elegon on Heroic difficulty.", level = 1 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Balance", level = 1 },
            { type = "list_item", text = "Arcane and Nature damage increase in Moonkin Form increased to 35% (was 25%).", level = 2 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "Combat", level = 1 },
            { type = "list_item", text = "Shallow Insight’s damage increase raised to 20% (was 10%).", level = 2 },
            { type = "list_item", text = "Moderate Insight’s damage increase raised to 30% (was 20%).", level = 2 },
            { type = "list_item", text = "Deep Insight’s damage increase raised to 40% (was 30%).", level = 2 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Destruction Warlocks should no longer incorrectly lose their Embers on encounter start if they cast a non-Fire and Brimstone Immolate to pull the boss.", level = 1 },
            { type = "h3", text = "September 2, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Items purchased from the Avatar of the August Celestials can now be refunded.", level = 0 },
            { type = "list_item", text = "The guild achievements Mogu’shan Vaults: The Heroic: Will of the Emperor and Heart of Fear: The Heroic: Grand Empress Shek’zeer are now earnable in 10-player difficulty.", level = 0 },
            { type = "list_item", text = "August Stone Fragments can now be held up to a maximum quantity of 70 (was 55).", level = 0 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Druids’ prior shapeshift forms are now correctly canceled by Amber-shaper Un’sok’s Reshape Life.", level = 1 },
            { type = "list_item", text = "Monk", level = 0 },
            { type = "list_item", text = "Chi Torpedo should no longer have circumstances where it can deal its damage or healing more than once to targets.", level = 1 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "list_item", text = "Sacred Shield will no longer absorb for an inflated amount after Crusader Strike has been cast.", level = 2 },
            { type = "list_item", text = "Player versus Player", level = 0 },
            { type = "list_item", text = "In 2v2 Arenas, every Shadow Sight after the first one has an increased duration of 5 seconds.", level = 1 },
            { type = "dev_note", text = "The Shadow Sight debuffs in Arenas were originally intended to allow for play against those who would delay or stall games using Stealth classes. With the current state of Subterfuge and other abilities in Mists of Pandaria, it has become clear that Shadow Sight behavior is not fulfilling its intended purpose. This change results in Shadow Sight lasting 15 seconds the first time it is picked up, and then 20 seconds, the second time, and then 25 seconds the third time, and so on.", level = 2 },
            { type = "h3", text = "August 26, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "When exiting an Arena, players’ Mana is no longer set to 0.", level = 0 },
            { type = "list_item", text = "Heart of Fear", level = 0 },
            { type = "list_item", text = "Fixed an issue that caused Blade Lord Ta’yak’s Wind Step ability to fail to apply the debuff.", level = 1 },
            { type = "list_item", text = "Fixed a bug causing Holy Paladins to fail to be treated as melee by some abilities after using Crusader Strike.", level = 1 },
            { type = "list_item", text = "Arms Warriors’ Sweeping Strikes no longer deal 100% increased damage to Garalon’s body when striking a Leg.", level = 1 },
            { type = "dev_note", text = "In Original Mists of Pandaria, during the first week of Heart of Fear Heroic difficulty, a Garalon hotfix addressed Sweeping Strikes, Blade Flurry, and similar effects. This was later superseded by changes made to Sweeping Strikes in patch 5.4, when Garalon was no longer the most relevant content. This fix returns Sweeping Strikes to its original behavior for Garalon’s body.", level = 2 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "list_item", text = "Subtlety", level = 1 },
            { type = "list_item", text = "Sanguinary Veins bonus damage reduced to 40% (was 50%).", level = 2 },
            { type = "dev_note", text = "A bug fix made right before the release of Heart of Fear addressed a situation where multiple rogues in a group were constantly removing this damage increase from each other and not benefitting from it. The bug was pulling down average Subtlety performance, and since the correction, things got a little out of hand. This may display an incorrect value between 40/45/50%, so to be clear, 40% is the intended value.", level = 3 },
            { type = "h3", text = "August 20, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "The achievement Spreading the Warmth can now be completed.", level = 0 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Balance", level = 1 },
            { type = "list_item", text = "Dream of Cenarius now correctly applies the Eclipse state without delay.", level = 2 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Felhunters and Observers no longer cast their spell lock ability while being out of line-of-sight of their target", level = 1 },
            { type = "list_item", text = "Summon Incubus is once again available.", level = 1 },
            { type = "list_item", text = "Added Grimoire of Service Incubus.", level = 1 },
            { type = "list_item", text = "Added Grimoire of Supremacy Archincubus.", level = 1 },
            { type = "list_item", text = "Shadow Bolt will now correctly add stacks of Molten Core when the target is below 25%.", level = 1 },
            { type = "dev_note", text = "Previously Shadow Bolt was only adding an initial stack and could not contribute to more stacks. This also means that Touch of Chaos will add stacks of Molten Core.", level = 2 },
            { type = "list_item", text = "Player versus Player", level = 0 },
            { type = "list_item", text = "In the Dalaran Sewers Arena, Priests can no longer place Lightwells in areas that other players cannot reach.", level = 1 },
            { type = "h3", text = "August 14, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Galleon now respawns every 30 minutes (was 1-2 hours).", level = 0 },
            { type = "list_item", text = "Avatar of the August Celestial’s vendor lists cleaned up substantially.", level = 0 },
            { type = "dev_note", text = "Players should no longer see armor pieces that do not correspond to their best armor type, or items that provide a primary stat that none of their class specializations utilize", level = 1 },
            { type = "list_item", text = "Celestial Dungeons", level = 0 },
            { type = "list_item", text = "Clearing a dungeon on Celestial difficulty now rewards the Heroic achievement.", level = 1 },
            { type = "list_item", text = "Blessing of Niuzao: Oxen Fortitude Strength, Agility, and Intellect per stack increased to 5%, now lasts 45 seconds, and can proc every 2 seconds.", level = 1 },
            { type = "list_item", text = "Blessing of Xuen: Xuen’s Ferocity scaling with Attack Power increased, and the damage loss per jump reduced to 5% per jump (was 25%).", level = 1 },
            { type = "list_item", text = "Blessing of Yu’lon: Serpent’s Jadefire periodic damage reduced and its scaling with Spell Power increased.", level = 1 },
            { type = "list_item", text = "Blessing of Chi-Ji: Blazing Song periodic damage reduced and its scaling per Spell Power increased.", level = 1 },
            { type = "list_item", text = "The visual for Blazing Song has been color shifted to green to make its intended behavior more clear.", level = 1 },
            { type = "h3", text = "August 13, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "August Stone Fragments held are now capped at 55 (was 45).", level = 0 },
            { type = "list_item", text = "In Rated Battlegrounds, non-tanks holding that flag now take 20% increased damage, as intended (was 25%).", level = 0 },
            { type = "list_item", text = "Fixed a bug preventing the Exalted Reputations achievements from progressing with MoP reputations.", level = 0 },
            { type = "list_item", text = "“Paint It Red” and “Unleash Hell” no longer auto-complete, and must be completed as originally intended.", level = 0 },
            { type = "list_item", text = "Celestial Dungeons", level = 0 },
            { type = "list_item", text = "Blessing of Chi-Ji: Blazing Song now lasts 15 seconds and healing increased.", level = 1 },
            { type = "list_item", text = "Blessing of Yu’lon: Serpent’s Jadefire damage amplification reduced to 3% and periodic damage reduced.", level = 1 },
            { type = "list_item", text = "Blessing of Xuen: Xuen’s Ferocity can now jump to an additional target and its direct damage increased.", level = 1 },
            { type = "list_item", text = "Blessing of Niuzao: Oxen Fortitude duration increased and the Stamina it provides per stack increased by 1%.", level = 1 },
            { type = "list_item", text = "The daily Celestial quest should no longer be removed when entering a random dungeon.", level = 1 },
            { type = "list_item", text = "Mogu’shan Vaults", level = 0 },
            { type = "list_item", text = "Gara’jal the Spiritbinder should now correctly summon Shadowy Minions regardless of when he is put into combat.", level = 1 },
            { type = "list_item", text = "Cutting Edge and Ahead of the Curve achievements can again be earned in Mogu’shan Vaults.", level = 1 },
            { type = "list_item", text = "Enchanting", level = 0 },
            { type = "list_item", text = "Jade Spirit and Spirit of Conquest now have the same per-level scaling and internal cooldown of 3 seconds.", level = 1 },
            { type = "list_item", text = "Dancing Steel and Bloody Dancing Steel now have the same per-level scaling.", level = 1 },
            { type = "h3", text = "August 12, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Riding Turtle now correctly appears in the mount collections tab.", level = 0 },
            { type = "list_item", text = "When in a Rated Battle for Gilneas, dying now always correctly places players back at their starting graveyard.", level = 0 },
            { type = "list_item", text = "Ancient Mogu Keys are now correctly usable in Heroic Mogu’shan Palace.", level = 0 },
            { type = "list_item", text = "Creatures for the achievement Over Their Heads should now correctly randomize.", level = 0 },
            { type = "list_item", text = "Mogushan Vaults", level = 0 },
            { type = "list_item", text = "Jan-Xi and Qin-Xi should no longer get desynced when performing the Arcing Slash combos.", level = 1 },
            { type = "list_item", text = "Opportunistic Strike should now consistently appear when successfully avoiding Devastating Combo.", level = 1 },
            { type = "list_item", text = "Titan Gas visual reduced in intensity.", level = 1 },
            { type = "list_item", text = "Magnetic Armor now has a visual indicator for where Magnetic Pull will occur.", level = 1 },
            { type = "list_item", text = "Elegon’s Energy Sparks should now consistently idle for a brief moment after spawning.", level = 1 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Wrathguard will no longer occasionally deal no damage when using Wrathstorm.", level = 1 },
            { type = "list_item", text = "Arenas", level = 0 },
            { type = "list_item", text = "All Arenas now correctly display the number of remaining players on each team.", level = 1 },
            { type = "list_item", text = "All Arenas now include timers displaying when the Arena will end.", level = 1 },
            { type = "list_item", text = "The UI at the top now correctly displays the teams as being Purple and Gold.", level = 1 },
            { type = "h3", text = "August 8, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "“Survival Rings: Blades” should now correctly always gain progress at all times.", level = 0 },
            { type = "list_item", text = "Classes", level = 0 },
            { type = "list_item", text = "Priest", level = 1 },
            { type = "list_item", text = "Fixed a bug that allowed Monks to bypass Guardian Spirit via Touch of Death.", level = 2 },
            { type = "list_item", text = "In Arenas, Priests can no longer place Lightwells in areas that other players cannot reach.", level = 2 },
            { type = "h3", text = "August 7, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "The Longest Day achievement no longer requires that dailies need to be completed in a single day.", level = 0 },
            { type = "list_item", text = "The Saurok Stone Tablet is now correctly enabled. Players can now discover this treasure once for experience and progress towards their treasure achievement.", level = 0 },
            { type = "list_item", text = "Classes", level = 0 },
            { type = "list_item", text = "Death Knight", level = 1 },
            { type = "list_item", text = "Frost Death Knights will now correctly display their Death Rune as refreshed from Blood Tap without having to spend another rune.", level = 2 },
            { type = "list_item", text = "Warlock", level = 1 },
            { type = "list_item", text = "Void Ray now correctly costs 40 Demonic Fury.", level = 2 },
            { type = "dev_note", text = "This was an unintended bug in patch 5.4 for Demonology, which looks to have gone uncorrected in the original game until Fel Flame was removed in patch 6.0.2.", level = 2 },
            { type = "list_item", text = "Player versus Player", level = 0 },
            { type = "list_item", text = "Fixed an issue where picking up the flag in a Rated Eye of the Storm match could affect the player’s ability to Stealth even after the flag had been capped.", level = 1 },
            { type = "list_item", text = "Quests", level = 0 },
            { type = "list_item", text = "During “The Wrestler” daily, Sling Sweat puddles will now be the correct size and the Slimy Feet debuff should now correctly always be removed when moving out of the ground effect.", level = 1 },
            { type = "h3", text = "August 6, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "World Bosses should now correctly reset, weekly.", level = 0 },
            { type = "list_item", text = "The Enchanted Pearl, Enchanted Tear, and Nightmare Tear gems will now give correct stats at max level.", level = 0 },
            { type = "list_item", text = "Windshear Cactus, Raptorleaf, and Snakeroot now have loot that is appropriate for the current patch.", level = 0 },
            { type = "list_item", text = "Classes", level = 0 },
            { type = "list_item", text = "Priest", level = 1 },
            { type = "list_item", text = "Shadow Apparition missiles now move at the correct speed.", level = 2 },
            { type = "list_item", text = "Player versus Player", level = 0 },
            { type = "list_item", text = "Fixed a bug causing class adjustments to not work as intended in Battle for Gilneas and Deepwind Gorge.", level = 1 },
            { type = "list_item", text = "Carts in Deepwind Gorge are now correctly returned when clicked on by the defending faction.", level = 1 },
            { type = "list_item", text = "Transmog", level = 0 },
            { type = "list_item", text = "Straw Hats that correspond to your Armor type are now usable as Transmog appearances.", level = 1 },
            { type = "h3", text = "August 4, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "The Mushroom Chair toy is no longer usable in Battlegrounds, Dungeons, or Raids.", level = 0 },
            { type = "list_item", text = "Fishing pools now correctly spawn in Stranglethorn Vale.", level = 0 },
            { type = "list_item", text = "Fixed a bug that prevented some players from being able to see the portal to Stormstout Brewery.", level = 0 },
            { type = "list_item", text = "Classes", level = 0 },
            { type = "list_item", text = "Death Knight", level = 1 },
            { type = "list_item", text = "Players who swap from Frost specialization to a different specialization and use Blood Tap on their Blood Runes will no longer erroneously convert their Blood Runes into permanent Death Runes.", level = 2 },
            { type = "list_item", text = "Monk", level = 1 },
            { type = "list_item", text = "When Brewmaster Monks use Provoke to taunt a target away from a currently active tank that has attack power active from Vengeance, they are now correctly granted 50% of the previous tank’s Vengeance value.", level = 2 },
            { type = "list_item", text = "Pet Battles", level = 0 },
            { type = "list_item", text = "Hoplet no longer has Moon Tears as both of its 2nd slot options; one is replaced by Moon Dance.", level = 1 },
            { type = "list_item", text = "Player versus Player", level = 0 },
            { type = "list_item", text = "The Flag will now cap immediately in Twin Peaks when returned to the base if there is a player standing on the cap point. Previously players had to move off of the capture point and then back. This mirrors how it occurs in Warsong Gulch.", level = 1 },
            { type = "list_item", text = "Priest", level = 1 },
            { type = "list_item", text = "Battleground flags are now immediately dropped when the priest transforms into a Spirit of Redemption, as intended.", level = 2 },
            { type = "list_item", text = "Priests can no longer cast Leap of Faith and pull flag carriers up to the graveyard in Twin Peaks.", level = 2 },
            { type = "list_item", text = "Quests", level = 0 },
            { type = "list_item", text = "Resolved inconsistencies with the Elder Charms of Good Fortune quest.", level = 1 },
            { type = "list_item", text = "Transmog", level = 0 },
            { type = "list_item", text = "The Valorous Dreadnaught set now has the correct appearance on all pieces.", level = 1 },
            { type = "hr" },
            { type = "h3", text = "July 30, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "The achievement Where’s my Air Support? is now awarded as intended.", level = 0 },
            { type = "list_item", text = "Classes", level = 0 },
            { type = "list_item", text = "Fixed a bug that caused macros for some spells, such as Charge, Jab, and Sprouting Mushrooms to incorrectly return the “Spell not Learned” error.", level = 1 },
            { type = "list_item", text = "Druid", level = 1 },
            { type = "list_item", text = "Guardian", level = 2 },
            { type = "list_item", text = "Rejuvenation no longer resets the swing timer while Heart of the Wild is active.", level = 3 },
            { type = "list_item", text = "Heart of the Wild’s cooldown refund now only triggers if the player is shifting into Bear Form.", level = 3 },
            { type = "dev_note", text = "This cooldown refund for Guardian druids will now only trigger if the player has been out of Bear Form for at least 3 seconds, and will not trigger if the player has not shifted into Bear Form at all since logging in.", level = 3 },
            { type = "list_item", text = "Hunter", level = 1 },
            { type = "list_item", text = "The pet ability Growl will now automatically turn off autocasting when entering a dungeon or raid.", level = 2 },
            { type = "list_item", text = "Mage", level = 1 },
            { type = "list_item", text = "Ring of Frosts cast through Presence of Mind now correctly has a 2 second arming time, which is correctly reduced by Haste.", level = 2 },
            { type = "list_item", text = "Monk", level = 1 },
            { type = "list_item", text = "Chi Torpedo and Roll can no longer be stopped by a cancelaura macro.", level = 2 },
            { type = "list_item", text = "Rogue", level = 1 },
            { type = "list_item", text = "Vanishing with Subterfuge talented and then picking up the Shadow Sight debuff in Arena now causes the Rogue to exit stealth.", level = 2 },
            { type = "list_item", text = "Currencies", level = 0 },
            { type = "list_item", text = "The Honor Quartermasters Lok’nor Bloodfist and Hayden Christophen now offer players Motes of Harmony for 400 Honor.", level = 1 },
            { type = "list_item", text = "The Honor Quartermasters in Pandaria now offer the Honor to Justice conversion.", level = 1 },
            { type = "list_item", text = "The Justice Quartermaster Lo ping now offer players Motes of Harmony for 600 Justice Points.", level = 1 },
            { type = "list_item", text = "The Justice Quartermaster in Pandaria now offers the Justice to Honor conversion.", level = 1 },
            { type = "dev_note", text = "We feel that it was too disruptive for players to return to Cataclysm vendors to do Honor conversions, and we really like keeping Justice Points relevant for longer.", level = 1 },
            { type = "list_item", text = "Items", level = 0 },
            { type = "list_item", text = "Golad, Twilight of Aspects and Tiriosh, Nightmare of Ages (the Fangs of the Father daggers) no longer scale up in power for players above level 85.", level = 1 },
            { type = "list_item", text = "Chaotic Skyfire Diamond no longer scales up in power for players above level 70.", level = 1 },
            { type = "list_item", text = "Powerful Earthsiege Diamond no longer scales up in power for players above level 80.", level = 1 },
            { type = "list_item", text = "The Cracked Talisman can no longer be used in combat until the release of the Siege of Orgrimmar content.", level = 1 },
            { type = "list_item", text = "Horde players can now correctly summon the Chi-ji Kite and Yu’lon Kites from Inscription.", level = 1 },
            { type = "list_item", text = "Quests", level = 0 },
            { type = "list_item", text = "Horde players can now correctly use the Shan’ze Dao and Shado-Pan Garrison portals after completing the quest “Through the Portal”.", level = 1 },
            { type = "hr" },
            { type = "h3", text = "July 28, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "You can now board another player’s Grand Expedition Yak if you’re grouped with them and a seat is open.", level = 0 },
            { type = "list_item", text = "Mounts that previously could not be used as ground-mounts while inside of areas that do not allow flying (such as Cloud-Serpents or Cataclysm Gladiator Mounts) can now be used as ground-mounts.", level = 0 },
            { type = "list_item", text = "Fixed a bug causing Daily Quests to sometimes misbehave on different layers.", level = 0 },
            { type = "list_item", text = "The achievement Eternally In The Vale is now correctly granted to players who have completed its criteria.", level = 0 },
            { type = "list_item", text = "Pet Battles", level = 0 },
            { type = "list_item", text = "Fabled Pandaren Pet Supplies now provide rewards.", level = 1 },
            { type = "list_item", text = "Cypress's stats and abilities have been changed.", level = 1 },
            { type = "list_item", text = "Health and Speed increased.", level = 2 },
            { type = "list_item", text = "Strength decreased.", level = 2 },
            { type = "list_item", text = "Life Sap damage reduced by 10%.", level = 2 },
            { type = "list_item", text = "Barkskin replaced by Roar.", level = 2 },
            { type = "list_item", text = "Professions", level = 0 },
            { type = "list_item", text = "Fixed a bug causing players to get a blank window when fishing.", level = 1 },
            { type = "list_item", text = "Fixed a bug that resulted in players being able to learn multiple Alchemy specializations.", level = 1 },
            { type = "list_item", text = "Players who have misplaced Recipe: Banana Infused Rum or Tablet of Ren Yun can now purchase a replacement from Sungshin Ironpaw in Halfhill.", level = 1 },
            { type = "h3", text = "July 24, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Cranedancer’s Staff is now correctly considered a caster weapon.", level = 0 },
            { type = "list_item", text = "Crazy for Cats now requires 15 cats (was 20).", level = 0 },
            { type = "list_item", text = "Spawn time for Shao-Tien Surveyor reduced for the daily quest.", level = 0 },
            { type = "list_item", text = "Rivett Clutchpop should now remain in the Strongarm Airship if “Instant Messaging” is completed before “They’re So Thorny!” is turned in.", level = 0 },
            { type = "list_item", text = "Wintergrasp quests now reward the correct amounts of Honor.", level = 0 },
            { type = "list_item", text = "Recipe: Venerable Potion of Invisibility can now be learned, as intended.", level = 0 },
            { type = "list_item", text = "Silvershard Envoy now invites Horde players to fight for the Horde (was incorrectly the Alliance).", level = 0 },
            { type = "list_item", text = "“Where are My Reinforcements?” now progresses properly.", level = 0 },
            { type = "list_item", text = "Vor’thik Dreadshapers and Vor’thik Fear-Shapers are no longer stuck inside buildings and evading.", level = 0 },
            { type = "list_item", text = "Players can once again convert 375 Honor points into 250 Justice points or 375 Justice points into 250 Honor points.", level = 0 },
            { type = "dev_note", text = "These exchange rates were adjusted in the 5.4 patch of original MoP, and we may revisit them again in a future patch of MoP Classic.", level = 1 },
            { type = "list_item", text = "Archaeology", level = 0 },
            { type = "list_item", text = "Mantid archaeology can now be solved.", level = 1 },
            { type = "dev_note", text = "While these were not originally available until the 5.2 patch, we feel that it’s appropriate to get started on them now, rather than waiting.", level = 2 },
            { type = "list_item", text = "Dungeons and Raids", level = 0 },
            { type = "list_item", text = "Dungeon Finder: Mists of Pandaria Normal should once again exist as an option for level 90 characters.", level = 1 },
            { type = "list_item", text = "Scholomance", level = 1 },
            { type = "list_item", text = "Dark Blaze should no longer disappear, and the spell visual has been improved to be clearer.", level = 2 },
            { type = "list_item", text = "Serpentshrine Cavern", level = 1 },
            { type = "list_item", text = "Lady Vashj’s Tainted Core no longer roots level 90 players.", level = 2 },
            { type = "list_item", text = "Pet Battles", level = 0 },
            { type = "list_item", text = "Arcane Eye spawn rate slightly increased.", level = 1 },
            { type = "h3", text = "July 22, 2025" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Spawn rates and item drop rates for “They’re So Thorny!” and “Forensic Science” have been significantly increased.", level = 0 },
            { type = "list_item", text = "The Season 12 PvP Honor Vendor is now available so that players can spend Honor.", level = 0 },
            { type = "list_item", text = "Honor Vendors correctly have their PvP weapon lists attached.", level = 1 },
            { type = "list_item", text = "All Conquest Weapons correctly require a Season total for Conquest earned.", level = 1 },
            { type = "list_item", text = "Motes of Harmony are not available through Honor or Conquest until a future patch.", level = 1 },
            { type = "dev_note", text = "In original Mists of Pandaria, PvP gear was not added to the Honor Vendors until Arena Season 12 started. In MoP Classic, we’ve added PvP gear to these vendors early, so you can use Honor to buy PvP gear in the offseason/preseason, ahead of next week’s Arena Season start. Dreadful Gladiator Honor PvP Weapons were never available during Season 12 in original Mists of Pandaria. We feel these weapons are a great steppingstone for PvP activities.", level = 1 },
            { type = "list_item", text = "Player flight speed is no longer reduced in Netherwing Ledge.", level = 0 },
            { type = "list_item", text = "The Kor’kron War Wolf will now correctly appear as the intended color in the Mount Journal.", level = 0 },
            { type = "list_item", text = "Dungeons", level = 0 },
            { type = "list_item", text = "Jade Temple", level = 1 },
            { type = "list_item", text = "Fixed an issue that would occasionally cause Wise Mari’s bubble to fail to burst after Corrupted Living Water was killed.", level = 2 },
            { type = "list_item", text = "Temple of the Jade Serpent will now correctly grant the achievement for completing it on Heroic.", level = 2 },
            },
        },
        ["2026-06-23-the-burning-crusade-hotfixes-updated-22-june-c8fc07c7bd"] = {
            id = "2026-06-23-the-burning-crusade-hotfixes-updated-22-june-c8fc07c7bd",
            post_key = "c8fc07c7bd",
            title = "The Burning Crusade Hotfixes - Updated 22 June",
            category = "The Burning Crusade Classic (EU)",
            timestamp = 1782180342,
            url = "https://eu.forums.blizzard.com/en/wow/t/601545/1",
            content = {
            { type = "h2", text = "HOTFIXES" },
            { type = "h3", text = "June 22, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Fixed an issue that was causing Midsummer Festival Bonfires to deal more damage to players than expected.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "June 12, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Fixed an issue that caused Darkmoon Faire to not properly run on the first Friday of every month.", level = 0 },
            { type = "list_item", text = "An extra Darkmoon Faire holiday will be available in Terrokkar Forest starting June 15 until June 22.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "June 5, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "If multiple players use a Crystalforged Darkrune at Shartuul’s Transporter simultaneously, any player who does not take control of the Felguard will keep their Crystalforged Darkrune.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "June 2, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Player versus Player", level = 0 },
            { type = "list_item", text = "Following an Arena match, the user interface now displays the pre-match Matchmaking Ratings (MMR) for each team.", level = 1 },
            { type = "dev_note", text = "Our goal is to provide more information, so that players can better contextualize their changing MMR.", level = 2 },
            { type = "hr" },
            { type = "h3", text = "April 1, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Significantly increased the amount of Honor earned in all battlegrounds.", level = 0 },
            { type = "h3", text = "February 20, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Fixed an issue that was causing the Karazhan Chess Event to run much faster than intended, allowing Medivh to cheat more often than he should. Sneaky Medivh!", level = 0 },
            { type = "h3", text = "February 12, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Updated the Communal Flamewrought Keys to be usable by either faction if the character is Friendly with Honor Hold/Thrallmar.", level = 0 },
            { type = "list_item", text = "[With realm restarts] Fixed a bug that caused enemies to be less armored against physical attacks than intended.", level = 0 },
            { type = "h3", text = "February 4, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "The book ‘Soothsaying for Dummies’ has been re-enabled.", level = 0 },
            { type = "list_item", text = "Fixed an issue that could prevent warlock players from being able to complete the quest “What is Love”.", level = 0 },
            { type = "list_item", text = "Fixed a bug where The Prophet Skeram would incorrectly purge buffs from players when transitioning between phases.", level = 0 },
            { type = "h3", text = "February 3, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Player-characters who were incorrectly granted the 150 Epic riding skill have been reverted to riding skill 75.", level = 0 },
            { type = "h3", text = "January 27, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Fixed a rare bug where characters who received a Level 58 Character Boost did not learn all their spells.", level = 0 },
            { type = "list_item", text = "Book “Soothsaying for Dummies”, used to re-choose profession specializations for Leatherworking and Engineering, has been temporarily disabled while we resolve an issue with it granting the wrong specialization.", level = 0 },
            { type = "dev_note", text = "We’re aiming to have the book reenabled in the not-too-distant future and will post a hotfix note when that happens.", level = 1 },
            { type = "list_item", text = "Fixed an issue where raid frames were not correctly displaying whether a player was in-range or not.", level = 0 },
            { type = "list_item", text = "Fixed an issue where pets with auto-cast spells would cause client performance to degrade over time.", level = 0 },
            { type = "list_item", text = "Fixed an issue that caused the pre-expansion event to disable briefly.", level = 0 },
            { type = "h3", text = "January 16, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Fixed an issue where Blackrock Spire only allowed 5 players to enter.", level = 0 },
            { type = "list_item", text = "Fixed a bug preventing the quest “The First and Last” from starting for eligible players.", level = 0 },
            { type = "list_item", text = "Cleansed Songflowers now apply their buff to the clicking player, not the player’s target.", level = 0 },
            { type = "list_item", text = "Paladins should now be able to learn Consecration from their trainer as intended.", level = 0 },
            { type = "list_item", text = "Shamans who were unable to learn Two-Handed Maces and Two-Handed Axes from the weapon trainer should again be able to.", level = 0 },
            { type = "dev_note", text = "Players may need to log out and back in to pick up this fix.", level = 1 },
            { type = "list_item", text = "Player versus Player", level = 0 },
            { type = "list_item", text = "The current active increase to Honor gains is now 150% (was a 100% bonus).", level = 1 },
            { type = "list_item", text = "Added level 51-60 versions of the “For Great Honor” (Horde) and “Concerted Effort” (Alliance) quests.", level = 1 },
            { type = "dev_note", text = "Soon after launching the Burning Crusade pre-expansion patch, we could see that PvP needed an additional increase in rate of gearing. These quests award 400 Honor (at level 60) when handed in, as well as experience for players from levels 51-59. These quests do not require Eye of the Storm, and their text will soon be updated to reflect that. When the Dark Portal opens, these quests will no longer be available, and the level 61-70 versions of these quests will become available.", level = 1 },
            { type = "h3", text = "January 14, 2026" },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Restored character Boost services after a brief outage.", level = 0 },
            { type = "list_item", text = "Enabled Arena Skirmishes, as intended.", level = 0 },
            { type = "list_item", text = "Fixed an issue that caused Addons to be unintentionally throttled.", level = 0 },
            { type = "list_item", text = "Returned the Chronoboon Displacer to its adjusted cost of 1 gold and stack size of 10.", level = 0 },
            },
        },
