            { type = "list_item", text = "Players can again place non-default flooring, leave their House, and return to find the flooring where they placed it.", level = 0 },
            { type = "h3", text = "Items" },
            { type = "list_item", text = "Fixed a bug preventing players from purchasing the Cache of Void-Touched Weapons before unlocking the Void-Touched Sunfury Poleaxe from any item.", level = 0 },
