        ["2026-06-18-hot-deals-on-cool-findsshop-the-wow-summer-sale-205daf1236"] = {
            id = "2026-06-18-hot-deals-on-cool-findsshop-the-wow-summer-sale-205daf1236",
            post_key = "205daf1236",
            title = "Hot Deals on Cool Finds—Shop the WoW Summer Sale!",
            category = "Blogs (US)",
            timestamp = 1781804302,
            url = "https://news.blizzard.com/en-us/article/24267735/hot-deals-on-cool-findsshop-the-wow-summer-sale",
            content = {
            { type = "p", text = "Step into the heat of Azeroth with cool summer savings of up to 50% off select World of Warcraft® cosmetic bundles, mounts, transmogs, pets, and toys now through July 7*. Read on for a hint of the summer savings that await!" },
            { type = "p", text = "Some exclusions apply, so visit the Battle.net shop to see the full list of discounted offerings and details." },
            { type = "hr" },
            { type = "h2", text = "MAKE THE MOST OF THESE WOW® MODERN MARKDOWNS" },
            { type = "p", text = "Wherever the path leads in Midnight, get summer savings on some items that are ready to go with you.**" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-18-hot-deals-on-cool-findsshop-the-wow-summer-sale-205daf1236\\image-1.jpg" },
            { type = "h3", text = "Wings & Wisdom Pack" },
            { type = "p", text = "Soar the skies atop Ravens, adorned in feathery garb inspired by Medivh and Khadgar. This bundle includes two Great Raven mounts*** and two transmog sets—Feathered Archmage and Feathered Prophet, including staff weapon transmogs. The staff weapon transmogs are not available for the following classes: Death Knight, Demon Hunter, Paladin, and Rogue." },
            { type = "h3", text = "Visit the Shop" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-18-hot-deals-on-cool-findsshop-the-wow-summer-sale-205daf1236\\image-2.jpg" },
            { type = "h3", text = "Heavenly Regalia Pack" },
            { type = "p", text = "Illuminate your path with the radiant Heavenly Regalia Pack. Each set reflects the beauty of the celestial forces, adorning any wearer with the power of light or shadow." },
            { type = "p", text = "The Heavenly Regalia Pack includes two color variants:" },
            { type = "list_item", text = "Ensemble: Radiant Vestments of the Heavens (Left)", level = 0 },
            { type = "list_item", text = "Ensemble: Shining Vestments of the Heavens (Right)", level = 0 },
            { type = "p", text = "The pieces in these sets give you the ultimate flexibility to express your fashion sensibilities. Fully replace the look of your gear or use a few accent pieces to enhance your favorite outfit for an authentic look." },
            { type = "h3", text = "Visit the Shop" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-18-hot-deals-on-cool-findsshop-the-wow-summer-sale-205daf1236\\image-3.jpg" },
            { type = "h3", text = "Green Snugglefin Murloc Romper" },
            { type = "p", text = "It’s easy being green when you’re this comfy. Don the Happy or Angry Hood to become one with your inner Murloc!" },
            { type = "p", text = "Green Snugglefin Murloc Romper Includes:" },
            { type = "list_item", text = "Happy Green Snugglefin Murloc Hood", level = 0 },
            { type = "list_item", text = "Angry Green Snugglefin Murloc Hood", level = 0 },
            { type = "list_item", text = "Green Snugglefin Murloc Pullover", level = 0 },
            { type = "list_item", text = "Green Snugglefin Murloc Sweatpants", level = 0 },
            { type = "list_item", text = "Green Snugglefin Murloc Slippers", level = 0 },
            { type = "list_item", text = "Green Snugglefin Murloc Mittens", level = 0 },
            { type = "list_item", text = "Green Snugglefin Murloc Backpack", level = 0 },
            { type = "h3", text = "Visit the Shop" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-18-hot-deals-on-cool-findsshop-the-wow-summer-sale-205daf1236\\image-4.jpg" },
            { type = "h3", text = "Herald of Sa'bak Mount***" },
            { type = "p", text = "Scale the skies of Azeroth in fearsome glory with this Skyriding mount!" },
            { type = "p", text = "The Tol'vir tell of the legendary Sa'bak, a great crocolisk believed to have emerged from the sacred valley of Un'Goro Crater. Although few have ever seen Sa'bak in the flesh, many believe he was blessed by the Titan Keepers to safeguard the vast waterways of Uldum." },
            { type = "h3", text = "Visit the Shop" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-18-hot-deals-on-cool-findsshop-the-wow-summer-sale-205daf1236\\image-5.jpg" },
            { type = "h3", text = "Sunwarmed Furline***" },
            { type = "p", text = "With eyes of pure emerald and the tail of a fox, this magical cat can carry you effortlessly from land to land. But its favorite places in all of Azeroth happen to be anywhere the sun shines through the autumn leaves, especially when a glowing campfire is nearby." },
            { type = "h3", text = "Visit the Shop" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-18-hot-deals-on-cool-findsshop-the-wow-summer-sale-205daf1236\\image-6.jpg" },
            { type = "h3", text = "Marvelous Meeksi Mounts***" },
            { type = "p", text = "Each tea-toting panda is sold individually, and steeped in tenderly curated colors that blend perfectly with any journey in Azeroth, whether on land or in the air. Choose a tea bear perfectly paired to fuel your trek across Azeroth—Teatuft (Red), Softpaw (Gray), Rufflefur (Blue), Rollingpaw (Orange), Brewthief (Purple)" },
            { type = "p", text = "Visit the Shop" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-18-hot-deals-on-cool-findsshop-the-wow-summer-sale-205daf1236\\image-7.jpg" },
            { type = "h3", text = "Sa'bak's Blessing Pet" },
            { type = "p", text = "Crocolisk hatchlings that break free of their shells during the Festival of the Sun are said to be blessed by the river guardian, Sa'bak. This little gator pet is so aggressively cute, you won’t even mind if he takes a little bite out of you." },
            { type = "p", text = "Visit the Shop" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-18-hot-deals-on-cool-findsshop-the-wow-summer-sale-205daf1236\\image-8.jpg" },
            { type = "h3", text = "Blinky Pet" },
            { type = "p", text = "Friends come in all colors with this cheerful companion! Blinky has a playful demeanor will not only faithfully flutter by your side but will also add a bit of magic to your days with its chromatic hue-shifting powers. Although Blinky’s colors might frequently change, his loyal friendship will be yours forever." },
            { type = "h3", text = "Visit the Shop" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-18-hot-deals-on-cool-findsshop-the-wow-summer-sale-205daf1236\\image-9.jpg" },
            { type = "h3", text = "Sandbox Storm Gyyphon Toy" },
            { type = "p", text = "Take flight without leaving the ground!" },
            { type = "p", text = "Playfully perch on your proud gryphon in your personal sandbox of imagination." },
            { type = "h3", text = "Visit the Shop" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-18-hot-deals-on-cool-findsshop-the-wow-summer-sale-205daf1236\\image-10.jpg" },
            { type = "h3", text = "Deepdweller’s Earthen Hearthstone Effect" },
            { type = "p", text = "Return home from your adventures through Azeroth by channeling the raw strength of the earth itself. The Deepdweller’s Earthen Hearthstone is a cosmetic effect that shares cooldown with your regular Hearthstone." },
            { type = "h3", text = "Visit the Shop" },
            { type = "hr" },
            { type = "h2", text = "CATCH COOL SAVINGS FOR YOUR CLASSIC WOW® COLLECTION" },
            { type = "p", text = "Seeking summer savings to carry you through your WoW Classic adventures? We have you covered with some offerings.**" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-18-hot-deals-on-cool-findsshop-the-wow-summer-sale-205daf1236\\image-11.jpg" },
            { type = "h3", text = "Wings of the Guardian Pack****" },
            { type = "p", text = "Soaring over Azeroth on your new black or white Great Crow will be a great caws for celebration! The Wings of the Guardian Pack includes the Prophet's Great Crow and Archmage's Great Crow. These Great Crow mounts are only available on WoW® Classic Progression (currently Mists of Pandaria™ Classic) realms." },
            { type = "p", text = "Visit the Shop" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-18-hot-deals-on-cool-findsshop-the-wow-summer-sale-205daf1236\\image-12.jpg" },
            { type = "h3", text = "Envoy of Sa'bak Mount****" },
            { type = "p", text = "Set scale for new horizons astride the Envoy of Sa'bak mount—legend has it that a great crocolisk emerged from the sacred valley of Un'Goro Crater. The Envoy of Sa’bak mount is only available on WoW® Classic Progression (currently Mists of Pandaria™ Classic) realms." },
            { type = "h3", text = "Visit the Shop" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-18-hot-deals-on-cool-findsshop-the-wow-summer-sale-205daf1236\\image-13.jpg" },
            { type = "h3", text = "Majestic Meeksi Mounts****" },
            { type = "p", text = "Each tea-toting panda is sold individually, and steeped in tenderly curated colors that blend perfectly with any journey—Teatuft (Red), Softpaw (Gray), Rufflefur (Blue), Rollingpaw (Orange), Brewthief (Purple). These majestic Meeksi mounts are only available on WoW® Classic Progression (currently Mists of Pandaria™ Classic) realms." },
            { type = "h3", text = "Visit the Shop" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-18-hot-deals-on-cool-findsshop-the-wow-summer-sale-205daf1236\\image-14.jpg" },
            { type = "h3", text = "Sa'bak's Favored Pet" },
            { type = "p", text = "This little gator pet is so aggressively cute, you won’t even mind if he takes a little bite out of you. Sa'bak's Favored Pet is only available on WoW® Classic Progression (currently Mists of Pandaria™ Classic) realms." },
            { type = "h3", text = "Visit the Shop" },
            { type = "hr" },
            { type = "p", text = "All these deals and more await you at the Battle.net shop." },
            { type = "p", text = "*Sale ends on July 8 at 10 am PDT **Use of these items requires a World of Warcraft® subscription or Game Time ***Shared across all present and future modern World of Warcraft® Modern (currently Midnight™) characters and automatically scales to the fastest riding skill known by each character. If a character isn’t high enough level to use a flying mount, it can also be used as a ground mount. ****Shared across all present and future WoW® Classic Progression (currently Mists of Pandaria™ Classic) characters and automatically scales to the fastest riding skill known by each character. If they aren’t high enough level to use a flying mount, it can also be used as a ground mount." },
            },
        },
