            { type = "hr" },
            { type = "h2", text = "TURBULENT TIMEWAYS RETURNS THE WEEK OF 1 JULY" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-17-the-midnight-revelations-content-update-is-now-live-8f0f50d0f3\\image-11.jpg" },
            { type = "p", text = "Turbulent Timeways returns with new rewards over six weeks, including a new mount—Spawn of Vyranoth— and adds six Dragonflight dungeons to the rotation:" },
            { type = "list_item", text = "Algeth’ar Academy", level = 0 },
            { type = "list_item", text = "Halls of Infusion", level = 0 },
            { type = "list_item", text = "Neltharus", level = 0 },
            { type = "list_item", text = "Ruby Life Pools", level = 0 },
            { type = "list_item", text = "The Azure Vaults", level = 0 },
            { type = "list_item", text = "Brackenhide Hollow", level = 0 },
            { type = "h3", text = "Schedule:" },
            { type = "list_item", text = "Week of 1 July: Dragonflight", level = 0 },
            { type = "list_item", text = "Week of 8 July: Battle for Azeroth", level = 0 },
            { type = "list_item", text = "Week of 15 July: Shadowlands", level = 0 },
            { type = "list_item", text = "Week of 22 July: Classic", level = 0 },
            { type = "list_item", text = "Week of 29 July: The Burning Crusade", level = 0 },
            { type = "list_item", text = "Week of 5 August: Dragonflight", level = 0 },
            { type = "p", text = "Learn more in our overview article here." },
            { type = "hr" },
            { type = "h2", text = "BEGIN THE NEXT CHAPTER WITH ZUL’JAN STARTING THE WEEK OF 8 JULY" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-17-the-midnight-revelations-content-update-is-now-live-8f0f50d0f3\\image-12.jpg" },
            { type = "p", text = "When the haranir call for a special gathering, Zul’jan attends as the Amani representative—only to be drawn into an ancient mystery surrounding the legacy of the Amani trolls. Join him and his uncle Kinduru on their journey of discovery to uncover the truth." },
            { type = "hr" },
            { type = "h2", text = "MORE USER INTERFACE UPDATES" },
            { type = "p", text = "We’re adding additional quality-of-life updates to raid frames, damage meters, and more." },
            { type = "hr" },
            { type = "h2", text = "CONTENT UPDATE NOTES" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-17-the-midnight-revelations-content-update-is-now-live-8f0f50d0f3\\image-13.jpg" },
            { type = "hr" },
            { type = "p", text = "There’s more to uncover in Midnight: Revelations. We’ll see you in Azeroth!" },
            },
        },
        ["2026-06-16-the-midnight-revelations-content-update-is-now-live-b6d677cfd5"] = {
            id = "2026-06-16-the-midnight-revelations-content-update-is-now-live-b6d677cfd5",
            post_key = "b6d677cfd5",
            title = "The Midnight: Revelations Content Update is Now Live!",
            category = "Blogs (US)",
            timestamp = 1781634388,
            url = "https://news.blizzard.com/en-us/article/24266797/the-midnight-revelations-content-update-goes-live-june-16",
            content = {
            { type = "p", text = "Take the next step in thwarting the forces of the Void, hunt down their leaders in two new areas and uncover new sources of power. Players also face a new single-boss raid in Sporefall and Turbulent Timeways returns with Dragonflight dungeons with a new slate of rewards." },
            { type = "hr" },
            { type = "h2", text = "TRAVEL TO VAL AND NAIGTAL TO QUELL LEADERS OF THE VOID" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-16-the-midnight-revelations-content-update-is-now-live-b6d677cfd5\\image-1.jpg" },
            { type = "p", text = "Facing the forces of the Void in Void Assaults and Ritual Sites isn’t enough to stop their machinations. To cut the threat off at its source, you’ll need to hunt down the leaders behind these brutal attacks on Azeroth. Track them through a portal in Voidstorm leading to two new locations—Val and Naigtal." },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-16-the-midnight-revelations-content-update-is-now-live-b6d677cfd5\\image-2.jpg" },
            { type = "p", text = "Naigtal: A fungal, arcane-rich world now occupied by an insidious ethereal faction known as the Hal'hadar." },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-16-the-midnight-revelations-content-update-is-now-live-b6d677cfd5\\image-3.jpg" },
            { type = "p", text = "Val: An icy world once inhabited by the Legion where the Domanaar Imperator Pertinax has established his bastion of power." },
            { type = "p", text = "The portal to these worlds is unstable and switches destinations every week, bringing a rotating set of challenges and experiences. Players can undertake World Quests, defeat rare enemies, take part in events, and ultimately have a showdown with the leaders as world bosses. Learn more in our overview article." },
            { type = "hr" },
            { type = "h2", text = "GAIN NEW POWER WITH THE OMNIUM FOLIO" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-16-the-midnight-revelations-content-update-is-now-live-b6d677cfd5\\image-4.jpg" },
            { type = "p", text = "Join Magister Umbric and Grand Magister Rommath on a mission to reconfigure and restore the Sunstrider Omnium. This ancient elven relic was originally created by Dath’remar Sunstrider to study and observe the various schools of magic and to serve as an academic repository. After years of silence, the Sunstrider Omnium has now reawakened, unsettling the Magisters and sowing disarray among them." },
            { type = "p", text = "Once unlocked, you’ll be entrusted with the Omnium Folio, a runic ledger containing powerful runes of power you can use in battle. Continue taking part in weekly activities to imbue more runes—customizing these initial runes and unlocking their maximum potential to aid you in the fight against the Void. Learn more in our previously published article." },
            { type = "hr" },
            { type = "h3", text = "Prepare to Face Rotmire in the Sporefall Raid" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-16-the-midnight-revelations-content-update-is-now-live-b6d677cfd5\\image-5.jpg" },
            { type = "p", text = "Introducing a new single-boss raid located in Harandar. You’ll face the fungal giant Rotmire in Raid Finder, Normal, Heroic, and Mythic difficulties. Players can also undertake Mythic difficulty in flexible groups of 15-25 players. You'll earn a variety of new rewards including the Luminous Sporeglider mount." },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-16-the-midnight-revelations-content-update-is-now-live-b6d677cfd5\\image-6.jpg" },
            { type = "p", text = "Luminous Sporeglider Mount“This sporeglider’s voracious appetite for luminescent spores has lent it an exquisite glow.”" },
            { type = "p", text = "Visit our previously published article to learn more." },
            { type = "hr" },
            { type = "h2", text = "GO LOREWALKING WITH THE LOA" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-16-the-midnight-revelations-content-update-is-now-live-b6d677cfd5\\image-7.jpg" },
            { type = "p", text = "Experience the lore of the loa with Assistant Lorewalker Li Li. You’ll dive deeper into the stories of the Zandalari, Drakkari, Gurubashi, and Darkspear trolls." },
            { type = "hr" },
            { type = "h2", text = "HELP LOA SPEAKER BREK HATCH JAN’ALAI’S NEW EGGS" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-16-the-midnight-revelations-content-update-is-now-live-b6d677cfd5\\image-8.jpg" },
            { type = "p", text = "With the return of Jan’alai, Loa of Fire comes a return to past traditions. She’s ready to bring a new clutch of eggs into the world but Loa Speaker Brek requires assistance with the ceremony and with ensuring all the Loa’s young are released safely from their eggs. Be a part of welcoming the first of her offspring and protecting them as they take their first steps." },
            { type = "hr" },
            { type = "h2", text = "GET MORE WITH RITUAL SITES AND VOID ASSAULT UPDATES" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-16-the-midnight-revelations-content-update-is-now-live-b6d677cfd5\\image-9.jpg" },
            { type = "p", text = "With the content update, players will find increased rewards from Ritual Sites and Void Assaults." },
            { type = "h3", text = "Void Strikes and Incursions Grant More Experience" },
            { type = "p", text = "Experience earned from Void Strikes, Void Incursions, and weekly quests is increased. Drop rates for Dark Particles have also increased, along with the chance to receive Bulging Satchels upon completing these activities." },
            { type = "h3", text = "Shop with Trima Dawnsetter and Maren Silverwing" },
            { type = "p", text = "Trima Dawnsetter in Silvermoon City now offers pouches for purchase that contain the same cosmetics found in Bulging Satchels, available for 150 Dark Particles. These pouches include items normally dropped from Ritual Site end chests." },
            { type = "p", text = "Maren Silverwing now sells slot-specific Bind-on-Pickup Heroic caches for 750 Field Accolades, as well as slot-specific Warbound Champion caches for 100 Field Accolades." },
            { type = "h3", text = "Challenge Yourself in Ritual Sites with a New Tier 6 Difficulty" },
            { type = "p", text = "Face greater challenges in Ritual Sites with the new Tier 6 difficulty. Select six challenges as you take on enemies within. Completing these encounters grants additional rewards, including 5 Mythic Dawncrests and 10 Heroic Dawncrests." },
            { type = "p", text = "New weekly quests are also available at Tier 6 when specific challenges are selected. Players can earn an additional Bonus Roll from these quests during weeks 3 and 6." },
            { type = "p", text = "Earn two new achievements:" },
            { type = "list_item", text = "Advanced Ritual Site Studies — Complete the six advanced challenges for Lady Darkglen.", level = 0 },
            { type = "list_item", text = "Pinnacle Ritual Work — Complete each Ritual Site at Tier 6 with all eight challenges active. Reward: Title — Ritual Breaker", level = 0 },
            { type = "hr" },
            { type = "h2", text = "RUN, LEAP, AND SPREAD CHEER DURING THE DARKSPEAR DASH MICRO-HOLIDAY JUNE 27" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-16-the-midnight-revelations-content-update-is-now-live-b6d677cfd5\\image-10.jpg" },
            { type = "p", text = "Join the Darkspear trolls and their Zandalari allies as they race from Echo Isles to Silvermoon City for an in-game event inspired by the Running of the Trolls community event. Prepare to run, leap, and spread rainbow cheer along the route." },
            { type = "hr" },
            { type = "h2", text = "TURBULENT TIMEWAYS RETURNS THE WEEK OF JUNE 30" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-16-the-midnight-revelations-content-update-is-now-live-b6d677cfd5\\image-11.jpg" },
            { type = "p", text = "Turbulent Timeways returns with new rewards over six weeks, including a new mount—Spawn of Vyranoth— and adds six Dragonflight dungeons to the rotation:" },
            { type = "list_item", text = "Algeth’ar Academy", level = 0 },
            { type = "list_item", text = "Halls of Infusion", level = 0 },
            { type = "list_item", text = "Neltharus", level = 0 },
            { type = "list_item", text = "Ruby Life Pools", level = 0 },
            { type = "list_item", text = "The Azure Vaults", level = 0 },
            { type = "list_item", text = "Brackenhide Hollow", level = 0 },
            { type = "h3", text = "Schedule:" },
            { type = "list_item", text = "Week of June 30: Dragonflight", level = 0 },
            { type = "list_item", text = "Week of July 7: Battle for Azeroth", level = 0 },
            { type = "list_item", text = "Week of July 14: Shadowlands", level = 0 },
            { type = "list_item", text = "Week of July 21: Classic", level = 0 },
            { type = "list_item", text = "Week of July 28: The Burning Crusade", level = 0 },
            { type = "list_item", text = "Week of August 4: Dragonflight", level = 0 },
            { type = "p", text = "Learn more in our overview article here." },
            { type = "hr" },
            { type = "h2", text = "BEGIN THE NEXT CHAPTER WITH ZUL’JAN STARTING THE WEEK OF JULY 7" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-16-the-midnight-revelations-content-update-is-now-live-b6d677cfd5\\image-12.jpg" },
            { type = "p", text = "When the haranir call for a special gathering, Zul’jan attends as the Amani representative—only to be drawn into an ancient mystery surrounding the legacy of the Amani trolls. Join him and his uncle Kinduru on their journey of discovery to uncover the truth." },
            { type = "hr" },
            { type = "h2", text = "MORE USER INTERFACE UPDATES" },
            { type = "p", text = "We’re adding additional quality-of-life updates to raid frames, damage meters, and more." },
            { type = "hr" },
            { type = "h2", text = "CONTENT UPDATE NOTES" },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-16-the-midnight-revelations-content-update-is-now-live-b6d677cfd5\\image-13.jpg" },
            { type = "hr" },
            { type = "p", text = "There’s more to uncover in Midnight: Revelations. We’ll see you in Azeroth!" },
            },
        },
        ["2026-06-16-march-on-queldanas-raid-tuning-16-june-3f72681c53"] = {
            id = "2026-06-16-march-on-queldanas-raid-tuning-16-june-3f72681c53",
            post_key = "3f72681c53",
            title = "March on Quel’Danas Raid Tuning – 16 June",
            category = "General Discussion (EU)",
            timestamp = 1781633010,
            url = "https://eu.forums.blizzard.com/en/wow/t/621630/1",
            content = {
            { type = "p", text = "With scheduled realm maintenance this week, we’ll make the following changes." },
            { type = "h2", text = "RAIDS" },
            { type = "list_item", text = "March on Quel’Danas", level = 0 },
            { type = "list_item", text = "Midnight Falls", level = 1 },
            { type = "list_item", text = "Glimmering damage reduced by 20% on Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Reduced the spread of Midnight Crystals and Dusk Crystals.", level = 2 },
            { type = "list_item", text = "Starsplinter can no longer target a player twice at the same time.", level = 2 },
            { type = "list_item", text = "Criticality cast time increased to 4 seconds (was 3 seconds).", level = 2 },
            { type = "list_item", text = "Dawn Crystals now begin pulsing Radiance after 6 seconds on Heroic and Mythic difficulties (was 5 seconds).", level = 2 },
            { type = "list_item", text = "Dark Constellation cast time increased to 3 seconds on Mythic difficulty (was 2.5 seconds).", level = 2 },
            { type = "list_item", text = "Dark Constellations now spawn further from Light Siphons.", level = 2 },
            { type = "list_item", text = "Radiance damage reduced by 50% on Heroic difficulty.", level = 2 },
            { type = "list_item", text = "Tears of L’ura now spawn 1 soak on Heroic difficulty (was 2).", level = 2 },
            },
        },
