            url = "https://us.forums.blizzard.com/en/wow/t/2314417/1",
            content = {
            { type = "h2", text = "NEW SEASON 3 CELESTIAL DUNGEONS WILL BECOME AVAILABLE WITH WEEKLY RESETS IN EACH REGION ON TUESDAY, JUNE 16." },
            { type = "list_item", text = "New Enemy Buffs", level = 0 },
            { type = "list_item", text = "Glory to the True Horde: Creatures in the Celestial Dungeons will have their Damage and Health increased.", level = 1 },
            { type = "list_item", text = "Kor’kron Banners: Banners are now planted throughout the dungeons that empower nearby enemies.", level = 1 },
            { type = "list_item", text = "Periodically, a boss is influenced by Garrosh Hellscream, and will use an ability based on one of his loyal followers from the Siege of Orgrimmar Raid.", level = 1 },
            { type = "list_item", text = "General Nazgrim, Wavebinder Kardis, and Siegecrafter Blackfuse have answered Garrosh’s call to arms.", level = 2 },
            { type = "list_item", text = "New Player Buffs", level = 0 },
            { type = "list_item", text = "Sensing the impending conflict against the Kor’kron, the Celestials have a final empowering boon that is bestowed upon players when all four Celestials are summoned simultaneously. The stars themselves will reshape in the sky to signify this immense moment.", level = 1 },
            { type = "list_item", text = "Celestial Witness: Witnessing the arrival of the August Celestials infuses players with the Celestial Witness buff, increasing their Damage and Healing done, and reducing their damage taken for an extended period.", level = 2 },
            { type = "h2", text = "NEW CHALLENGE MODE DUNGEONS: DIAMOND DIFFICULTY WILL BECOME AVAILABLE WITH WEEKLY RESETS IN EACH REGION ON TUESDAY, JUNE 23." },
            { type = "p", text = "The reward for Diamond times in Season 3 will be the Celestial Ox transformation mount." },
            { type = "image", width = 606, height = 420, u = 0.591797, v = 0.820312, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-09-new-celestial-dungeons-and-challenge-mode-diamond-coming-soon-fe63352b7a\\image-1.jpg" },
            { type = "p", text = "Complete the new difficult times to add the Celestial Ox god to your collection." },
            },
