        ["2026-06-04-mists-of-pandaria-classic-siege-of-orgrimmar-raid-now-live-4c6e929322"] = {
            id = "2026-06-04-mists-of-pandaria-classic-siege-of-orgrimmar-raid-now-live-4c6e929322",
            post_key = "4c6e929322",
            title = "Mists of Pandaria Classic: Siege of Orgrimmar Raid Now Live",
            category = "Blogs (US)",
            timestamp = 1780610628,
            url = "https://news.blizzard.com/en-us/article/24252017/mists-of-pandaria-classic-siege-of-orgrimmar-raid-now-live",
            content = {
            { type = "p", text = "The tensions stoked by Garrosh Hellscream’s arrogance have reached a boiling point with the devastation unleashed upon the Vale of Eternal Blossoms. Champions of the Alliance and the Horde must answer for Hellscream’s destruction, lay siege to his capital, and topple the ruthless Warchief once and for all!" },
            { type = "p", text = "Heroes of the Alliance and the Horde have tested their mettle against the might of the sha, the Thunder King, and each other, yet neither side could have foreseen the atrocities the Horde’s Warchief would unleash." },
            { type = "p", text = "Garrosh Hellscream’s reckless thirst for power has unleashed horrors upon the Vale of Eternal Blossoms, once the sacred heart of the pandaren empire." },
            { type = "hr" },
            { type = "h2", text = "BRING DOWN THE WARCHIEF" },
            { type = "p", text = "The Siege of Orgrimmar is a sprawling, two‑part raid that takes players from the scarred ruins of the Vale of Eternal Blossoms to the heart of the Horde's capital, Orgrimmar in Durotar." },
            { type = "p", text = "Location: Begins inside the shattered pillar before Mogu’shan Palace on the southwest side of the Vale of Eternal Blossoms and ends in Orgrimmar, Durotar.Level: 90Difficulty: Normal, HeroicTotal Bosses: 14" },
            { type = "hr" },
            { type = "h2", text = "DEAL WITH THE VILE EVENTS IN THE VALE OF ETERNAL BLOSSOMS" },
            { type = "p", text = "The first order of business is to confront the aftermath of Garrosh’s foul machinations. His poisoning of the Pools of Power has brought devastation to the land and to those who have long defended it." },
            { type = "h3", text = "Vale of Eternal Sorrows" },
            { type = "p", text = "Venture through the scarred Vale of Eternal Blossoms, exploring unearthed mogu ruins to discover the source of the destruction." },
            { type = "image", width = 672, height = 420, u = 0.65625, v = 0.820312, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-04-mists-of-pandaria-classic-siege-of-orgrimmar-raid-now-live-4c6e929322\\image-1.jpg" },
            { type = "p", text = "The ancient inhabitants of Pandaria recognized the vital importance of the lifegiving Pools of Power, building an underground system of aqueducts to safeguard the waters and nurture life in the Vale of Eternal Blossoms. The touch of corruption has animated and twisted these waters, and Immerseus stands as an unnatural embodiment of the Vale's sorrow." },
            { type = "image", width = 672, height = 420, u = 0.65625, v = 0.820312, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-04-mists-of-pandaria-classic-siege-of-orgrimmar-raid-now-live-4c6e929322\\image-2.jpg" },
            { type = "p", text = "The Golden Lotus and Shado-Pan guardians of the Vale of Eternal Blossoms were caught in the epicenter of the devastating blast that scarred the Vale and were torn apart by the dark energies. Their spirits linger in the place they once protected, confused and tormented by their failure." },
            { type = "image", width = 672, height = 420, u = 0.65625, v = 0.820312, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-04-mists-of-pandaria-classic-siege-of-orgrimmar-raid-now-live-4c6e929322\\image-3.jpg" },
            { type = "p", text = "Some say that the mogu race was created in the image of this titanic construct, left deep beneath Pandaria to watch over and guard the continent's darkest and most dangerous secret." },
            { type = "image", width = 672, height = 420, u = 0.65625, v = 0.820312, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-04-mists-of-pandaria-classic-siege-of-orgrimmar-raid-now-live-4c6e929322\\image-4.jpg" },
            { type = "p", text = "The seventh sha, the Sha of Pride, was the final burden to which Emperor Shaohao clung, shrouding the land in mist and biding its time for millennia. When Garrosh awakened the Heart of Y'shaarj, the force of his arrogance caused this dark energy to coalesce in the chamber where the Heart was unearthed." },
            { type = "hr" },
            { type = "h2", text = "STORM THE STRONGHOLD AND CONFRONT THE ENCOUNTERS WITHIN" },
            { type = "p", text = "With the crisis in the Vale contained, heroes of the Horde and the Alliance must take the war to Garrosh’s doorstep in Durotar, push past his outer defenses, and confront the evil festering within the gates of Orgrimmar." },
            { type = "h3", text = "Gates of Retribution" },
            { type = "p", text = "War has come to the gates of Orgrimmar, as Alliance forces and the Darkspear Rebellion seek revenge against Garrosh Hellscream." },
            { type = "image", width = 672, height = 420, u = 0.65625, v = 0.820312, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-04-mists-of-pandaria-classic-siege-of-orgrimmar-raid-now-live-4c6e929322\\image-5.jpg" },
            { type = "p", text = "Warlord Zaela formed a close bond with Garrosh during events in the Twilight Highlands, and she and her Dragonmaw orcs have pledged loyalty to Garrosh's cause. Riding atop the fearsome Galakras, a direct descendant of the cataclysmic progenitor of all dragonkind, Zaela oversees the naval defense of Orgrimmar." },
            { type = "image", width = 672, height = 420, u = 0.65625, v = 0.820312, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-04-mists-of-pandaria-classic-siege-of-orgrimmar-raid-now-live-4c6e929322\\image-6.jpg" },
            { type = "p", text = "This mechanical terror, designed nearly as much for intimidation as destruction, is the centerpiece of Garrosh's siege weaponry. Crafted in the image of the mighty Kor'kron war scorpion, the Iron Juggernaut guards the gates of Orgrimmar, crushing any who would rise to challenge Garrosh's True Horde." },
            { type = "image", width = 672, height = 420, u = 0.65625, v = 0.820312, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-04-mists-of-pandaria-classic-siege-of-orgrimmar-raid-now-live-4c6e929322\\image-7.jpg" },
            { type = "p", text = "Haromm and Kardris trained thousands of shaman to whisper reverently to the elements to requisition their aid. The army of Garrosh, however, does not ask; it takes what it desires in the name of the True Horde. Dark shamanism forces the elements into servitude, twisting them into burned-out ash, corrupted waters, and toxic air." },
            { type = "image", width = 672, height = 420, u = 0.65625, v = 0.820312, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-04-mists-of-pandaria-classic-siege-of-orgrimmar-raid-now-live-4c6e929322\\image-8.jpg" },
            { type = "p", text = "Once a grunt in the service of the former Warchief, Thrall, General Nazgrim rose quickly through the ranks after overwhelming victories in Grizzly Hills and the sunken city of Vashj'ir. Fiercely loyal to the Horde and bound by a rigorous code of honor and duty, Nazgrim will hold the line for his Warchief until his dying breath." },
            { type = "image", width = 672, height = 420, u = 0.65625, v = 0.820312, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-04-mists-of-pandaria-classic-siege-of-orgrimmar-raid-now-live-4c6e929322\\image-9.jpg" },
            { type = "p", text = "Malkorok has been Garrosh's most loyal and trusted lieutenant throughout the Pandaria campaign. When the Warchief needed a volunteer to infuse with the power of Y'Shaarj, it was only natural for Malkorok to offer without hesitation." },
            { type = "image", width = 672, height = 420, u = 0.65625, v = 0.820312, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-04-mists-of-pandaria-classic-siege-of-orgrimmar-raid-now-live-4c6e929322\\image-10.jpg" },
            { type = "p", text = "When Garrosh gazed across Pandaria, he saw untapped power. During the course of his campaign, Garrosh has plundered weapons, treasures, and artifacts of the pandaren, the mogu, and the mantid. They are kept in a warehouse deep within his underground base, guarded by a mysterious security system that appears to be of Titan origins." },
            { type = "image", width = 672, height = 420, u = 0.65625, v = 0.820312, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-04-mists-of-pandaria-classic-siege-of-orgrimmar-raid-now-live-4c6e929322\\image-11.jpg" },
            { type = "p", text = "When the Isle of Giants was discovered off the coast of Pandaria, teeming with primal devilsaurs, Garrosh sent men to capture some of the most fearsome specimens, hoping to subjugate them and use them as beasts of war. Countless orcish beastmasters have fallen to Thok's jaws as they struggle to tame him, yet the creature's thirst for blood remains unslaked." },
            { type = "h3", text = "Downfall" },
            { type = "p", text = "Wielding the dark power that lay dormant beneath Pandaria, Garrosh seeks to bring a new order to Azeroth. He must be stopped!" },
            { type = "image", width = 672, height = 420, u = 0.65625, v = 0.820312, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-04-mists-of-pandaria-classic-siege-of-orgrimmar-raid-now-live-4c6e929322\\image-12.jpg" },
            { type = "p", text = "Helix Blackfuse was the only goblin with the combination of engineering prowess, professionalism, and ruthlessness to satisfy Garrosh in his search for the engineer of the True Horde. A mercenary at heart, Blackfuse's love for his creations (and the gold they fetch) has forever linked his fate with that of his patron and Warchief." },
            { type = "image", width = 672, height = 420, u = 0.65625, v = 0.820312, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-04-mists-of-pandaria-classic-siege-of-orgrimmar-raid-now-live-4c6e929322\\image-13.jpg" },
            { type = "p", text = "The nine surviving Klaxxi'va Paragons are ancient champions of the mantid who fought alongside the Wakener against the madness of Empress Shek'zeer. But the paragons, as do all mantid, hold a far deeper loyalty. When Garrosh unearthed the heart of Y'Shaarj, the paragons followed the whispers of their ancient master to the iron halls beneath Orgrimmar." },
            { type = "image", width = 672, height = 420, u = 0.65625, v = 0.820312, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-04-mists-of-pandaria-classic-siege-of-orgrimmar-raid-now-live-4c6e929322\\image-14.jpg" },
            { type = "p", text = "Garrosh, son of Grommash Hellscream, first learned of his father’s heroism when Thrall encountered the young orc in Outland. With the seeds of pride planted, Garrosh spearheaded Horde victories in Northrend and, as Warchief, consolidated Horde power amid the chaos of the Cataclysm. But his vision of orc supremacy at any cost has brought the armies of the world crashing down upon Orgrimmar... and a reckoning Garrosh himself awaits with brutal relish." },
            { type = "hr" },
            { type = "h2", text = "SEIZE VICTORY AND CLAIM YOUR REWARDS" },
            { type = "p", text = "Bring the siege to its end and claim rewards forged in the downfall of Garrosh Hellscream." },
            { type = "p", text = "The Siege of Orgrimmar unfolds across two difficulties, each offering rewards for champions who endure the assault." },
            { type = "p", text = "Difficulty" },
            { type = "p", text = "Item Level" },
            { type = "p", text = "Warforged" },
            { type = "h3", text = "Normal" },
            { type = "p", text = "553" },
            { type = "p", text = "559" },
            { type = "h3", text = "Heroic" },
            { type = "p", text = "566" },
            { type = "p", text = "572" },
            { type = "hr" },
            { type = "h3", text = "Claim the Power of Tier 16 Gear" },
            { type = "image", width = 720, height = 256, u = 0.703125, v = 1, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-04-mists-of-pandaria-classic-siege-of-orgrimmar-raid-now-live-4c6e929322\\image-15.jpg" },
            { type = "p", text = "Siege of Orgrimmar introduces Tier 16 raid gear, with the full set available within the raid, and Garrosh Hellscream also has a chance to drop Essences, which can be exchanged for any Tier 16 piece." },
            { type = "p", text = "Here are the specific bosses that drop Tier Set armor in Siege of Orgrimmar:" },
            { type = "p", text = "Token" },
            { type = "p", text = "Boss" },
            { type = "p", text = "Helm" },
            { type = "p", text = "Thok the Bloodthirsty" },
            { type = "p", text = "Shoulders" },
            { type = "p", text = "Siegecrafter Blackfuse" },
            { type = "p", text = "Chest" },
            { type = "p", text = "Sha of Pride" },
            { type = "p", text = "Legs" },
            { type = "p", text = "Paragons of the Klaxxi" },
            { type = "p", text = "Gloves" },
            { type = "p", text = "General Nazgrim" },
            { type = "p", text = "The following classes share Armor Tokens:" },
            { type = "list_item", text = "Vanquisher : Death Knight, Druid, Mage and Rogue", level = 0 },
            { type = "list_item", text = "Conqueror : Paladin, Priest and Warlock", level = 0 },
            { type = "list_item", text = "Protector : Hunter, Monk, Shaman, and Warrior", level = 0 },
            { type = "p", text = "Exchange Armor Tokens for Tier 16 set pieces at vendors on the second-floor balconies of the faction shrines in the Vale of Eternal Blossoms:" },
            { type = "list_item", text = "Alliance : Clarice Chapmann (Normal) and Lorry Warmheart (Heroic) at the Shrine of the Seven Stars", level = 0 },
            { type = "list_item", text = "Horde : Ki’agnuu (Normal) and Tu’aho Pathcutter (Heroic) at the Shrine of the Two Moons", level = 0 },
            { type = "h3", text = "Claim Glory and Take to the Skies" },
            { type = "p", text = "Complete all fourteen challenge achievements to earn the “Glory of the Orgrimmar Raider” meta-achievement for the Reins of Galakras, teaching brave champions how to summon the Spawn of Galakras flying mount." },
            { type = "image", width = 720, height = 405, u = 0.703125, v = 0.791016, file = "Interface\\AddOns\\BluePosts\\Media\\Posts\\2026-06-04-mists-of-pandaria-classic-siege-of-orgrimmar-raid-now-live-4c6e929322\\image-16.jpg" },
            { type = "h3", text = "With Great Glory Come Great Achievements" },
            { type = "p", text = "Achievement" },
            { type = "p", text = "Description" },
            { type = "p", text = "“No More Tears”" },
            { type = "p", text = "Defeat Immerseus after killing 10 Tears of the Vale in Siege of Orgrimmar on Normal or Heroic difficulty." },
            { type = "p", text = "“Go Long”" },
            { type = "p", text = "Transfer the Mark of Anguish to at least 5 unique players over a total of 200 yards or more during a single Desperate Measures phase and then defeat the Fallen Protectors in Siege of Orgrimmar on Normal or Heroic difficulty." },
            { type = "p", text = "“None Shall Pass”" },
            { type = "p", text = "Defeat the Amalgam of Corruption without allowing any unleashed corruption to fuse with it in Siege of Orgrimmar on Normal or Heroic difficulty." },
            { type = "p", text = "“Swallow Your Pride”" },
            { type = "p", text = "Defeat the Sha of Pride in Siege of Orgrimmar on Normal or Heroic difficulty after no player has gained Pride from Manifestations of Pride while Norushen is alive." },
            { type = "p", text = "“The Immortal Vanguard”" },
            { type = "p", text = "Defeat Galakras without having allowed a single friendly NPC to perish in battle in Siege of Orgrimmar on Normal or Heroic difficulty." },
            { type = "p", text = "“Fire in the Hole”" },
            { type = "p", text = "Stomp on 6 superheated Crawler Mines and then defeat the Iron Juggernaut in Siege of Orgrimmar on Normal or Heroic difficulty." },
            { type = "p", text = "“Rescue Raiders”" },
            { type = "p", text = "Rescue a set of caged prisoners, a group of unwilling combat participants, and Ji Firepaw before defeating the Kor'kron Dark Shaman in Siege of Orgrimmar on Normal or Heroic difficulty." },
            { type = "p", text = "“Gamon Will Save Us!”" },
            { type = "p", text = "Defeat General Nazgrim while Gamon is alive and participating in the battle in Siege of Orgrimmar on Normal or Heroic difficulty." },
            { type = "p", text = "“Unlimited Potential”" },
            { type = "p", text = "Transform a Corrupted Skullsplitter into a Corrupted Amalgamation and then defeat Malkorok in Siege of Orgrimmar on Normal or Heroic difficulty." },
            { type = "p", text = "“Criss Cross”" },
            { type = "p", text = "Complete the Spoils of Pandaria encounter in Siege of Orgrimmar on Normal or Heroic difficulty without any raid member defeating both a Mantid and a Mogu enemy." },
            { type = "p", text = "“Giant Dinosaur vs. Mega Snail”" },
            { type = "p", text = "Open the Thrice-Locked Cage during the Thok the Bloodthirsty encounter in Siege of Orgrimmar on Normal or Heroic difficulty, and then allow its inhabitant to feast upon Thok's corpse once you have defeated the encounter." },
            { type = "p", text = "“Lasers and Magnets and Drills! Oh My!”" },
            { type = "p", text = "Defeat Siegecrafter Blackfuse without destroying each of the following weapons in Siege of Orgrimmar on Normal or Heroic difficulty: Deactivated Laser Turret, Deactivated Missile Turret, Deactivated Electromagnet, and Disassembled Crawler Mines." },
            { type = "p", text = "“Now We are the Paragon”" },
            { type = "p", text = "Defeat the Paragons after assuming the mantle of three different Paragons in Siege of Orgrimmar on Normal or Heroic difficulty." },
            { type = "p", text = "“Strike!”" },
            { type = "p", text = "Kill 18 Kor'kron Warbringers with a single Iron Star and then defeat Garrosh in Siege of Orgrimmar on Normal or Heroic difficulty." },
            { type = "hr" },
            { type = "p", text = "Garrosh’s reign stands on the brink of ruin. Champions of the Alliance and the Horde must press the assault forward, topple the ruthless Warchief, and claim the rewards and achievements won in victory." },
            },
        },
        ["2026-06-04-hotfixes-june-3-2026-a0243cda21"] = {
            id = "2026-06-04-hotfixes-june-3-2026-a0243cda21",
            post_key = "a0243cda21",
            title = "Hotfixes: June 3, 2026",
            category = "Blogs (US)",
            timestamp = 1780534200,
            url = "https://news.blizzard.com/en-us/article/24276957/hotfixes-june-2-2026",
            content = {
            { type = "p", text = "Here you'll find a list of hotfixes that address various issues related to World of Warcraft: Midnight, Mists of Pandaria Classic, Season of Discovery, Burning Crusade Classic, WoW Classic Era, and Hardcore. Some of the hotfixes below take effect the moment they were implemented, while others may require scheduled realm restarts to go into effect. Please keep in mind that some issues cannot be addressed without a client-side patch update. This list will be updated as additional hotfixes are applied." },
            { type = "h2", text = "HOTFIXES" },
            { type = "hr" },
            { type = "h3", text = "June 3, 2026" },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Reduced the gold costs of Transmog outfit and slots by 90%.", level = 0 },
            { type = "dev_note", text = "Patch 5.5.4 was released with these gold costs unintentionally set too high.", level = 1 },
            { type = "list_item", text = "Removed Prideful Gladiator gear that was temporarily, unintentionally rewarded from World Bosses.", level = 0 },
            { type = "list_item", text = "Fixed a bug causing Battle Fatigue to work incorrectly in PvP.", level = 0 },
            { type = "list_item", text = "Fixed a bug preventing Warforged Seals from having a rolling weekly cap as expected.", level = 0 },
            { type = "list_item", text = "Fixed a bug preventing players from mounting Spectral Gryphon or Spectral Wind Rider as intended.", level = 0 },
            { type = "list_item", text = "Fixed a bug that briefly prevented players on some realms from buying replacement cloaks or starting legendary and quests.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "June 2, 2026" },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Death Knight", level = 0 },
            { type = "list_item", text = "Unholy", level = 1 },
            { type = "list_item", text = "Resolved an issue causing Unholy Aura and Forbidden Ritual to be canceled earlier than expected.", level = 2 },
            { type = "h3", text = "Items" },
            { type = "list_item", text = "Fixed an issue with the Darkmoon Dominion: Blood trinket proccing for multiple stats if they're all equally the lowest stat.", level = 0 },
            { type = "h3", text = "The Burning Crusade Classic" },
            { type = "list_item", text = "Player versus Player", level = 0 },
            { type = "list_item", text = "Following an Arena match, the user interface now displays the pre-match Matchmaking Ratings (MMR) for each team.", level = 1 },
            { type = "dev_note", text = "Our goal is to provide more information, so that players can better contextualize their changing MMR.", level = 2 },
            { type = "h3", text = "Mists of Pandaria Classic" },
            { type = "list_item", text = "Classes", level = 0 },
            { type = "list_item", text = "Death Knight", level = 1 },
            { type = "list_item", text = "Blood", level = 2 },
            { type = "list_item", text = "Bloodworms again have avoidance of area-of-effect spells.", level = 3 },
            { type = "hr" },
            { type = "h3", text = "May 26, 2026" },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Demon Hunter", level = 0 },
            { type = "dev_note", text = "Aldrachi Reaver performance has been below its alternative Hero Talent options, so we’re buffing some of its effects to reduce the disparity.", level = 1 },
            { type = "list_item", text = "Havoc", level = 1 },
            { type = "list_item", text = "Death Sweep damage increased by 10%.", level = 2 },
            { type = "dev_note", text = "This resolves an issue from a previous update where Blade Dance damage was increased, but Death Sweep’s damage was not correctly updated to match. The base damage of Death Sweep is intended to be 30% more than that of Blade Dance.", level = 2 },
            { type = "list_item", text = "Aldrachi Reaver: Reaver’s Glaive damage increased by 15%.", level = 2 },
            { type = "list_item", text = "Aldrachi Reaver: Warblade’s Hunger damage increased by 55%.", level = 2 },
            { type = "list_item", text = "Aldrachi Reaver: Wounded Quarry now deals 30% of Physical damage to the target of your Reaver’s Mark (was 25%).", level = 2 },
            { type = "list_item", text = "Vengeance", level = 1 },
            { type = "list_item", text = "Aldrachi Reaver: Reaver’s Glaive damage increased by 30%.", level = 2 },
            { type = "list_item", text = "Aldrachi Reaver: Warblade’s Hunger damage increased by 55%.", level = 2 },
            { type = "list_item", text = "Aldrachi Reaver: Wounded Quarry now deals 25% of Physical damage to the target of your Reaver’s Mark (was 20%).", level = 2 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Feral", level = 1 },
            { type = "list_item", text = "All damage dealt increased by 4%.", level = 2 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Arcane", level = 1 },
            { type = "dev_note", text = "In addition to an overall damage buff, we’d like to get Sunfury’s damage closer to Spellslinger’s.", level = 2 },
            { type = "list_item", text = "All ability damage increased by 5%. Does not apply to PvP.", level = 2 },
            { type = "list_item", text = "Arcane Missiles damage increased by 10%. Does not apply to PvP.", level = 2 },
            { type = "list_item", text = "Sunfury: Burden of Power - Arcane Blast damage bonus increased to 30% (was 25%). Arcane Pulse damage bonus increased to 20% (was 15%).", level = 2 },
            { type = "list_item", text = "Fire", level = 1 },
            { type = "dev_note", text = "These changes are intended to increase Fire’s single target damage. The value of the increase should be comparable for all Hero Talent options.", level = 2 },
            { type = "list_item", text = "Pyroblast damage increased by 8%. Does not apply to PvP.", level = 2 },
            { type = "list_item", text = "Frostfire: Frostfire Bolt damage increased by 5%. Does not apply to PvP.", level = 2 },
            { type = "list_item", text = "Frost", level = 1 },
            { type = "dev_note", text = "Frostfire performance is farther behind Spellslinger than we’re happy with, so we’re boosting a number of its talents to increase their single target and AOE damage.", level = 2 },
            { type = "list_item", text = "Frostfire: Frostfire Bolt damage increased by 5%. Does not apply to PvP", level = 2 },
            { type = "list_item", text = "Frostfire: Duality - Pyroblast damage increased by 25%.", level = 2 },
            { type = "list_item", text = "Frostfire: Dualcasting Adept - Shatter damage bonus increased to 40% (was 15%).", level = 2 },
            { type = "list_item", text = "Frostfire: Heat Sink - Flurry damage bonus increased to 25% (was 10%).", level = 2 },
            { type = "list_item", text = "Frostfire: Blast Radius - Comet Storm damage bonus increased to 50% (was 20%).", level = 2 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Retribution", level = 1 },
            { type = "dev_note", text = "Herald of the Sun has been trailing behind Templar in overall throughput. To improve its output, we’re extending its effective damage window by granting an additional Dawnlight charge. We’re also aiming to further improve its AoE performance by increasing the duration extension provided by Divine Storm.", level = 2 },
            { type = "list_item", text = "Wake of Ashes now causes the next 3 Holy Power spending abilities to apply a Dawnlight (was 2).", level = 2 },
            { type = "list_item", text = "Endless Gleam now extends Dawnlight’s duration by an additional 0.5 seconds when Divine Storm strikes at least 2 Dawnlights (was 0.3 seconds).", level = 2 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "dev_note", text = "We’re reducing the mana costs of some core spell casts so Holy Priest can feel more comfortable casting Prayer of Healing and Flash Heal, particularly in raid settings.", level = 2 },
            { type = "list_item", text = "Flash Heal mana cost reduced by 8%.", level = 2 },
            { type = "list_item", text = "Benediction mana cost reduced by 8%.", level = 2 },
            { type = "list_item", text = "Prayer of Mending mana cost reduced by 8%.", level = 2 },
            { type = "list_item", text = "Prayer of Healing mana cost reduced by 8%.", level = 2 },
            { type = "list_item", text = "Rogue", level = 0 },
            { type = "dev_note", text = "Deathstalker damage is below the other Hero Talent options for most content and damage profiles, especially for Assassination, and to the least degree for Subtlety single target output. Changes are targeted at improving Deathstalker’s total performance compared to each specialization’s alternative.", level = 1 },
            { type = "list_item", text = "Assassination", level = 1 },
            { type = "list_item", text = "Deathstalker: Deathstalker’s Mark damage increased by 30%.", level = 2 },
            { type = "list_item", text = "Deathstalker: Clear the Witnesses now increases Fan of Knives damage by 60% (was 40%).", level = 2 },
            { type = "list_item", text = "Deathstalker: Hunt Them Down damage increased by 25%.", level = 2 },
            { type = "list_item", text = "Deathstalker: Corrupt the Blood now increases Rupture damage by 20% (was 10%).", level = 2 },
            { type = "list_item", text = "Deathstalker: Darkest Night effect now increases Envenom damage by 35% (was 30%).", level = 2 },
            { type = "list_item", text = "Subtlety", level = 1 },
            { type = "list_item", text = "Deathstalker: Deathstalker’s Mark damage increased by 30%.", level = 2 },
            { type = "list_item", text = "Deathstalker: Clear the Witnesses now increases Shuriken Storm damage by 60% (was 40%).", level = 2 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "Elemental", level = 1 },
            { type = "list_item", text = "Farseer: Ancestral Spirits from the Farseer Hero Talent tree now benefit from the critical damage increase of the Elemental Fury talent.", level = 2 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "dev_note", text = "We’re adjusting the mana costs of some of Restoration Shaman’s basic spell casts to give them more room to spend mana on things like Chain Heal particularly in raid settings.", level = 2 },
            { type = "list_item", text = "The mana cost of Chain Heal, Healing Wave, and Riptide has been reduced by 5%.", level = 2 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "dev_note", text = "These change aim to improve Colossus’ performance in single target and Mountain Thane’s performance in AOE relative to other Hero Talent options.", level = 1 },
            { type = "list_item", text = "Arms", level = 1 },
            { type = "list_item", text = "Colossus: Practiced Strikes - Mortal Strike and Slam damage increased by 25% (was 15%). Does not apply to PvP.", level = 2 },
            { type = "list_item", text = "Fury", level = 1 },
            { type = "list_item", text = "Mountain Thane: Thunder Blast damage increased by 30%. Does not apply to PvP.", level = 2 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "list_item", text = "Colossus: Practiced Strikes - Shield Slam damage increased by 25% (was 15%). Does not apply to PvP.", level = 2 },
            { type = "list_item", text = "Mountain Thane: Thunder Blast damage increased by 30%. Does not apply to PvP.", level = 2 },
            { type = "h3", text = "Player versus Player" },
            { type = "list_item", text = "Death Knight", level = 0 },
            { type = "list_item", text = "Unholy", level = 1 },
            { type = "list_item", text = "San’layn: Vampiric Strike damage increased by 30% in PvP combat.", level = 2 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Balance", level = 1 },
            { type = "list_item", text = "Elune’s Chosen: Lunar Calling now increases Starfire damage by an additional 20% in PvP combat.", level = 2 },
            { type = "list_item", text = "Feral", level = 1 },
            { type = "list_item", text = "Druid of the Claw: Ravage damage increased by 20% in PvP combat.", level = 2 },
            { type = "list_item", text = "Evoker", level = 0 },
            { type = "list_item", text = "Preservation", level = 1 },
            { type = "dev_note", text = "Preservation has pulled ahead of the other healers partially due to their ability to withstand crowd control but also due to their raw healing output. We’re reducing some of their throughput capabilities and also the uptime on Nullifying Shroud to bring them in line.", level = 2 },
            { type = "list_item", text = "All healing reduced by 5% in PvP combat.", level = 2 },
            { type = "list_item", text = "Nullifying Shroud duration reduced to 3 seconds (was 4 seconds).", level = 2 },
            { type = "list_item", text = "Dream Breath instant healing reduced by 17% in PvP combat.", level = 2 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Survival", level = 1 },
            { type = "dev_note", text = "Survival has a strong burst window with Takedown, but outside of that, they are lacking. We’d like to reduce the heavy burst of Takedown and redistribute that power to compensate.", level = 2 },
            { type = "list_item", text = "Takedown damage reduced by 25% in PvP.", level = 2 },
            { type = "list_item", text = "Damage of all spells and abilities increased by 6% in PvP.", level = 2 },
            { type = "list_item", text = "Mage", level = 0 },
            { type = "list_item", text = "Fire", level = 1 },
            { type = "dev_note", text = "We’d like to increase Fire’s steady state damage by adjusting Fireball to reward casting, and Meteor has been harder to justify picking up than we would like in PvP.", level = 2 },
            { type = "list_item", text = "Fireball and Frostfire Bolt damage increased by 35% in PvP combat.", level = 2 },
            { type = "list_item", text = "Meteor direct damage increased by 30% in PvP combat.", level = 2 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "dev_note", text = "Holy Light’s mana cost is more restrictive in PvP than intended, so we’re adjusting Divine Favor to make its use less punishing long-term. Divine Favor now reduces the mana cost of Holy Light by 30% (was 10%) in PvP combat.", level = 2 },
            { type = "list_item", text = "Fixed an issue that caused Denounce to not scale its damage with level or with buffs such as Avenging Wrath. This is about a 90% increase to its baseline output.", level = 2 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "dev_note", text = "Protection Paladin’s damage capabilities have been higher than healthy for a spec with its utility.", level = 2 },
            { type = "list_item", text = "All damage reduced by 10% in PvP combat.", level = 2 },
            { type = "list_item", text = "Retribution", level = 1 },
            { type = "dev_note", text = "We’re adjusting Divine Exaction’s effectiveness to reduce Retribution’s burst window.", level = 2 },
            { type = "list_item", text = "Templar: Divine Exaction down to 75% (was 150%) in PvP combat.", level = 2 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Holy", level = 1 },
            { type = "dev_note", text = "We’re reducing the mana cost of a few core spells for Holy Priest this week (see PvE changes for details) which is intended to help with healing in longer engagements. Additionally, Archon has felt weak compared to Oracle, so we’re targeting a buff to Halo to improve its viability.", level = 2 },
            { type = "list_item", text = "Archon: Halo damage and healing increased by 25% in PvP combat.", level = 2 },
            { type = "list_item", text = "Shadow", level = 1 },
            { type = "dev_note", text = "We feel Voidweaver is in a good position in PvP. Archon’s pressure is lacking in comparison, so we’re targeting some of its spells to improve its output.", level = 2 },
            { type = "list_item", text = "Archon: Halo damage and healing increased by 25% in PvP combat.", level = 2 },
            { type = "list_item", text = "Archon: Mind Flay Insanity damage increased by 25% in PvP combat.", level = 2 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "Elemental", level = 1 },
            { type = "dev_note", text = "Elemental is often relying on Ascendance for kills due to its high burst potential. These changes are intended to increase overall pressure while reducing reliance on cooldowns to score skills.", level = 2 },
            { type = "list_item", text = "Bloodlust and Heroism from Shamanism now increases haste by 15% (was 20%)", level = 2 },
            { type = "list_item", text = "Ascendance now increases Elemental Overload damage by 10% in PvP Combat (was 25%).", level = 2 },
            { type = "list_item", text = "Lava Burst damage increased by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Lightning Bolt damage increased by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Enhancement", level = 1 },
            { type = "dev_note", text = "Enhancement burst has been hard to react to during cooldowns due to a Maelstrom Weapon bug we’re fixing. In addition, we’re toning down the haste gained from Shamanism to reduce the cooldown pressure from Shaman DPS specializations.", level = 2 },
            { type = "list_item", text = "Bloodlust and Heroism from Shamanism now increases haste by 15% (was 20%) in PvP.", level = 2 },
            { type = "list_item", text = "Resolved an issue causing Malestrom Weapon spenders from Thorim’s Invocation during Doom Winds to deal more damage than intended.", level = 2 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Affliction", level = 1 },
            { type = "dev_note", text = "Hellcaller has underperformed compared to Soul Harvester and we would like to shrink that gap.", level = 2 },
            { type = "list_item", text = "Hellcaller: Blackened Soul damage increased by 35% in PvP combat.", level = 2 },
            { type = "list_item", text = "Hellcaller: Wither damage increased by 15% in PvP combat.", level = 2 },
            { type = "list_item", text = "Hellcaller: Mark of Xavius now causes Blackened Soul to deal 4% increased damage per stack of Wither in PvP combat (was 2%).", level = 2 },
            { type = "list_item", text = "Demonology", level = 1 },
            { type = "dev_note", text = "For Demonology and Destruction, we’re pulling back on some of the previous reductions to Conflagrate and Ruination as they were proving to be a little heavy handed. We’re also bringing up the damage of core casts like Incinerate and Hand of Gul’dan to reward Warlocks more for successful casts.", level = 2 },
            { type = "list_item", text = "Hand of Gul’dan damage increased by 30% in PvP combat.", level = 2 },
            { type = "list_item", text = "Diabolist: Ruination damage increased by 100% in PvP combat.", level = 2 },
            { type = "list_item", text = "Destruction", level = 1 },
            { type = "list_item", text = "Incinerate damage increased by 30% in PvP combat.", level = 2 },
            { type = "list_item", text = "Conflagrate damage increased by 60% in PvP combat.", level = 2 },
            { type = "list_item", text = "Diabolist: Ruination damage increased by 100% in PvP combat.", level = 2 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "dev_note", text = "Berserker Roar’s duration has been overly disruptive. Decreasing it should open up more options when deciding how to handle its effect.", level = 1 },
            { type = "list_item", text = "Berserker Roar’s duration reduced to 5 seconds (was 10 seconds).", level = 1 },
            { type = "list_item", text = "Arms", level = 1 },
            { type = "dev_note", text = "Arms’ overall pressure output has been slightly higher than we would like, so we’re tweaking their damage down to land them in a healthier spot.", level = 2 },
            { type = "list_item", text = "All damage reduced by 3% in PvP combat.", level = 2 },
            { type = "hr" },
            { type = "h3", text = "May 22, 2026" },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Death Knight", level = 0 },
            { type = "list_item", text = "Unholy", level = 1 },
            { type = "list_item", text = "Resolved an issue causing Forbidden Ritual aura to remain permanently on the Death Knight.", level = 2 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "list_item", text = "Reduced the number of sounds and visuals that play when using the talent Flourish with Tranquility.", level = 2 },
            { type = "list_item", text = "Priest", level = 0 },
            { type = "list_item", text = "Discipline", level = 1 },
            { type = "list_item", text = "Master the Darkness can now be tracked in the cooldown manager.", level = 2 },
            { type = "h3", text = "Player versus Player" },
            { type = "list_item", text = "There is no longer a cap on the total number of Bloody Tokens a player may accumulate.", level = 0 },
            { type = "list_item", text = "Resolved an issue that could prevent players from earning Slayer's Rise Dominance while holding all bases.", level = 0 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "list_item", text = "Fixed an issue where Guardian of the Forgotten Queen could not be interrupted by some crowd control effects as intended.", level = 2 },
            { type = "hr" },
            { type = "h3", text = "May 19, 2026" },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Retribution", level = 1 },
            { type = "list_item", text = "Templar: Resolved an issue causing Hammer of Light to not cast properly in high haste situations.", level = 2 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Affliction", level = 1 },
            { type = "list_item", text = "Fixed an issue where Soul Swap would carry Unstable Affliction stacks when entering or exiting an instanced area.", level = 2 },
            { type = "h3", text = "Dungeons and Raids" },
            { type = "list_item", text = "March on Quel’Danas", level = 0 },
            { type = "list_item", text = "The Hall of Fame for players who have completed Mythic difficulty is now closed.", level = 1 },
            { type = "list_item", text = "Midnight Falls", level = 1 },
            { type = "list_item", text = "Fixed an issue causing The Dark Archangel to sometimes not cancel upon triggering the final phase on Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Heaven’s Glaives maximum duration reduced to 1 minute (was 2 minutes).", level = 2 },
            { type = "list_item", text = "Reduced the spread of Midnight Crystals on Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Starsplinter initial damage reduced by 20% on Mythic difficulty.", level = 2 },
            { type = "list_item", text = "Criticality damage reduced by 20%.", level = 2 },
            { type = "h3", text = "Items and Rewards" },
            { type = "list_item", text = "There is no longer a cap on the amount of upgrade Crests that can be accumulated by each player.", level = 0 },
            { type = "h3", text = "Player versus Player" },
            { type = "list_item", text = "There is no longer a cap on the amount of Conquest that can be earned, for the rest of Season 1.", level = 0 },
            { type = "h3", text = "Quests" },
            { type = "list_item", text = "The repeatable “Legends of the Haranir” quests are now available to player-characters who belong to a Warband that includes a character who has completed the first-time versions of the quests, and they may now be obtained by more than one character in your warband per week.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "May 15, 2026" },
            { type = "h3", text = "Achievements" },
            { type = "list_item", text = "Reservation for One will now be granted to players who collect Mythic-tier fish meat multiple times in the same run.", level = 0 },
            { type = "list_item", text = "Additionally fixed issues with the Champion of Pahk creature in Abyss Anglers that caused it to disappear before players could catch it.", level = 1 },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Delves", level = 0 },
            { type = "list_item", text = "Nemesis Squads should no longer spawn under the world in Parhelion Plaza.", level = 1 },
            { type = "h3", text = "Decor Duel" },
            { type = "list_item", text = "Hiders can no longer swap with Enchanted Decoys.", level = 0 },
            { type = "h3", text = "Dungeons and Raids" },
            { type = "list_item", text = "The Voidspire", level = 0 },
            { type = "list_item", text = "A teleport pad now appears in the Isle of Quel'Danas for raid groups that used the raid shortcut and have bosses to defeat.", level = 1 },
            { type = "list_item", text = "Fallen-King Salhadaar", level = 1 },
            { type = "list_item", text = "Resolved an issue making the Broken Oath warning unmovable in Edit Mode.", level = 2 },
            { type = "h3", text = "Player versus Player" },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Beast Mastery", level = 1 },
            { type = "list_item", text = "Bestial Wrath now displays as important on enemy nameplates.", level = 2 },
            { type = "hr" },
            { type = "h3", text = "May 12, 2026" },
            { type = "h3", text = "Achievements" },
            { type = "list_item", text = "Abyss Anglers: Depth Grease no longer requires the Reinforced Joints upgrade.", level = 0 },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Death Knight", level = 0 },
            { type = "list_item", text = "Blood", level = 1 },
            { type = "dev_note", text = "We are looking at smoothing out the damage intake of Blood outside of their cooldown window by increasing the consistency and uptime of their Apex Talent. To further help these windows of high damage intake we are also increasing their Health and Death Strike healing.", level = 2 },
            { type = "list_item", text = "Dancing Rune Weapon grants 25% Parry (was 20%).", level = 2 },
            { type = "list_item", text = "Blood Fortification grants 40% Stamina (was 35%).", level = 2 },
            { type = "list_item", text = "Improved Death Strike healing increased to 15% (was 5%).", level = 2 },
            { type = "list_item", text = "Dance of Midnight grants Dancing Rune Weapon for 8 seconds (was 6 seconds).", level = 2 },
            { type = "list_item", text = "Dance of Midnight chance to proc increased to 12.5% (was 10%).", level = 2 },
            { type = "list_item", text = "Unholy", level = 1 },
            { type = "list_item", text = "Death and Decay can now be tracked in the cooldown manager.", level = 2 },
            { type = "list_item", text = "Demon Hunter", level = 0 },
            { type = "list_item", text = "Vengeance", level = 1 },
            { type = "dev_note", text = "Vengeance Demon Hunter’s baseline defenses are its most lacking, while cooldown availability and values are currently serving the spec well. As a result, we will be primarily targeting core values for Health and damage reduction, with an additional smaller increase specifically to Armor.", level = 2 },
            { type = "list_item", text = "Demonic Wards now reduces all damage taken by 12% (was 8%).", level = 2 },
            { type = "list_item", text = "Thick Skin now grants 55% increased Stamina (was 50%).", level = 2 },
            { type = "list_item", text = "Effectiveness of Mastery: Fel Blood increased by 20%.", level = 2 },
            { type = "list_item", text = "Void Reaver now causes Frailty to reduce damage taken by 5% (was 4%).", level = 2 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Guardian", level = 1 },
            { type = "list_item", text = "Thrash direct damage reduced by 25%.", level = 2 },
            { type = "list_item", text = "Elune’s Favored now heals for 15% of Arcane damage dealt (was 25%).", level = 2 },
            { type = "dev_note", text = "These changes aim to bring this build closer to its expected output: high-damage relative to other tanks, but not abnormally so. Recent previous adjustments to Guardian have made the Elune’s Chosen build stronger than intended. With this tuning, we’re choosing to not break the Elune’s Chosen build or require the Apex talent. We have further plans to update the Guardian Apex Talent in a future patch to give us more flexibility with it and alleviate some of the current pain points for Druids.", level = 2 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Marksmanship", level = 1 },
            { type = "list_item", text = "Corrected an issue where Explosive Shot applied from the Salvo talent did not properly grant Lock and Load from the Shrapnel Shot talent when applied.", level = 2 },
            { type = "list_item", text = "Paladin", level = 0 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "dev_note", text = "With these changes, we’re aiming to improve baseline durability for Protection Paladins by increasing passive effects which contribute to effective health. We’re also addressing on-demand survivability with adjustments to defensive cooldown coverage and strength.", level = 2 },
            { type = "list_item", text = "Blessing of Dusk reduces damage taken by up to 20%, increasing as your health decreases (was 10%).", level = 2 },
            { type = "list_item", text = "Sanctified Plates increases stamina by 7/15% (was 5/10%).", level = 2 },
            { type = "list_item", text = "Ardent Defender duration increased to 12 seconds (was 8 seconds).", level = 2 },
            { type = "list_item", text = "Ardent Defender now reduces damage taken by 30% (was 20%).", level = 2 },
            { type = "list_item", text = "Sentinel duration increased to 20 seconds (was 16 seconds).", level = 2 },
            { type = "list_item", text = "Shaman", level = 0 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "list_item", text = "Corrected an issue where Downpour would consume Nature's Swiftness and Ancestral Swiftness.", level = 2 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Diabolist: Fixed an issue where Diabolic Oculi would target creatures that are not in combat with their summoner.", level = 1 },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "Protection", level = 1 },
            { type = "dev_note", text = "Protection melee damage mitigation is quite strong, but is a bit behind for magical attacks and damage-over-time effects. These changes are aimed at strengthening those areas as well as making it easier to maintain healthy Ignore Pain values.", level = 2 },
            { type = "list_item", text = "Fight Through Flames reduces magic damage taken by 6% (was 4%).", level = 2 },
            { type = "list_item", text = "Phalanx reduces damage enemies deal to you by 8% (was 5%).", level = 2 },
            { type = "list_item", text = "Ignore Pain effectiveness increased by 8%.", level = 2 },
            { type = "h3", text = "Delves" },
            { type = "list_item", text = "Light spores in Sunkiller Sanctum should no longer interrupt channeled spells.", level = 0 },
            { type = "h3", text = "Housing" },
            { type = "list_item", text = "Players who purchased the Roofus bundle can now buy additional copies of the decor in that bundle from promotional decor resupply vendors in Stormwind (Tuuran), Orgrimmar (Gabbi), and Silvermoon City (Dennia Silvertongue).", level = 0 },
            { type = "h3", text = "Items" },
            { type = "list_item", text = "Fixed an issue where the Dundun's Abundant Travel Method toy would teleport players to the incorrect location.", level = 0 },
            { type = "list_item", text = "Fixed an issue preventing weapons and trinkets crafted before 12.0.5 from being eligible for Ascendant Voidcore upgrades.", level = 0 },
            { type = "h3", text = "Prey" },
            { type = "list_item", text = "Removed the once per week restriction on Preferential Killing which generates a hunt with custom parameters. Players may complete Custom Hunts as often as desired after reaching rank 10 in the Season 1 Prey Journey, but subsequent Custom Hunts in a week give reduced rewards.", level = 0 },
            { type = "list_item", text = "Increased Prey hunt progress gained from completing World Quests, defeating Ambushes, delivering Ripostes, and interacting with Remnants of Anguish.", level = 0 },
            { type = "list_item", text = "Removed Hunter's Momentum from Hard and Nightmare mode Prey hunts.", level = 0 },
            { type = "list_item", text = "Significantly increased the number of the Coalescing Anguish spawns in the outdoor world.", level = 0 },
            { type = "h3", text = "Player versus Player" },
            { type = "list_item", text = "Significantly increased rating gains from completing 2v2, 3v3, and Solo Shuffle matches.", level = 0 },
            { type = "dev_note", text = "This adjustment is intended to meaningfully improve progression as the season continues to support healthier ladder movement. We'll continue to monitor rating distribution and make further adjustments if needed.", level = 0 },
            { type = "h3", text = "Void Assaults" },
            { type = "list_item", text = "Increased the progress gained for certain Void Assault steps.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "May 8, 2026" },
            { type = "h3", text = "Abyss Anglers" },
            { type = "list_item", text = "Resolved an issue in Abyss Anglers where some players weren't able to complete the Achievement Depth Grease , even if they had met the correct conditions.", level = 0 },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Monk", level = 0 },
            { type = "list_item", text = "Mistweaver", level = 1 },
            { type = "list_item", text = "Fixed an issue that caused Rushing Wind Kick's heal to sometimes fail.", level = 2 },
            { type = "h3", text = "Dungeons and Raids" },
            { type = "list_item", text = "Magisters Terrace", level = 0 },
            { type = "list_item", text = "Fixed an issue where sometimes Gemellus would fail to resume using abilities if a player died during Astral Grasp.", level = 1 },
            { type = "list_item", text = "Nexus-Point Xenas", level = 0 },
            { type = "list_item", text = "Fixed an issue causing Mana Batteries to appear as a neutral faction while casting Corespark Overload.", level = 1 },
            { type = "list_item", text = "The Voidspire", level = 0 },
            { type = "list_item", text = "Using the raid skip no longer causes players to automatically teleport when returning to the entrance.", level = 1 },
            { type = "h3", text = "Quests" },
            { type = "list_item", text = "Fixed an issue that prevented repeat play of \"The Story of the Cauldron of Echoes\".", level = 0 },
            { type = "list_item", text = "Resolved an issue where players could be blocked from accepting \"Rescue in the Shadows\" if they had completed \"Crypt in the Mist\" during the Zul'Aman campaign.", level = 0 },
            { type = "h3", text = "User Interface" },
            { type = "list_item", text = "Fixed a bug causing Wings of the Void to unintentionally appear in the Spellbook.", level = 0 },
            { type = "hr" },
            { type = "h3", text = "May 6, 2026" },
            { type = "h3", text = "Abyss Anglers" },
            { type = "list_item", text = "Ka'bubb the capybara will now join your Abyss Anglers dives once you've earned the Certified Depthdiver", level = 0 },
            { type = "list_item", text = "Solved an issue in Abyss Anglers where some players couldn’t complete the Achievement Depth Grease , even if they had accomplished the correct conditions.", level = 0 },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "list_item", text = "Incarnation: Tree of Life's duration can now be tracked in the cooldown manager while talented into Reforestation without Incarnation: Tree of Life.", level = 2 },
            { type = "list_item", text = "Monk", level = 0 },
            { type = "list_item", text = "Brewmaster", level = 1 },
            { type = "list_item", text = "Fixed an issue where Flurry Strikes did not correctly generate threat.", level = 2 },
            { type = "list_item", text = "Fixed an issue where Vital Flame and Refreshing Drink incorrectly generated healing threat.", level = 2 },
            { type = "list_item", text = "Warlock", level = 0 },
            { type = "list_item", text = "Affliction", level = 1 },
            { type = "list_item", text = "Fixed an issue where sometimes Wither would not replace Corruption.", level = 2 },
            { type = "list_item", text = "Soul Harvester: Fixed an issue where Sataiel's Volition would sometimes stop providing its Corruption modifier.", level = 2 },
            { type = "list_item", text = "Destruction", level = 1 },
            { type = "list_item", text = "Fixed an issue where Conflagration of Chaos would not increase the damage of Shadowburn.", level = 2 },
            { type = "h3", text = "Decor Duel" },
            { type = "list_item", text = "Groups may now queue into Decor Duel through the Group Finder.", level = 0 },
            { type = "h3", text = "Dungeons and Raids" },
            { type = "list_item", text = "Pit of Saron", level = 0 },
            { type = "list_item", text = "Risen Soldiers and Arcanist Cadavers can no longer be charmed.", level = 1 },
            { type = "list_item", text = "Ick and Krick", level = 1 },
            { type = "list_item", text = "Addressed an issue where Krick could fail to cast Get 'Em, Ick!", level = 2 },
            { type = "list_item", text = "Windrunner Spire", level = 0 },
            { type = "list_item", text = "Derelict Duo", level = 1 },
            { type = "list_item", text = "Added an arrow over the head of the player being aimed at by Latch's Heaving Yank (in addition to the existing dynamic marker showing the closet target within the path).", level = 2 },
            { type = "list_item", text = "Added a screen effect for when a player is standing in the path of Latch's Heaving Yank.", level = 2 },
            { type = "list_item", text = "Addressed a few situations where Latch's Heaving Yank could behave unexpectedly.", level = 2 },
            { type = "list_item", text = "Adjusted Kalis's teleport locations during Heaving Yank to leave more space between her and the edges of the arena.", level = 2 },
            { type = "list_item", text = "The Voidspire", level = 0 },
            { type = "list_item", text = "Corrected an issue where players were unable to teleport to The Approach after the instance has been soft reset.", level = 1 },
            { type = "h3", text = "Player versus Player" },
            { type = "list_item", text = "Warrior", level = 0 },
            { type = "list_item", text = "Berserker Roar now displays as an important buff on enemy nameplates.", level = 1 },
            { type = "hr" },
            { type = "h3", text = "May 5, 2026" },
            { type = "h3", text = "Classes" },
            { type = "list_item", text = "Death Knight", level = 0 },
            { type = "list_item", text = "Frost", level = 1 },
            { type = "list_item", text = "All damage increased by 5%. Does not affect PvP combat.", level = 2 },
            { type = "list_item", text = "Unholy", level = 1 },
            { type = "dev_note", text = "Unholy Death Knight is performing better than intended after recent bugfixes and the 12.0.5 changes.", level = 2 },
            { type = "list_item", text = "Magus of the Dead Shadow Bolt damage reduced by 15%. Does not affect PvP combat.", level = 2 },
            { type = "list_item", text = "Graveyard damage reduced by 15%. Does not affect PvP combat.", level = 2 },
            { type = "list_item", text = "Rider of the Apocalypse: Whitemane’s Epidemic damage reduced by 25%. This does not affect PvP combat.", level = 2 },
            { type = "list_item", text = "Rider of the Apocalypse: Trolbane’s Icy Fury damage reduced by 25%. Does not affect PvP combat.", level = 2 },
            { type = "list_item", text = "San’layn: Thrill of Blood now increases the damage of Dread Plague and Virulent Plague by 10% (was 5%).", level = 2 },
            { type = "list_item", text = "Demon Hunter", level = 0 },
            { type = "list_item", text = "Devourer", level = 1 },
            { type = "list_item", text = "All damage reduced by 3%.", level = 2 },
            { type = "list_item", text = "Annihilator: Voidfall Meteor damage reduced by 12%.", level = 2 },
            { type = "list_item", text = "Annihilator: Meteoric Rise damage bonus for Void Ray reduced to 10% (was 15%).", level = 2 },
            { type = "list_item", text = "Vengeance", level = 1 },
            { type = "list_item", text = "Thick Skin now increases Armor by 190% (was 150%).", level = 2 },
            { type = "list_item", text = "Druid", level = 0 },
            { type = "list_item", text = "Guardian", level = 1 },
            { type = "list_item", text = "Wild Guardian now clears when entering Arena and Battlegrounds, and when starting a Mythic+ dungeon or a raid encounter.", level = 2 },
            { type = "dev_note", text = "Guardian Druids have continued to overperform in single target contexts, while experiencing difficulties with threat and sustained damage outside of cooldowns. With these changes, we’re aiming to reduce burst potential and transfer some of that power into more reliable and consistent abilities to aid in generating and maintaining threat.", level = 2 },
            { type = "list_item", text = "Wild Guardian echo effectiveness reduced to 200% (was 300%).", level = 2 },
            { type = "list_item", text = "Red Moon damage reduced by 20%.", level = 2 },
            { type = "list_item", text = "Maul damage reduced by 15%.", level = 2 },
            { type = "list_item", text = "Raze damage reduced by 15%.", level = 2 },
            { type = "list_item", text = "Ravage damage reduced by 15%.", level = 2 },
            { type = "list_item", text = "Thrash direct damage increased by 200%.", level = 2 },
            { type = "list_item", text = "Thrash bleed damage increased by 100%.", level = 2 },
            { type = "list_item", text = "Restoration", level = 1 },
            { type = "list_item", text = "All healing reduced by 3%. Does not apply to PvP combat.", level = 2 },
            { type = "list_item", text = "Everbloom heals for 20/40% of Lifebloom’s final heal (was 25/50%). Does not apply to PvP combat.", level = 2 },
            { type = "list_item", text = "Call of the Elder Druid's cooldown is now trackable in the cooldown manager.", level = 2 },
            { type = "list_item", text = "Evoker", level = 0 },
            { type = "list_item", text = "Augmentation", level = 1 },
            { type = "list_item", text = "All ability damage and pet damage reduced by 5%.", level = 2 },
            { type = "list_item", text = "Fixed an issue where Inferno’s Blessing damage was not properly modified by the specialization baseline passive. Inferno’s Blessing’s spell damage coefficient has been adjusted to compensate, so its effective damage will only be changed per the above adjustment.", level = 2 },
            { type = "list_item", text = "Scalecommander: Fixed an issue where Bombardment damage was not properly modified by the specialization’s baseline passives. Bombardment’s damage calculations have been adjusted to compensate.", level = 2 },
            { type = "dev_note", text = "Effective damage will be unchanged for Devastation and only reduced by 5% for Augmentation with the above adjustment.", level = 3 },
            { type = "list_item", text = "Hunter", level = 0 },
            { type = "list_item", text = "Pack Leader: Corrected an issue where Howl of the Pack Leader would not summon a Boar or a Bear if the Kill Command that would summon the Boar or Bear killed your target.", level = 1 },
            { type = "list_item", text = "Pack Leader: Corrected an issue where the Pack Leader Boar's charge would not grant any of the Hogstrider damage bonuses or deal area damage if your Boar's primary target died before the Boar reached it.", level = 1 },
            { type = "list_item", text = "Beast Mastery", level = 1 },
            { type = "list_item", text = "All damage dealt by you and your pets increased by 4%. Does not apply to PvP combat.", level = 2 },
            { type = "list_item", text = "Corrected an issue where the Piercing Fangs talent did not apply a critical damage bonus to the bonus pet summoned from Nature's Ally.", level = 2 },
            { type = "list_item", text = "Marksmanship", level = 1 },
            { type = "list_item", text = "Rapid Fire damage increased by 20%. Does not affect PvP combat.", level = 2 },
            { type = "list_item", text = "Explosive Shot damage increased by 100%.", level = 2 },
